import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { createChat } from '../services/geminiService';

interface ChatPanelProps {
  ideaTitle: string;
}

const ChatPanel: React.FC<ChatPanelProps> = ({ ideaTitle }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    chatRef.current = createChat(`You are a brilliant venture capitalist and startup co-founder. You are discussing the idea: "${ideaTitle}". Be critical but supportive. Ask tough questions. Keep answers concise.`);
    setMessages([{ role: 'model', content: `That's a fascinating vision for ${ideaTitle}. How do you see this scaling in the first 12 months?` }]);
  }, [ideaTitle]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsTyping(true);

    try {
      const result = await chatRef.current.sendMessageStream({ message: userMsg });
      let fullContent = '';

      setMessages(prev => [...prev, { role: 'model', content: '' }]);

      for await (const chunk of result) {
        fullContent += chunk.text;
        setMessages(prev => {
          const updated = [...prev];
          updated[updated.length - 1].content = fullContent;
          return updated;
        });
      }
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', content: 'Sorry, I encountered an error. Let’s try that again.' }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 w-[400px] h-[600px] glass rounded-3xl shadow-2xl flex flex-col hidden lg:flex border border-white/5 overflow-hidden z-50">
      <div className="p-4 border-b border-white/5 flex items-center justify-between bg-white/5">
        <div className="flex items-center gap-3">
          <div className="w-3 h-3 bg-green-500 rounded-full animate-pulse" />
          <span className="font-semibold text-sm">AI Co-founder</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-grow overflow-y-auto p-4 space-y-4">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
              msg.role === 'user' 
                ? 'bg-purple-600 text-white rounded-br-none' 
                : 'bg-white/10 text-gray-200 rounded-bl-none'
            }`}>
              {msg.content}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white/10 p-3 rounded-2xl rounded-bl-none">
              <div className="flex gap-1">
                <div className="w-1 h-1 bg-gray-400 rounded-full animate-bounce" />
                <div className="w-1 h-1 bg-gray-400 rounded-full animate-bounce [animation-delay:0.2s]" />
                <div className="w-1 h-1 bg-gray-400 rounded-full animate-bounce [animation-delay:0.4s]" />
              </div>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="p-4 bg-white/5 border-t border-white/5">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask your co-founder anything..."
          className="w-full bg-[#0a0a0f] border border-white/10 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-purple-500 transition-colors"
        />
      </form>
    </div>
  );
};

export default ChatPanel;

import React, { useState } from 'react';
import Hero from './components/Hero';
import BlueprintView from './components/BlueprintView';
import ChatPanel from './components/ChatPanel';
import { IdeaState, IdeaBlueprint } from './types';
import { generateBlueprint, generateConceptVisual } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<IdeaState>({
    rawInput: '',
    blueprint: null,
    conceptImage: null,
    isProcessing: false,
    isGeneratingImage: false
  });

  const handleStart = async (idea: string) => {
    setState(prev => ({ ...prev, rawInput: idea, isProcessing: true }));

    try {
      // Step 1: Generate Blueprint
      const blueprint = await generateBlueprint(idea);
      setState(prev => ({ ...prev, blueprint, isProcessing: false, isGeneratingImage: true }));

      // Step 2: Generate Visual (Asynchronously)
      const imageUrl = await generateConceptVisual(blueprint.title, blueprint.summary);
      setState(prev => ({ ...prev, conceptImage: imageUrl, isGeneratingImage: false }));
    } catch (error) {
      console.error("Failed to forge idea:", error);
      alert("The forge is too hot! Please try again in a moment.");
      setState(prev => ({ ...prev, isProcessing: false, isGeneratingImage: false }));
    }
  };

  const reset = () => {
    setState({
      rawInput: '',
      blueprint: null,
      conceptImage: null,
      isProcessing: false,
      isGeneratingImage: false
    });
  };

  return (
    <div className="min-h-screen selection:bg-purple-500/30">
      <nav className="p-6 flex justify-between items-center max-w-7xl mx-auto">
        <div 
          className="text-2xl font-bold flex items-center gap-2 cursor-pointer"
          onClick={reset}
        >
          <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center text-white text-lg">
            IF
          </div>
          <span className="tracking-tight">IdeaForge<span className="text-purple-500">.</span></span>
        </div>
        <button 
          onClick={() => window.location.reload()}
          className="text-sm text-gray-500 hover:text-white transition-colors"
        >
          Reset Session
        </button>
      </nav>

      <main>
        {!state.blueprint ? (
          <Hero onStart={handleStart} loading={state.isProcessing} />
        ) : (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <BlueprintView 
              blueprint={state.blueprint} 
              imageUrl={state.conceptImage}
              isGeneratingImage={state.isGeneratingImage}
            />
            <ChatPanel ideaTitle={state.blueprint.title} />

            <div className="flex justify-center pb-24">
              <button 
                onClick={reset}
                className="px-6 py-3 rounded-full border border-white/10 hover:bg-white/5 transition-colors text-sm text-gray-400"
              >
                ← Forge another idea
              </button>
            </div>
          </div>
        )}
      </main>

      <footer className="py-12 text-center text-gray-600 text-sm border-t border-white/5">
        <p>© {new Date().getFullYear()} IdeaForge AI. Powered by Google Gemini.</p>
      </footer>
    </div>
  );
};

export default App;

export interface MarketReference {
  title: string;
  uri: string;
}

export interface IdeaBlueprint {
  title: string;
  summary: string;
  targetAudience: string;
  uniqueValueProp: string;
  marketOpportunities: string[];
  challenges: string[];
  roadmap: string[];
  marketReferences?: MarketReference[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
}

export interface IdeaState {
  rawInput: string;
  blueprint: IdeaBlueprint | null;
  conceptImage: string | null;
  isProcessing: boolean;
  isGeneratingImage: boolean;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { IdeaBlueprint } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateBlueprint = async (idea: string): Promise<IdeaBlueprint> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `请将以下原始创意转化为专业的商业蓝图，并使用中文回复： "${idea}"。
    你需要结合当前最新的市场动态进行分析。`,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "创意的核心名称" },
          summary: { type: Type.STRING, description: "一句话概括" },
          targetAudience: { type: Type.STRING, description: "核心受众群体" },
          uniqueValueProp: { type: Type.STRING, description: "独特价值主张" },
          marketOpportunities: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "市场机会点"
          },
          challenges: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "主要挑战与风险"
          },
          roadmap: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "分阶段实施路径"
          }
        },
        required: ["title", "summary", "targetAudience", "uniqueValueProp", "marketOpportunities", "challenges", "roadmap"]
      }
    }
  });

  const blueprint = JSON.parse(response.text || '{}') as IdeaBlueprint;

  // 提取搜索结果作为参考链接
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    blueprint.marketReferences = chunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || '参考链接',
        uri: chunk.web?.uri || ''
      }));
  }

  return blueprint;
};

export const generateConceptVisual = async (ideaTitle: string, summary: string): Promise<string | null> => {
  const ai = getAI();
  const prompt = `A cinematic, high-quality 3D concept render for: ${ideaTitle}. Context: ${summary}. Minimalist, futuristic, professional design, 4k, trending on ArtStation.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const createChat = (systemInstruction: string) => {
  const ai = getAI();
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction
    }
  });
};

