export interface InvoiceData {
  invoiceNumber: string;
  sellerName: string;
  buyerName: string;
  sellerTaxId: string;
  buyerTaxId: string;
  category: string;
  amount: number;
}

export interface SubmitterInfo {
  name: string;
  studentId: string;
  groupName: string;
  phone: string;
  isPaid: boolean;
}

export interface SubmissionRecord extends InvoiceData, SubmitterInfo {
  id: string;
  timestamp: number;
}

export interface ProcessingFile {
  id: string;
  file: File;
  previewUrl: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  extractedData?: InvoiceData;
  error?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { InvoiceData } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.readAsDataURL(file);
  });
  return {
    inlineData: {
      data: await base64EncodedDataPromise,
      mimeType: file.type,
    },
  };
};

export const extractInvoiceData = async (file: File): Promise<InvoiceData> => {
  const ai = getAI();
  const imagePart = await fileToGenerativePart(file);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          imagePart,
          { text: "请从这张中国增值税发票中提取信息。如果信息缺失，请填空字符串。金额请只提供数字。分类请根据商品名称总结为一个简短的词（如：办公用品、餐饮、交通等）。" }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          invoiceNumber: { type: Type.STRING, description: "发票号码" },
          sellerName: { type: Type.STRING, description: "销售方名称" },
          buyerName: { type: Type.STRING, description: "购买方名称" },
          sellerTaxId: { type: Type.STRING, description: "销售方纳税人识别号" },
          buyerTaxId: { type: Type.STRING, description: "购买方纳税人识别号" },
          category: { type: Type.STRING, description: "商品类型/分类汇总" },
          amount: { type: Type.NUMBER, description: "合计金额（不含税或价税合计，请优先取价税合计总额）" }
        },
        required: ["invoiceNumber", "sellerName", "buyerName", "sellerTaxId", "buyerTaxId", "category", "amount"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as InvoiceData;
};

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, SubmitterInfo } from './types';

const App: React.FC = () => {
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [submitter, setSubmitter] = useState<SubmitterInfo>({
    name: '',
    studentId: '',
    groupName: '',
    phone: '',
    isPaid: false
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // 从本地存储加载记录
  useEffect(() => {
    const saved = localStorage.getItem('invoice_records');
    if (saved) setRecords(JSON.parse(saved));
  }, []);

  // 监听记录变化并保存
  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newFiles = Array.from(e.target.files || []).map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string) => {
    // 全系统查重逻辑
    const isDuplicate = records.some(r => r.invoiceNumber === extracted.invoiceNumber);
    if (isDuplicate) {
      alert(`错误：发票号码 ${extracted.invoiceNumber} 已在系统中提交过，请勿重复提交！`);
      return;
    }

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...submitter,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    setRecords(prev => [newRecord, ...prev]);
    handleRemoveFile(fileId);
  };

  const exportToExcel = () => {
    if (records.length === 0) return;
    const headers = ['发票号码', '销售方', '购买方', '销售税号', '购买税号', '分类', '金额', '提交人', '学号', '组别', '电话', '是否已付', '提交时间'];
    const rows = records.map(r => [
      r.invoiceNumber, r.sellerName, r.buyerName, r.sellerTaxId, r.buyerTaxId, r.category, r.amount,
      r.name, r.studentId, r.groupName, r.phone, r.isPaid ? '是' : '否', new Date(r.timestamp).toLocaleString()
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob(["\ufeff" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `发票报销明细_${new Date().toLocaleDateString()}.csv`);
    link.click();
  };

  const clearRecords = () => {
    if (confirm('确定要清空所有已提交记录吗？此操作不可撤销。')) {
      setRecords([]);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans">
      <header className="bg-white border-b sticky top-0 z-10 px-6 py-4 flex justify-between items-center shadow-sm">
        <h1 className="text-xl font-bold flex items-center gap-2">
          <span className="bg-blue-600 text-white p-1 rounded">🧾</span> 发票报销助手
        </h1>
        <div className="flex gap-3">
          <button 
            onClick={exportToExcel}
            className="px-4 py-2 bg-green-600 text-white rounded-lg text-sm font-medium hover:bg-green-700 transition-colors flex items-center gap-2"
          >
            导出 Excel 报表
          </button>
          <button 
            onClick={clearRecords}
            className="px-4 py-2 border text-red-600 rounded-lg text-sm hover:bg-red-50 transition-colors"
          >
            清空数据
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 左侧：上传与识别区 */}
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white p-6 rounded-xl border shadow-sm">
            <h2 className="text-sm font-bold uppercase text-gray-400 mb-4 tracking-wider">第一步：填写个人信息</h2>
            <div className="grid grid-cols-2 gap-4">
              <input 
                placeholder="姓名" 
                className="border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                value={submitter.name}
                onChange={e => setSubmitter({...submitter, name: e.target.value})}
              />
              <input 
                placeholder="学号" 
                className="border rounded-lg px-3 py-2 text-sm outline-none"
                value={submitter.studentId}
                onChange={e => setSubmitter({...submitter, studentId: e.target.value})}
              />
              <input 
                placeholder="组别" 
                className="border rounded-lg px-3 py-2 text-sm outline-none"
                value={submitter.groupName}
                onChange={e => setSubmitter({...submitter, groupName: e.target.value})}
              />
              <input 
                placeholder="电话" 
                className="border rounded-lg px-3 py-2 text-sm outline-none"
                value={submitter.phone}
                onChange={e => setSubmitter({...submitter, phone: e.target.value})}
              />
              <label className="flex items-center gap-2 text-sm col-span-2 cursor-pointer">
                <input 
                  type="checkbox" 
                  className="w-4 h-4 rounded text-blue-600"
                  checked={submitter.isPaid}
                  onChange={e => setSubmitter({...submitter, isPaid: e.target.checked})}
                />
                已付款
              </label>
            </div>
          </section>

          <section className="bg-white p-6 rounded-xl border shadow-sm space-y-4">
            <h2 className="text-sm font-bold uppercase text-gray-400 mb-4 tracking-wider">第二步：上传发票 (AI 自动识别)</h2>
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="border-2 border-dashed border-gray-200 rounded-xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group"
            >
              <div className="text-3xl mb-2 grayscale group-hover:grayscale-0 transition-all">📸</div>
              <p className="text-sm font-medium">点击或拖拽发票图片/PDF</p>
              <p className="text-xs text-gray-400 mt-1">支持批量上传</p>
              <input 
                ref={fileInputRef}
                type="file" 
                multiple 
                accept="image/*,application/pdf"
                className="hidden" 
                onChange={handleFileUpload}
              />
            </div>

            <div className="space-y-3">
              {files.map(item => (
                <div key={item.id} className="border rounded-xl p-4 flex gap-4 bg-gray-50">
                  <img src={item.previewUrl} className="w-20 h-20 object-cover rounded-lg border bg-white" />
                  <div className="flex-grow min-w-0">
                    <div className="flex justify-between items-start mb-2">
                      <span className="text-xs font-mono text-gray-500 truncate max-w-[150px]">{item.file.name}</span>
                      <button onClick={() => handleRemoveFile(item.id)} className="text-gray-400 hover:text-red-500">✕</button>
                    </div>

                    {item.status === 'processing' && (
                      <div className="space-y-2">
                        <div className="h-1 bg-gray-200 rounded-full overflow-hidden">
                          <div className="h-full bg-blue-500 animate-[loading_2s_infinite]" style={{width: '30%'}}></div>
                        </div>
                        <p className="text-xs text-blue-600 font-medium">AI 正在精准提取信息...</p>
                      </div>
                    )}

                    {item.status === 'completed' && item.extractedData && (
                      <div className="space-y-1">
                        <p className="text-sm font-bold text-gray-800">¥{item.extractedData.amount.toFixed(2)} - {item.extractedData.category}</p>
                        <p className="text-xs text-gray-500 truncate">No: {item.extractedData.invoiceNumber}</p>
                        <button 
                          onClick={() => handleAddRecord(item.extractedData!, item.id)}
                          className="mt-2 w-full py-1.5 bg-blue-600 text-white rounded-md text-xs font-bold hover:bg-blue-700 shadow-sm"
                        >
                          确认并提交
                        </button>
