                    {item.status === 'error' && (
                      <p className="text-xs text-red-500 font-medium">❌ 识别失败，请检查文件质量</p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* 右侧：记录列表区 */}
        <div className="lg:col-span-7">
          <section className="bg-white rounded-xl border shadow-sm overflow-hidden flex flex-col h-[80vh]">
