import { GoogleGenAI, Type, Chat } from "@google/genai";
import { InvoiceData } from "../types";

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.readAsDataURL(file);
  });
  return {
    inlineData: {
      data: await base64EncodedDataPromise,
      mimeType: file.type,
    },
  };
};

export const extractInvoiceData = async (file: File): Promise<InvoiceData> => {
  // Initialize the AI client using named parameters
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = await fileToGenerativePart(file);

  // Directly call generateContent with model name and prompt contents
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        imagePart,
        { text: "请精准提取中国增值税发票信息。特别注意：1. 销售方银行账号通常在发票左下角或右下角的‘销售方’栏位中。2. 金额必须为纯数字。3. 如果某项信息实在无法找到，请填空字符串。" }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          invoiceNumber: { type: Type.STRING, description: "发票号码" },
          sellerName: { type: Type.STRING, description: "销售方名称" },
          buyerName: { type: Type.STRING, description: "购买方名称" },
          sellerTaxId: { type: Type.STRING, description: "销售方纳税人识别号" },
          buyerTaxId: { type: Type.STRING, description: "购买方纳税人识别号" },
          sellerBankAccount: { type: Type.STRING, description: "销售方银行账号/开户行及账号" },
          category: { type: Type.STRING, description: "商品类型或服务名称" },
          amount: { type: Type.NUMBER, description: "价税合计总额" }
        },
        required: ["invoiceNumber", "sellerName", "buyerName", "sellerTaxId", "buyerTaxId", "sellerBankAccount", "category", "amount"]
      }
    }
  });

  // Directly access the text property as per guidelines
  return JSON.parse(response.text || '{}') as InvoiceData;
};

export const createChat = (systemInstruction: string): Chat => {
  // Initialize a fresh instance for the chat session
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: { systemInstruction },
  });
};

