import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // 初始化加载
  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  // 保存记录
  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string, // 改为指导老师
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");

    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;

    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);

      // 抬头校验逻辑
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim() === SCHOOL_TAX_ID;

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data,
        isBuyerValid 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean) => {
    if (!isValid) {
      alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}，税号：${SCHOOL_TAX_ID}`);
      return;
    }

    const isDuplicate = records.some(r => r.invoiceNumber === extracted.invoiceNumber);
    if (isDuplicate) {
      alert(`错误：发票号 ${extracted.invoiceNumber} 已存在，请勿重复提交！`);
      return;
    }

    if (!user) return;

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => prev.filter(f => f.id !== fileId));
  };

  const handleRemoveFile = (fileId: string) => {
    setFiles(prev => prev.filter(f => f.id !== fileId));
  };

  const exportToExcel = () => {
    if (records.length === 0) return;
    // 更新表头：添加电话、指导老师，删除购买方名称和税号
    const headers = ['发票号', '销售方', '银行账号', '分类', '金额', '提交人', '学号', '联系电话', '指导老师', '报销状态'];
    const rows = records.map(r => [
      r.invoiceNumber, 
      r.sellerName, 
      r.sellerBankAccount, 
      r.category, 
      r.amount, 
      r.name, 
      r.studentId, 
      r.phone, // 新增：电话
      r.supervisor, // 新增：指导老师
      r.isPaid ? '已付' : '待付'
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `报销清单_${new Date().toLocaleDateString()}.csv`;
    link.click();
  };

  // 登录界面
  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full">
          <div className="text-center mb-8">
            <span className="text-4xl">🧾</span>
            <h1 className="text-2xl font-bold mt-2">身份信息登记</h1>
            <p className="text-gray-500 text-sm">只需登记一次，系统将自动记住您的报销身份</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold hover:bg-blue-700 transition-all">进入系统</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900">
      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <h1 className="text-xl font-bold">发票报销助手</h1>
          <div className="h-6 w-[1px] bg-gray-200" />
          <div className="text-xs text-gray-500">
            <span className="font-bold text-gray-800">{user.name}</span> ({user.studentId})
            <span className="ml-2 text-gray-400">| 导师: {user.supervisor}</span>
            <button onClick={() => setIsLoginView(true)} className="ml-4 text-blue-600 hover:underline">修改信息</button>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={exportToExcel} className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-bold">导出 CSV</button>
          <button onClick={() => setRecords([])} className="border text-red-500 px-4 py-2 rounded-lg text-sm">清空</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 操作区 */}
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest">发票上传</h2>
              <label className="flex items-center gap-2 text-xs font-bold cursor-pointer select-none">
                <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-4 h-4 rounded text-blue-600" />
                已由个人先行付款
              </label>
            </div>

            <div 
              onClick={() => fileInputRef.current?.click()}
              className="border-2 border-dashed border-gray-200 rounded-2xl p-8 text-center cursor-pointer hover:bg-blue-50 hover:border-blue-400 transition-all"
            >
              <div className="text-3xl mb-2">📄</div>
              <p className="text-sm font-bold">点击选择或拖拽发票文件</p>
              <p className="text-xs text-gray-400 mt-1">支持图片和 PDF 批量处理</p>
              <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
            </div>

            <div className="mt-6 space-y-4">
              {files.map(item => (
                <div key={item.id} className={`border-2 rounded-2xl p-4 flex gap-4 transition-all ${item.isBuyerValid === false ? 'border-red-500 bg-red-50' : 'bg-gray-50 border-gray-100'}`}>
                  <img src={item.previewUrl} className="w-20 h-20 object-cover rounded-xl border bg-white" alt="preview" />
