      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim() === SCHOOL_TAX_ID;

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data,
        isBuyerValid 
      } : f));
