import { GoogleGenAI, Type, Chat } from "@google/genai";
import { InvoiceData } from "../types";

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.readAsDataURL(file);
  });
  return {
    inlineData: {
      data: await base64EncodedDataPromise,
      mimeType: file.type,
    },
  };
};

export const extractInvoiceData = async (file: File): Promise<InvoiceData> => {
  // Use gemini-3-flash-preview for the highest possible speed
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = await fileToGenerativePart(file);

  // Refined prompt for faster inference (less conversational, more instructional)
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        imagePart,
        { text: "Fast Extract: 1.Invoice Number, 2.Seller Name, 3.Buyer Name, 4.Seller Tax ID, 5.Buyer Tax ID, 6.Seller Bank Account (check bottom left/right), 7.Category, 8.Total Amount (number only). No preamble." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      // Disable thinking to minimize latency for OCR tasks
      thinkingConfig: { thinkingBudget: 0 },
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          invoiceNumber: { type: Type.STRING },
          sellerName: { type: Type.STRING },
          buyerName: { type: Type.STRING },
          sellerTaxId: { type: Type.STRING },
          buyerTaxId: { type: Type.STRING },
          sellerBankAccount: { type: Type.STRING },
          category: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        },
        required: ["invoiceNumber", "sellerName", "buyerName", "sellerTaxId", "buyerTaxId", "sellerBankAccount", "category", "amount"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as InvoiceData;
};

export const createChat = (systemInstruction: string): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: { systemInstruction },
  });
};

