            <span className="text-4xl">🧾</span>
            <h1 className="text-2xl font-bold mt-2">身份信息登记</h1>
            <p className="text-gray-500 text-sm">只需登记一次，系统将自动记住您的报销身份</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold hover:bg-blue-700 transition-all">进入系统</button>
          </form>
        </div>
      </div>
    );
  }

