          <div className="text-xs text-gray-500">
            <span className="font-bold text-gray-800">{user.name}</span> ({user.studentId})
            <span className="ml-2 text-gray-400">| 导师: {user.supervisor}</span>
            <button onClick={() => setIsLoginView(true)} className="ml-4 text-blue-600 hover:underline">修改信息</button>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={exportToExcel} className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-green-700 transition-colors">导出 CSV</button>
          <button onClick={() => { if(confirm("确定清空记录吗？")) setRecords([]) }} className="border text-red-500 px-4 py-2 rounded-lg text-sm hover:bg-red-50 transition-colors">清空</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest">发票上传</h2>
              <label className="flex items-center gap-3 px-5 py-2.5 bg-blue-50 border border-blue-100 rounded-full cursor-pointer select-none transition-all hover:bg-blue-100 group shadow-sm">
                <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded text-blue-600 focus:ring-offset-0 transition-transform active:scale-90" />
                <span className={`text-xl font-black transition-colors ${isPaid ? 'text-blue-700' : 'text-gray-400'}`}>已付</span>
              </label>
            </div>

            <div 
              onClick={() => fileInputRef.current?.click()}
              className="border-2 border-dashed border-gray-200 rounded-2xl p-8 text-center cursor-pointer hover:bg-blue-50 hover:border-blue-400 transition-all group"
            >
              <div className="text-4xl mb-2 group-hover:scale-110 transition-transform">📄</div>
              <p className="text-sm font-bold">点击选择或拖拽发票文件</p>
              <p className="text-xs text-gray-400 mt-1">AI 提速模式：PDF/图片批量快传</p>
              <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
            </div>

            <div className="mt-6 space-y-4">
              {files.map(item => (
                <div key={item.id} className={`border-2 rounded-2xl p-4 flex gap-4 transition-all ${item.isDuplicate ? 'border-orange-500 bg-orange-50 shadow-sm' : item.isBuyerValid === false ? 'border-red-500 bg-red-50 shadow-sm' : 'bg-gray-50 border-gray-100'}`}>
                  <div className="relative flex-shrink-0">
                    <img src={item.previewUrl} className="w-20 h-20 object-cover rounded-xl border bg-white" alt="preview" />
                    {item.isDuplicate && (
                      <div className="absolute inset-0 bg-orange-600/20 flex items-center justify-center rounded-xl overflow-hidden">
                        <span className="bg-orange-600 text-white text-[8px] font-bold px-1 rounded rotate-[-15deg] shadow-lg border border-orange-400">重复</span>
                      </div>
                    )}
                  </div>
                  <div className="flex-grow min-w-0">
                    {item.status === 'processing' ? (
                      <div className="h-full flex flex-col justify-center">
                        <div className="h-1.5 bg-gray-200 rounded-full overflow-hidden">
                          <div className="h-full bg-blue-500 animate-[loading_1.5s_infinite]" style={{width: '60%'}} />
                        </div>
                        <p className="text-[10px] text-blue-600 font-bold mt-2">快读加速中...</p>
                      </div>
                    ) : item.status === 'completed' && item.extractedData ? (
                      <div className="space-y-1">
                        <div className="flex justify-between items-start gap-1 flex-wrap">
                          <span className="text-base font-black">¥{item.extractedData.amount.toFixed(2)}</span>
                          <div className="flex gap-1">
                            {item.isDuplicate && <span className="text-[10px] bg-orange-600 text-white px-2 py-0.5 rounded font-bold uppercase shadow-sm animate-pulse">重复报销</span>}
                            {item.isBuyerValid === false && <span className="text-[10px] bg-red-600 text-white px-2 py-0.5 rounded font-bold uppercase shadow-sm">抬头错误</span>}
                          </div>
                        </div>
                        <p className="text-[10px] text-gray-500 truncate">{item.extractedData.category}</p>
                        <p className="text-[10px] font-mono text-gray-400 truncate">No: {item.extractedData.invoiceNumber}</p>

                        {(item.isDuplicate || item.isBuyerValid === false) ? (
                          <div className="mt-2 text-[10px] font-bold bg-white p-2 rounded-lg border shadow-sm">
                            {item.isDuplicate && <div className="text-orange-600">⚠️ 系统已存此单，请勿重复操作</div>}
                            {item.isBuyerValid === false && <div className="text-red-600">❌ 抬头非江南大学或税号有误</div>}
                          </div>
                        ) : (
                          <button 
                            onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)}
                            className="mt-2 w-full py-2 bg-blue-600 text-white rounded-xl text-xs font-bold shadow-lg hover:bg-blue-700 active:scale-95 transition-all"
                          >
                            确认报销
                          </button>
                        )}
                        <button onClick={() => handleRemoveFile(item.id)} className="w-full mt-1 text-[10px] text-gray-400 hover:text-red-500 transition-colors">移除此单</button>
                      </div>
                    ) : (
                      <p className="text-xs text-red-500 font-bold">识别超时或失败</p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        <div className="lg:col-span-7">
          <div className="bg-white rounded-2xl border shadow-sm overflow-hidden flex flex-col h-[75vh]">
            <div className="px-6 py-4 border-b bg-gray-50 flex justify-between items-center">
              <h2 className="text-sm font-bold text-gray-600 flex items-center gap-2">
                <span>已保存报销单</span>
                <span className="bg-gray-200 text-gray-600 px-2 py-0.5 rounded-full text-[10px]">{records.length} 笔</span>
              </h2>
              <span className="text-xs text-gray-400">发票号码作为唯一查重凭证</span>
            </div>
            <div className="flex-grow overflow-auto">
              {records.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-gray-300 py-20">
                  <span className="text-6xl mb-4 grayscale opacity-20">📁</span>
                  <p className="text-sm font-medium">暂无记录，上传上方文件开启报销</p>
                </div>
              ) : (
                <table className="w-full text-left text-xs">
                  <thead className="bg-white sticky top-0 border-b z-10">
                    <tr>
                      <th className="px-4 py-3 font-bold text-gray-400">发票号码</th>
                      <th className="px-4 py-3 font-bold text-gray-400">用途/销售方</th>
                      <th className="px-4 py-3 font-bold text-gray-400">金额</th>
                      <th className="px-4 py-3 font-bold text-gray-400">支付状态</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {records.map(r => (
                      <tr key={r.id} className="hover:bg-blue-50/50 transition-colors group">
                        <td className="px-4 py-4">
                          <div className="font-mono text-gray-800 font-bold">{r.invoiceNumber}</div>
                          <div className="text-[8px] text-gray-400">提交: {new Date(r.timestamp).toLocaleTimeString()}</div>
                        </td>
                        <td className="px-4 py-4">
                          <div className="font-bold text-gray-700">{r.category}</div>
                          <div className="text-[10px] text-gray-400 truncate max-w-[200px]">{r.sellerName}</div>
                        </td>
                        <td className="px-4 py-4">
                          <div className="font-black text-blue-600 text-sm">¥{r.amount.toFixed(2)}</div>
                        </td>
                        <td className="px-4 py-4">
                          <button 
                            onClick={() => toggleRecordPaidStatus(r.id)}
                            className={`px-4 py-1.5 rounded-full text-[11px] font-black transition-all active:scale-90 shadow-sm ${
                              r.isPaid 
                                ? 'bg-green-100 text-green-700 hover:bg-green-200 ring-1 ring-green-200' 
                                : 'bg-orange-100 text-orange-700 hover:bg-orange-200 ring-1 ring-orange-200'
                            }`}
                          >
                            {r.isPaid ? '已付' : '待付'}
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(250%); }
        }
      `}</style>
    </div>
  );
};

export default App;

export interface InvoiceData {
  invoiceNumber: string;
  sellerName: string;
  buyerName: string;
  sellerTaxId: string;
  buyerTaxId: string;
  sellerBankAccount: string;
  category: string;
  amount: number;
}

export interface SubmitterInfo {
  name: string;
  studentId: string;
  supervisor: string;
  phone: string;
  isPaid: boolean;
}

export interface UserProfile extends Omit<SubmitterInfo, 'isPaid'> {}

export type ReimbursementStatus = 'box' | 'han' | 'assistant' | 'office' | 'success' | 'rejected';

export interface SubmissionRecord extends InvoiceData, SubmitterInfo {
  id: string;
  timestamp: number;
  paidEditCount: number; // 记录支付状态修改次数
  surveyAnswers?: {
    hasDoubleSignature: boolean; // 2名以上老师签字
    hasPaymentRecord: boolean;   // 附上支付记录
  };
  status: ReimbursementStatus;
  rejectionReason?: string;
}

export interface ProcessingFile {
  id: string;
  file: File;
  previewUrl: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  extractedData?: InvoiceData;
  error?: string;
  isBuyerValid?: boolean;
  isDuplicate?: boolean;
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false); // 后台模式
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 提交后的工作流弹窗
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);
    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      // 修复查重逻辑：去除空白符并转大写
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };
    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => prev.filter(f => f.id !== fileId));
    setActiveWorkflowId(newRecord.id); // 开启问卷流程
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (record && record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }
    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: !r.isPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const updateSurvey = (id: string, answers: { hasDoubleSignature: boolean; hasPaymentRecord: boolean }) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, surveyAnswers: answers } : r));
    setActiveWorkflowId(null);
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature ? '是' : '否',
      r.surveyAnswers?.hasPaymentRecord ? '是' : '否',
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  // 进度组件
  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border border-white/20">
          <div className="text-center mb-8">
            <span className="text-5xl drop-shadow-lg">📋</span>
            <h1 className="text-2xl font-black mt-4 text-slate-800">报销身份认证</h1>
            <p className="text-slate-400 text-sm mt-2">请一次性准确填写，我们将为您自动同步</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg hover:bg-blue-700 shadow-lg active:scale-95 transition-all">开启高效报销</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 提交后问卷弹窗 */}
      {activeWorkflowId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">发票合规性确认</h2>
            <div className="space-y-6">
              <div>
                <p className="text-sm font-bold mb-3">1. 发票是否由2名以上的老师签字？</p>
                <div className="flex gap-2">
                  <button onClick={() => updateSurvey(activeWorkflowId, { hasDoubleSignature: true, hasPaymentRecord: false })} className="flex-1 py-3 bg-blue-50 border border-blue-200 rounded-xl text-blue-600 font-bold hover:bg-blue-600 hover:text-white transition-all">是</button>
                  <button onClick={() => updateSurvey(activeWorkflowId, { hasDoubleSignature: false, hasPaymentRecord: false })} className="flex-1 py-3 bg-gray-50 border border-gray-200 rounded-xl text-gray-400 font-bold">否</button>
                </div>
              </div>
              <div>
                <p className="text-sm font-bold mb-3">2. 已付发票是否附上支付记录？</p>
                <div className="flex gap-2">
                  <button onClick={() => {
                    const r = records.find(rec => rec.id === activeWorkflowId);
                    updateSurvey(activeWorkflowId, { hasDoubleSignature: r?.surveyAnswers?.hasDoubleSignature || false, hasPaymentRecord: true });
                  }} className="flex-1 py-3 bg-blue-50 border border-blue-200 rounded-xl text-blue-600 font-bold hover:bg-blue-600 hover:text-white transition-all">是</button>
                  <button onClick={() => {
                    const r = records.find(rec => rec.id === activeWorkflowId);
                    updateSurvey(activeWorkflowId, { hasDoubleSignature: r?.surveyAnswers?.hasDoubleSignature || false, hasPaymentRecord: false });
                  }} className="flex-1 py-3 bg-gray-50 border border-gray-200 rounded-xl text-gray-400 font-bold">否</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="h-4 w-[1px] bg-slate-200 hidden md:block" />
          <div className="hidden md:flex text-xs text-slate-400 gap-3">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>导师: <b className="text-slate-800">{user.supervisor}</b></span>
          </div>
        </div>
        <div className="flex gap-2">
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-bold">后台导出(全量)</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-bold">我的导出</button>
          <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${isAdminMode ? 'bg-red-50 text-red-600 border-red-200' : 'text-slate-400 border-slate-200'}`}>
            {isAdminMode ? '退出管理' : '管理员模式'}
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 操作区 */}
        <div className={`lg:col-span-5 space-y-6 ${isAdminMode ? 'opacity-50 pointer-events-none' : ''}`}>
          <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl overflow-hidden relative">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
              <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none transition-all hover:bg-blue-100 group shadow-lg active:scale-95">
                <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
              </label>
            </div>

            <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
              <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📂</span>
              <p className="text-lg font-black text-slate-800">批量上传发票</p>
              <p className="text-sm text-slate-400 mt-2">支持 PDF / 图片 | AI 加速模式已开启</p>
              <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
            </div>

            <div className="mt-8 space-y-4">
              {files.map(item => (
                <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100'}`}>
                  <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border" alt="preview" />
                  <div className="flex-grow min-w-0">
                    {item.status === 'processing' ? (
                      <div className="h-full flex flex-col justify-center">
                        <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-blue-500 animate-[loading_1s_infinite]" style={{width: '70%'}} />
                        </div>
                        <p className="text-xs font-black text-blue-600 mt-3 animate-pulse">正在极速提取数据...</p>
                      </div>
                    ) : item.status === 'completed' && item.extractedData ? (
                      <div className="flex flex-col h-full justify-between">
                        <div>
                          <div className="flex justify-between items-start">
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            {item.isDuplicate && <span className="bg-amber-600 text-white text-[10px] px-2 py-0.5 rounded-lg font-black">重复报销</span>}
                          </div>
                          <p className="text-xs font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          <p className="text-[10px] font-mono text-slate-400"># {item.extractedData.invoiceNumber}</p>
                        </div>

                        {(item.isDuplicate || item.isBuyerValid === false) ? (
                          <div className="mt-3 text-[10px] font-black bg-white/50 p-2 rounded-xl border">
                            {item.isDuplicate && <div className="text-amber-600">⚠️ 系统查重拦截：该发票已存在</div>}
                            {item.isBuyerValid === false && <div className="text-red-600">❌ 抬头错误：非江南大学或税号有误</div>}
                          </div>
                        ) : (
                          <div className="flex gap-2 mt-3">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-2.5 bg-blue-600 text-white rounded-xl text-xs font-bold shadow-lg active:scale-95 transition-all">确认无误</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl hover:bg-red-50 hover:text-red-600 transition-all">删除</button>
                          </div>
                        )}
                      </div>
                    ) : (
                      <div className="text-center py-4"><span className="text-red-500 font-black text-xs">识别失败，请检查文件</span></div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* 报销记录/管理区 */}
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col h-[80vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <div>
                <h2 className="text-lg font-black text-slate-800">报销进程追踪</h2>
                <p className="text-xs text-slate-400 mt-1">发票实时查重范围：{records.length} 条已存记录</p>
              </div>
              <div className="text-right">
                <span className="text-xs font-black text-blue-600 block">{records.filter(r => r.status === 'success').length} 笔成功</span>
                <span className="text-[10px] text-slate-400">共计 ¥{records.reduce((acc, r) => acc + r.amount, 0).toLocaleString()}</span>
              </div>
            </div>

            <div className="flex-grow overflow-auto p-4 space-y-4">
              {records.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center opacity-20">
                  <span className="text-8xl">📤</span>
                  <p className="mt-4 font-black">快去上传发票吧</p>
                </div>
              ) : (
                records.map(r => (
                  <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-lg ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex gap-4 items-center">
                        <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-xl shadow-inner">🧾</div>
                        <div>
                          <h3 className="font-black text-slate-800">{r.category}</h3>
                          <p className="text-[10px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                        <button 
                          onClick={() => toggleRecordPaidStatus(r.id)}
                          disabled={r.paidEditCount >= 1 && !isAdminMode}
                          className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-all ${
                            r.isPaid ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                          } ${r.paidEditCount >= 1 && !isAdminMode ? 'opacity-50 cursor-not-allowed' : 'hover:scale-105 active:scale-95'}`}
                        >
                          {r.isPaid ? '已支付' : '待支付'} {r.paidEditCount >= 1 && !isAdminMode && '(已锁定)'}
                        </button>
                      </div>
                    </div>

                    <ProgressSteps status={r.status} reason={r.rejectionReason} />

                    {isAdminMode && (
                      <div className="mt-4 pt-4 border-t flex flex-wrap gap-2 items-center">
                        <span className="text-[10px] font-black text-slate-400">后台改样:</span>
                        {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                          <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>{s}</button>
                        ))}
                        <button onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === 'rejected' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-500'}`}>退单</button>
                        <div className="ml-auto flex items-center gap-2 text-[10px] text-slate-400">
                          <span>提交人: {r.name}</span>
                          <button onClick={() => { if(confirm("管理删单?")) setRecords(prev => prev.filter(rec => rec.id !== r.id)) }} className="text-red-400 hover:text-red-600">删除</button>
                        </div>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes loading { 0% { transform: translateX(-100%); } 100% { transform: translateX(200%); } }
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

export interface InvoiceData {
  invoiceNumber: string;
  sellerName: string;
  buyerName: string;
  sellerTaxId: string;
  buyerTaxId: string;
  sellerBankAccount: string;
  category: string;
  amount: number;
}

export interface SubmitterInfo {
  name: string;
  studentId: string;
  supervisor: string;
  phone: string;
  isPaid: boolean;
}

export interface UserProfile extends Omit<SubmitterInfo, 'isPaid'> {}

export type ReimbursementStatus = 'box' | 'han' | 'assistant' | 'office' | 'success' | 'rejected';

export interface SubmissionRecord extends InvoiceData, SubmitterInfo {
  id: string;
  timestamp: number;
  paidEditCount: number; // 记录支付状态修改次数
  surveyAnswers?: {
    hasDoubleSignature: boolean; // 2名以上老师签字
    hasPaymentRecord: boolean;   // 附上支付记录
  };
  status: ReimbursementStatus;
  rejectionReason?: string;
}

export interface ProcessingFile {
  id: string;
  file: File;
  previewUrl: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  extractedData?: InvoiceData;
  error?: string;
  isBuyerValid?: boolean;
  isDuplicate?: boolean;
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
}

/**
 * Added IdeaBlueprint interface to fix the import error in components/BlueprintView.tsx.
 * This interface defines the structure for a generated business idea blueprint.
 */
export interface IdeaBlueprint {
  title: string;
  summary: string;
  targetAudience: string;
  marketReferences: Array<{
    uri: string;
    title: string;
  }>;
  uniqueValueProp: string;
  marketOpportunities: string[];
  challenges: string[];
  roadmap: string[];
}

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false); // 后台模式
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 提交后的工作流弹窗
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);
    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      // 修复查重逻辑：去除空白符并转大写
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  /**
   * Fix for line 303 error: Implemented handleRemoveFile to allow users to remove uploaded files from the queue.
   * Also ensures the blob URL is revoked to prevent memory leaks.
   */
  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) {
        URL.revokeObjectURL(fileToRemove.previewUrl);
      }
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };
    setRecords(prev => [newRecord, ...prev]);
    // Also cleanup object URL when moving file to records
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) {
        URL.revokeObjectURL(fileToRemove.previewUrl);
      }
      return prev.filter(f => f.id !== fileId);
    });
    setActiveWorkflowId(newRecord.id); // 开启问卷流程
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (record && record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }
    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: !r.isPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const updateSurvey = (id: string, answers: { hasDoubleSignature: boolean; hasPaymentRecord: boolean }) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, surveyAnswers: answers } : r));
    setActiveWorkflowId(null);
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature ? '是' : '否',
      r.surveyAnswers?.hasPaymentRecord ? '是' : '否',
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  // 进度组件
  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border border-white/20">
          <div className="text-center mb-8">
            <span className="text-5xl drop-shadow-lg">📋</span>
            <h1 className="text-2xl font-black mt-4 text-slate-800">报销身份认证</h1>
            <p className="text-slate-400 text-sm mt-2">请一次性准确填写，我们将为您自动同步</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg hover:bg-blue-700 shadow-lg active:scale-95 transition-all">开启高效报销</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 提交后问卷弹窗 */}
      {activeWorkflowId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">发票合规性确认</h2>
            <div className="space-y-6">
              <div>
                <p className="text-sm font-bold mb-3">1. 发票是否由2名以上的老师签字？</p>
                <div className="flex gap-2">
                  <button onClick={() => updateSurvey(activeWorkflowId, { hasDoubleSignature: true, hasPaymentRecord: false })} className="flex-1 py-3 bg-blue-50 border border-blue-200 rounded-xl text-blue-600 font-bold hover:bg-blue-600 hover:text-white transition-all">是</button>
                  <button onClick={() => updateSurvey(activeWorkflowId, { hasDoubleSignature: false, hasPaymentRecord: false })} className="flex-1 py-3 bg-gray-50 border border-gray-200 rounded-xl text-gray-400 font-bold">否</button>
                </div>
              </div>
              <div>
                <p className="text-sm font-bold mb-3">2. 已付发票是否附上支付记录？</p>
                <div className="flex gap-2">
                  <button onClick={() => {
                    const r = records.find(rec => rec.id === activeWorkflowId);
                    updateSurvey(activeWorkflowId, { hasDoubleSignature: r?.surveyAnswers?.hasDoubleSignature || false, hasPaymentRecord: true });
                  }} className="flex-1 py-3 bg-blue-50 border border-blue-200 rounded-xl text-blue-600 font-bold hover:bg-blue-600 hover:text-white transition-all">是</button>
                  <button onClick={() => {
                    const r = records.find(rec => rec.id === activeWorkflowId);
                    updateSurvey(activeWorkflowId, { hasDoubleSignature: r?.surveyAnswers?.hasDoubleSignature || false, hasPaymentRecord: false });
                  }} className="flex-1 py-3 bg-gray-50 border border-gray-200 rounded-xl text-gray-400 font-bold">否</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="h-4 w-[1px] bg-slate-200 hidden md:block" />
          <div className="hidden md:flex text-xs text-slate-400 gap-3">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>导师: <b className="text-slate-800">{user.supervisor}</b></span>
          </div>
        </div>
        <div className="flex gap-2">
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-bold">后台导出(全量)</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-bold">我的导出</button>
          <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${isAdminMode ? 'bg-red-50 text-red-600 border-red-200' : 'text-slate-400 border-slate-200'}`}>
            {isAdminMode ? '退出管理' : '管理员模式'}
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 操作区 */}
        <div className={`lg:col-span-5 space-y-6 ${isAdminMode ? 'opacity-50 pointer-events-none' : ''}`}>
          <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl overflow-hidden relative">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
              <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none transition-all hover:bg-blue-100 group shadow-lg active:scale-95">
                <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
              </label>
            </div>

            <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
              <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📂</span>
              <p className="text-lg font-black text-slate-800">批量上传发票</p>
              <p className="text-sm text-slate-400 mt-2">支持 PDF / 图片 | AI 加速模式已开启</p>
              <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
            </div>

            <div className="mt-8 space-y-4">
              {files.map(item => (
                <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100'}`}>
                  <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border" alt="preview" />
                  <div className="flex-grow min-w-0">
                    {item.status === 'processing' ? (
                      <div className="h-full flex flex-col justify-center">
                        <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-blue-500 animate-[loading_1s_infinite]" style={{width: '70%'}} />
                        </div>
                        <p className="text-xs font-black text-blue-600 mt-3 animate-pulse">正在极速提取数据...</p>
                      </div>
                    ) : item.status === 'completed' && item.extractedData ? (
                      <div className="flex flex-col h-full justify-between">
                        <div>
                          <div className="flex justify-between items-start">
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            {item.isDuplicate && <span className="bg-amber-600 text-white text-[10px] px-2 py-0.5 rounded-lg font-black">重复报销</span>}
                          </div>
                          <p className="text-xs font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          <p className="text-[10px] font-mono text-slate-400"># {item.extractedData.invoiceNumber}</p>
                        </div>

                        {(item.isDuplicate || item.isBuyerValid === false) ? (
                          <div className="mt-3 text-[10px] font-black bg-white/50 p-2 rounded-xl border">
                            {item.isDuplicate && <div className="text-amber-600">⚠️ 系统查重拦截：该发票已存在</div>}
                            {item.isBuyerValid === false && <div className="text-red-600">❌ 抬头错误：非江南大学或税号有误</div>}
                          </div>
                        ) : (
                          <div className="flex gap-2 mt-3">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-2.5 bg-blue-600 text-white rounded-xl text-xs font-bold shadow-lg active:scale-95 transition-all">确认无误</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl hover:bg-red-50 hover:text-red-600 transition-all">删除</button>
                          </div>
                        )}
                      </div>
                    ) : (
                      <div className="text-center py-4"><span className="text-red-500 font-black text-xs">识别失败，请检查文件</span></div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* 报销记录/管理区 */}
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col h-[80vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <div>
                <h2 className="text-lg font-black text-slate-800">报销进程追踪</h2>
                <p className="text-xs text-slate-400 mt-1">发票实时查重范围：{records.length} 条已存记录</p>
              </div>
              <div className="text-right">
                <span className="text-xs font-black text-blue-600 block">{records.filter(r => r.status === 'success').length} 笔成功</span>
                <span className="text-[10px] text-slate-400">共计 ¥{records.reduce((acc, r) => acc + r.amount, 0).toLocaleString()}</span>
              </div>
            </div>

            <div className="flex-grow overflow-auto p-4 space-y-4">
              {records.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center opacity-20">
                  <span className="text-8xl">📤</span>
                  <p className="mt-4 font-black">快去上传发票吧</p>
                </div>
              ) : (
                records.map(r => (
                  <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-lg ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex gap-4 items-center">
                        <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-xl shadow-inner">🧾</div>
                        <div>
                          <h3 className="font-black text-slate-800">{r.category}</h3>
                          <p className="text-[10px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                        <button 
                          onClick={() => toggleRecordPaidStatus(r.id)}
                          disabled={r.paidEditCount >= 1 && !isAdminMode}
                          className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-all ${
                            r.isPaid ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                          } ${r.paidEditCount >= 1 && !isAdminMode ? 'opacity-50 cursor-not-allowed' : 'hover:scale-105 active:scale-95'}`}
                        >
                          {r.isPaid ? '已支付' : '待支付'} {r.paidEditCount >= 1 && !isAdminMode && '(已锁定)'}
                        </button>
                      </div>
                    </div>

                    <ProgressSteps status={r.status} reason={r.rejectionReason} />

                    {isAdminMode && (
                      <div className="mt-4 pt-4 border-t flex flex-wrap gap-2 items-center">
                        <span className="text-[10px] font-black text-slate-400">后台改样:</span>
                        {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                          <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>{s}</button>
                        ))}
                        <button onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === 'rejected' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-500'}`}>退单</button>
                        <div className="ml-auto flex items-center gap-2 text-[10px] text-slate-400">
                          <span>提交人: {r.name}</span>
                          <button onClick={() => { if(confirm("管理删单?")) setRecords(prev => prev.filter(rec => rec.id !== r.id)) }} className="text-red-400 hover:text-red-600">删除</button>
                        </div>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes loading { 0% { transform: translateX(-100%); } 100% { transform: translateX(200%); } }
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false); // 后台模式
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 提交后的工作流弹窗
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  // 临时存储问卷状态
  const [tempSurvey, setTempSurvey] = useState<{
    hasDoubleSignature: boolean | null;
    hasPaymentRecord: boolean | null;
  }>({ hasDoubleSignature: null, hasPaymentRecord: null });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);
    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) {
        URL.revokeObjectURL(fileToRemove.previewUrl);
      }
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };
    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) {
        URL.revokeObjectURL(fileToRemove.previewUrl);
      }
      return prev.filter(f => f.id !== fileId);
    });
    // 重置临时问卷并开启流程
    setTempSurvey({ hasDoubleSignature: null, hasPaymentRecord: null });
    setActiveWorkflowId(newRecord.id); 
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (record && record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }
    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: !r.isPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const finishSurvey = () => {
    if (tempSurvey.hasDoubleSignature === null || tempSurvey.hasPaymentRecord === null) {
      alert("请完成所有选项的确认。");
      return;
    }
    const id = activeWorkflowId;
    if (!id) return;

    setRecords(prev => prev.map(r => r.id === id ? { 
      ...r, 
      surveyAnswers: { 
        hasDoubleSignature: !!tempSurvey.hasDoubleSignature, 
        hasPaymentRecord: !!tempSurvey.hasPaymentRecord 
      } 
    } : r));
    setActiveWorkflowId(null);
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature ? '是' : '否',
      r.surveyAnswers?.hasPaymentRecord ? '是' : '否',
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border border-white/20">
          <div className="text-center mb-8">
            <span className="text-5xl drop-shadow-lg">📋</span>
            <h1 className="text-2xl font-black mt-4 text-slate-800">报销身份认证</h1>
            <p className="text-slate-400 text-sm mt-2">请一次性准确填写，我们将为您自动同步</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 border-slate-100 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg hover:bg-blue-700 shadow-lg active:scale-95 transition-all">开启高效报销</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 提交后问卷弹窗 */}
      {activeWorkflowId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">发票合规性确认</h2>
            <div className="space-y-6">
              <div>
                <p className="text-sm font-bold mb-3">1. 发票是否由2名以上的老师签字？</p>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setTempSurvey(prev => ({ ...prev, hasDoubleSignature: true }))} 
                    className={`flex-1 py-3 border-2 rounded-xl font-bold transition-all ${tempSurvey.hasDoubleSignature === true ? 'bg-blue-600 text-white border-blue-600 shadow-lg' : 'bg-blue-50 border-blue-100 text-blue-600'}`}
                  >是</button>
                  <button 
                    onClick={() => setTempSurvey(prev => ({ ...prev, hasDoubleSignature: false }))} 
                    className={`flex-1 py-3 border-2 rounded-xl font-bold transition-all ${tempSurvey.hasDoubleSignature === false ? 'bg-slate-600 text-white border-slate-600 shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                  >否</button>
                </div>
              </div>
              <div>
                <p className="text-sm font-bold mb-3">2. 已付发票是否附上支付记录？</p>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setTempSurvey(prev => ({ ...prev, hasPaymentRecord: true }))} 
                    className={`flex-1 py-3 border-2 rounded-xl font-bold transition-all ${tempSurvey.hasPaymentRecord === true ? 'bg-blue-600 text-white border-blue-600 shadow-lg' : 'bg-blue-50 border-blue-100 text-blue-600'}`}
                  >是</button>
                  <button 
                    onClick={() => setTempSurvey(prev => ({ ...prev, hasPaymentRecord: false }))} 
                    className={`flex-1 py-3 border-2 rounded-xl font-bold transition-all ${tempSurvey.hasPaymentRecord === false ? 'bg-slate-600 text-white border-slate-600 shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                  >否</button>
                </div>
              </div>
              <button 
                onClick={finishSurvey}
                className={`w-full py-4 rounded-2xl font-black text-lg shadow-xl transition-all active:scale-95 ${
                  tempSurvey.hasDoubleSignature !== null && tempSurvey.hasPaymentRecord !== null
                  ? 'bg-blue-600 text-white hover:bg-blue-700'
                  : 'bg-slate-200 text-slate-400 cursor-not-allowed'
                }`}
              >完成确认</button>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="h-4 w-[1px] bg-slate-200 hidden md:block" />
          <div className="hidden md:flex text-xs text-slate-400 gap-3">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>导师: <b className="text-slate-800">{user.supervisor}</b></span>
          </div>
        </div>
        <div className="flex gap-2">
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-bold">后台导出(全量)</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-bold">我的导出</button>
          <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${isAdminMode ? 'bg-red-50 text-red-600 border-red-200' : 'text-slate-400 border-slate-200'}`}>
            {isAdminMode ? '退出管理' : '管理员模式'}
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className={`lg:col-span-5 space-y-6 ${isAdminMode ? 'opacity-50 pointer-events-none' : ''}`}>
          <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl overflow-hidden relative">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
              <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none transition-all hover:bg-blue-100 group shadow-lg active:scale-95">
                <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
              </label>
            </div>

            <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
              <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📂</span>
              <p className="text-lg font-black text-slate-800">批量上传发票</p>
              <p className="text-sm text-slate-400 mt-2">支持 PDF / 图片 | AI 加速模式已开启</p>
              <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
            </div>

            <div className="mt-8 space-y-4">
              {files.map(item => (
                <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100'}`}>
                  <div className="relative flex-shrink-0">
                    <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border" alt="preview" />
                    {(item.isDuplicate || item.isBuyerValid === false) && (
                      <div className="absolute -top-2 -right-2 bg-red-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold shadow-lg">!</div>
                    )}
                  </div>
                  <div className="flex-grow min-w-0">
                    {item.status === 'processing' ? (
                      <div className="h-full flex flex-col justify-center">
                        <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                          <div className="h-full bg-blue-500 animate-[loading_1s_infinite]" style={{width: '70%'}} />
                        </div>
                        <p className="text-xs font-black text-blue-600 mt-3 animate-pulse">正在极速提取数据...</p>
                      </div>
                    ) : item.status === 'completed' && item.extractedData ? (
                      <div className="flex flex-col h-full justify-between">
                        <div>
                          <div className="flex justify-between items-start">
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            {item.isDuplicate && <span className="bg-amber-600 text-white text-[10px] px-2 py-0.5 rounded-lg font-black">重复报销</span>}
                          </div>
                          <p className="text-xs font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          <p className="text-[10px] font-mono text-slate-400"># {item.extractedData.invoiceNumber}</p>
                        </div>

                        {(item.isDuplicate || item.isBuyerValid === false) ? (
                          <div className="mt-3 space-y-2">
                            <div className="text-[10px] font-black bg-white/50 p-2 rounded-xl border shadow-sm">
                              {item.isDuplicate && <div className="text-amber-600 flex items-center gap-1">⚠️ 系统查重拦截：该发票已存在</div>}
                              {item.isBuyerValid === false && <div className="text-red-600 flex items-center gap-1">❌ 抬头错误：非江南大学或税号有误</div>}
                            </div>
                            {/* 新增显眼的删除按钮 */}
                            <button 
                              onClick={() => handleRemoveFile(item.id)} 
                              className="w-full py-2 bg-red-600 text-white rounded-xl text-[11px] font-black shadow-lg hover:bg-red-700 transition-all flex items-center justify-center gap-1"
                            >
                              <span>🗑️</span> 删除此无效单
                            </button>
                          </div>
                        ) : (
                          <div className="flex gap-2 mt-3">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-2.5 bg-blue-600 text-white rounded-xl text-xs font-bold shadow-lg active:scale-95 transition-all">确认无误</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl hover:bg-red-50 hover:text-red-600 transition-all">删除</button>
                          </div>
                        )}
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center h-full">
                        <span className="text-red-500 font-black text-xs mb-2">识别失败</span>
                        <button onClick={() => handleRemoveFile(item.id)} className="text-[10px] text-slate-400 underline">重试/删除</button>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* 报销记录/管理区 */}
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col h-[80vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <div>
                <h2 className="text-lg font-black text-slate-800">报销进程追踪</h2>
                <p className="text-xs text-slate-400 mt-1">发票实时查重范围：{records.length} 条已存记录</p>
              </div>
              <div className="text-right">
                <span className="text-xs font-black text-blue-600 block">{records.filter(r => r.status === 'success').length} 笔成功</span>
                <span className="text-[10px] text-slate-400">共计 ¥{records.reduce((acc, r) => acc + r.amount, 0).toLocaleString()}</span>
              </div>
            </div>

            <div className="flex-grow overflow-auto p-4 space-y-4">
              {records.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center opacity-20">
                  <span className="text-8xl">📤</span>
                  <p className="mt-4 font-black">快去上传发票吧</p>
                </div>
              ) : (
                records.map(r => (
                  <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-lg ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex gap-4 items-center">
                        <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-xl shadow-inner">🧾</div>
                        <div>
                          <h3 className="font-black text-slate-800">{r.category}</h3>
                          <p className="text-[10px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                        <button 
                          onClick={() => toggleRecordPaidStatus(r.id)}
                          disabled={r.paidEditCount >= 1 && !isAdminMode}
                          className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-all ${
                            r.isPaid ? 'bg-green-100 text-green-700 shadow-sm' : 'bg-amber-100 text-amber-700 shadow-sm'
                          } ${r.paidEditCount >= 1 && !isAdminMode ? 'opacity-50 cursor-not-allowed' : 'hover:scale-105 active:scale-95'}`}
                        >
                          {r.isPaid ? '已支付' : '待支付'} {r.paidEditCount >= 1 && !isAdminMode && '(锁定)'}
                        </button>
                      </div>
                    </div>

                    <ProgressSteps status={r.status} reason={r.rejectionReason} />

                    {isAdminMode && (
                      <div className="mt-4 pt-4 border-t flex flex-wrap gap-2 items-center">
                        <span className="text-[10px] font-black text-slate-400">后台状态控制:</span>
                        {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                          <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>{s}</button>
                        ))}
                        <button onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === 'rejected' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-500'}`}>退单</button>
                        <div className="ml-auto flex items-center gap-2 text-[10px] text-slate-400">
                          <span>提交人: {r.name}</span>
                          <button onClick={() => { if(confirm("管理删单?")) setRecords(prev => prev.filter(rec => rec.id !== r.id)) }} className="text-red-400 hover:text-red-600">删除</button>
                        </div>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes loading { 0% { transform: translateX(-100%); } 100% { transform: translateX(200%); } }
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

export interface InvoiceData {
  invoiceNumber: string;
  sellerName: string;
  buyerName: string;
  sellerTaxId: string;
  buyerTaxId: string;
  sellerBankAccount: string;
  category: string;
  amount: number;
}

export interface SubmitterInfo {
  name: string;
  studentId: string;
  supervisor: string;
  phone: string;
  isPaid: boolean;
}

export interface UserProfile extends Omit<SubmitterInfo, 'isPaid'> {
  isAdmin?: boolean;
}

export type ReimbursementStatus = 'box' | 'han' | 'assistant' | 'office' | 'success' | 'rejected';

export interface SubmissionRecord extends InvoiceData, SubmitterInfo {
  id: string;
  timestamp: number;
  paidEditCount: number;
  surveyAnswers?: {
    hasDoubleSignature?: boolean; // 2名以上老师签字 (仅针对待付)
    hasPaymentRecord?: boolean;   // 附上支付记录 (仅针对已付)
  };
  status: ReimbursementStatus;
  rejectionReason?: string;
}

export interface ProcessingFile {
  id: string;
  file: File;
  previewUrl: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  extractedData?: InvoiceData;
  error?: string;
  isBuyerValid?: boolean;
  isDuplicate?: boolean;
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
}

export interface IdeaBlueprint {
  title: string;
  summary: string;
  targetAudience: string;
  marketReferences: Array<{
    uri: string;
    title: string;
  }>;
  uniqueValueProp: string;
  marketOpportunities: string[];
  challenges: string[];
  roadmap: string[];
}

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";
const ADMIN_PASSWORD = "0911";

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [authorizedAdmins, setAuthorizedAdmins] = useState<string[]>([SUPER_ADMIN_ID]);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 工作流相关
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [workflowType, setWorkflowType] = useState<'paid' | 'unpaid' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    const savedAdmins = localStorage.getItem('authorized_admins');

    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);

    if (savedRecords) setRecords(JSON.parse(savedRecords));
    if (savedAdmins) setAuthorizedAdmins(JSON.parse(savedAdmins));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('authorized_admins', JSON.stringify(authorizedAdmins));
  }, [authorizedAdmins]);

  const isUserAdmin = user && authorizedAdmins.includes(user.studentId);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const authorizeNewAdmin = () => {
    const pass = prompt("请输入管理授权密码：");
    if (pass === ADMIN_PASSWORD) {
      const targetId = prompt("请输入要授权的学号/工号：");
      if (targetId && !authorizedAdmins.includes(targetId)) {
        setAuthorizedAdmins(prev => [...prev, targetId]);
        alert("授权成功！");
      }
    } else {
      alert("密码错误，授权失败。");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };
    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    // 根据当前勾选的“已付”状态决定工作流
    setWorkflowType(isPaid ? 'paid' : 'unpaid');
    setActiveWorkflowId(newRecord.id); 
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }

    const newIsPaid = !record.isPaid;

    // 如果是从待付改为已付，需要确认支付记录
    if (newIsPaid) {
      setWorkflowType('paid');
      setActiveWorkflowId(recordId);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: newIsPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const finishSurvey = (answer: boolean) => {
    if (!activeWorkflowId) return;
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(workflowType === 'paid' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));
    setActiveWorkflowId(null);
    setWorkflowType(null);
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">报销身份认证</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">进入系统</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 合规性问卷弹窗 */}
      {activeWorkflowId && workflowType && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center">
                {workflowType === 'paid' ? "已付发票是否附上支付记录？" : "发票是否由2名以上的老师签字？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => finishSurvey(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => finishSurvey(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="hidden md:flex text-xs text-slate-400 gap-3 ml-4">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>学号: <b className="text-slate-800">{user.studentId}</b></span>
          </div>
        </div>
        <div className="flex gap-2">
          {isUserAdmin && (
            <>
              <button onClick={authorizeNewAdmin} className="text-xs text-blue-500 hover:underline">授权管理</button>
              <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${isAdminMode ? 'bg-red-50 text-red-600 border-red-200' : 'text-slate-400 border-slate-200'}`}>
                {isAdminMode ? '退出后台' : '管理员模式'}
              </button>
            </>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-bold">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-bold">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 普通用户上传区 - 管理员模式下隐藏 */}
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
                </label>
              </div>

              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📂</span>
                <p className="text-lg font-black text-slate-800">上传发票</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100'}`}>
                    <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border" alt="preview" />
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center animate-pulse">识别中...</div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <div className="flex justify-between items-start">
                              <span className="text-xl font-black">¥{item.extractedData.amount.toFixed(2)}</span>
                              {item.isDuplicate && <span className="bg-amber-600 text-white text-[10px] px-2 py-0.5 rounded-lg font-black">重复</span>}
                            </div>
                            <p className="text-xs font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-3 flex gap-2">
                            {(item.isDuplicate || item.isBuyerValid === false) ? (
                              <button onClick={() => handleRemoveFile(item.id)} className="w-full py-2.5 bg-red-600 text-white rounded-xl text-xs font-black shadow-lg">🗑️ 删除此无效单</button>
                            ) : (
                              <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-xs font-black shadow-lg">确认无误</button>
                            )}
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold">识别失败</div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        {/* 记录区 - 管理员模式占满全宽 */}
        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[80vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <div>
                <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部报销清单 (后台管理)" : "我的报销进程"}</h2>
                <p className="text-xs text-slate-400 mt-1">发票号码是唯一的查重凭证</p>
              </div>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length === 0 ? (
                <div className="col-span-full h-full flex flex-col items-center justify-center opacity-20 py-20">
                  <span className="text-8xl">📦</span>
                  <p className="mt-4 font-black">空空如也</p>
                </div>
              ) : (
                (isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                  <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-lg ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex gap-4 items-center">
                        <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-xl">🧾</div>
                        <div>
                          <h3 className="font-black text-slate-800">{r.category}</h3>
                          <p className="text-[10px] font-mono text-slate-400 truncate max-w-[120px]">{r.invoiceNumber}</p>
                          {isAdminMode && <p className="text-[10px] text-blue-500 font-bold mt-1">提交人: {r.name} ({r.studentId})</p>}
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                        <button 
                          onClick={() => toggleRecordPaidStatus(r.id)}
                          disabled={r.paidEditCount >= 1 && !isAdminMode}
                          className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-all ${
                            r.isPaid ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                          } ${r.paidEditCount >= 1 && !isAdminMode ? 'opacity-50' : 'hover:scale-105'}`}
                        >
                          {r.isPaid ? '已付' : '待付'}
                        </button>
                      </div>
                    </div>

                    <ProgressSteps status={r.status} reason={r.rejectionReason} />

                    <div className="mt-4 p-3 bg-slate-50 rounded-2xl text-[10px] space-y-1">
                      {r.isPaid ? (
                        <div className="flex justify-between">
                          <span className="text-slate-400">支付记录附带：</span>
                          <span className={r.surveyAnswers?.hasPaymentRecord ? "text-green-600 font-bold" : "text-red-500 font-bold"}>
                            {r.surveyAnswers?.hasPaymentRecord === undefined ? "未确认" : (r.surveyAnswers.hasPaymentRecord ? "是" : "否")}
                          </span>
                        </div>
                      ) : (
                        <div className="flex justify-between">
                          <span className="text-slate-400">2名以上老师签字：</span>
                          <span className={r.surveyAnswers?.hasDoubleSignature ? "text-green-600 font-bold" : "text-red-500 font-bold"}>
                            {r.surveyAnswers?.hasDoubleSignature === undefined ? "未确认" : (r.surveyAnswers.hasDoubleSignature ? "是" : "否")}
                          </span>
                        </div>
                      )}
                    </div>

                    {isAdminMode && (
                      <div className="mt-4 pt-4 border-t space-y-3">
                        <div className="flex flex-wrap gap-1">
                          {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                            <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{s}</button>
                          ))}
                        </div>
                        <div className="flex gap-2">
                          <button onClick={() => {
                            const reason = prompt("请输入退单原因：");
                            if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                          }} className="flex-1 py-1.5 bg-red-50 text-red-500 text-[9px] font-bold rounded-lg border border-red-100">退单</button>
                          <button onClick={() => { if(confirm("彻底删除该发票记录？")) setRecords(prev => prev.filter(rec => rec.id !== r.id)) }} className="px-2 py-1.5 bg-slate-100 text-slate-400 text-[9px] font-bold rounded-lg">删除</button>
                        </div>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";
const ADMIN_PASSWORD = "0911";

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [authorizedAdmins, setAuthorizedAdmins] = useState<string[]>([SUPER_ADMIN_ID]);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 工作流相关
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [workflowType, setWorkflowType] = useState<'paid' | 'unpaid' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    const savedAdmins = localStorage.getItem('authorized_admins');

    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);

    if (savedRecords) setRecords(JSON.parse(savedRecords));
    if (savedAdmins) setAuthorizedAdmins(JSON.parse(savedAdmins));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('authorized_admins', JSON.stringify(authorizedAdmins));
  }, [authorizedAdmins]);

  const isUserAdmin = user && authorizedAdmins.includes(user.studentId);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const authorizeNewAdmin = () => {
    // 关键更改：根据用户需求精确设置提示词
    const pass = prompt("请输入四位数密码");
    if (pass === ADMIN_PASSWORD) {
      const targetId = prompt("请输入要授权的学号/工号：");
      if (targetId && !authorizedAdmins.includes(targetId)) {
        setAuthorizedAdmins(prev => [...prev, targetId]);
        alert("授权成功！");
      }
    } else if (pass !== null) {
      alert("密码错误，授权失败。");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };
    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setWorkflowType(isPaid ? 'paid' : 'unpaid');
    setActiveWorkflowId(newRecord.id); 
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }

    const newIsPaid = !record.isPaid;
    if (newIsPaid) {
      setWorkflowType('paid');
      setActiveWorkflowId(recordId);
    } else {
      setWorkflowType('unpaid');
      setActiveWorkflowId(recordId);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: newIsPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const finishSurvey = (answer: boolean) => {
    if (!activeWorkflowId) return;
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(workflowType === 'paid' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));
    setActiveWorkflowId(null);
    setWorkflowType(null);
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">报销身份认证</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">进入系统</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 合规性问卷弹窗 */}
      {activeWorkflowId && workflowType && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {workflowType === 'paid' ? "已付发票是否附上支付记录？" : "发票是否由2名以上的老师签字？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => finishSurvey(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => finishSurvey(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="hidden md:flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1 rounded-full border">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>学号: <b className="text-slate-800">{user.studentId}</b></span>
          </div>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <>
              <button onClick={authorizeNewAdmin} className="text-[10px] font-bold text-blue-500 px-3 py-1.5 hover:bg-blue-50 rounded-lg transition-colors border border-blue-100">授权管理</button>
              <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'}`}>
                {isAdminMode ? '退出管理' : '进入后台'}
              </button>
            </>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持多选 PDF / 图片批量上传</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100 hover:shadow-lg'}`}>
                    <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <p className="text-[10px] font-black text-blue-500 animate-pulse">识别中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">识别失败</div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className="mt-1 px-3 py-1 rounded-lg text-[10px] font-black bg-slate-100">{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>
                  <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100'}`}>{s}</button>
                      ))}
                      <button onClick={() => {
                        const reason = prompt("请输入退单原因：");
                        if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                      }} className="px-2 py-1 bg-red-50 text-red-500 text-[8px] font-bold rounded-lg">退单</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";
const ADMIN_PASSWORD = "0911";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [authorizedAdmins, setAuthorizedAdmins] = useState<string[]>([SUPER_ADMIN_ID]);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流增强
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    const savedAdmins = localStorage.getItem('authorized_admins');

    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);

    if (savedRecords) setRecords(JSON.parse(savedRecords));
    if (savedAdmins) setAuthorizedAdmins(JSON.parse(savedAdmins));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('authorized_admins', JSON.stringify(authorizedAdmins));
  }, [authorizedAdmins]);

  const isUserAdmin = user && authorizedAdmins.includes(user.studentId);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const authorizeNewAdmin = () => {
    const pass = prompt("请输入四位数密码");
    if (pass === ADMIN_PASSWORD) {
      const targetId = prompt("请输入要授权的学号/工号：");
      if (targetId && !authorizedAdmins.includes(targetId)) {
        setAuthorizedAdmins(prev => [...prev, targetId]);
        alert("授权成功！");
      }
    } else if (pass !== null) {
      alert("密码错误，授权失败。");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    // 设置问卷队列
    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">报销身份认证</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">进入系统</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && <p className="mt-4 text-[10px] text-center text-slate-400">步骤 1 / 2</p>}
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="hidden md:flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1 rounded-full border">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>学号: <b className="text-slate-800">{user.studentId}</b></span>
          </div>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <>
              <button onClick={authorizeNewAdmin} className="text-[10px] font-bold text-blue-500 px-3 py-1.5 hover:bg-blue-50 rounded-lg transition-colors border border-blue-100">授权管理</button>
              <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'}`}>
                {isAdminMode ? '退出管理' : '进入后台'}
              </button>
            </>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持多选 PDF / 图片批量上传</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100 hover:shadow-lg'}`}>
                    <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <p className="text-[10px] font-black text-blue-500 animate-pulse">识别中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">识别失败</div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-colors ${r.isPaid ? 'bg-blue-50 text-blue-600' : 'bg-slate-100'}`}>{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>
                  <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100'}`}>{s}</button>
                      ))}
                      <button onClick={() => {
                        const reason = prompt("请输入退单原因：");
                        if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                      }} className="px-2 py-1 bg-red-50 text-red-500 text-[8px] font-bold rounded-lg">退单</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";
const ADMIN_PASSWORD = "0911";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [authorizedAdmins, setAuthorizedAdmins] = useState<string[]>([SUPER_ADMIN_ID]);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');
    const savedAdmins = localStorage.getItem('authorized_admins');

    if (savedUser) setUser(JSON.parse(savedUser));
    else setIsLoginView(true);

    if (savedRecords) setRecords(JSON.parse(savedRecords));
    if (savedAdmins) setAuthorizedAdmins(JSON.parse(savedAdmins));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('authorized_admins', JSON.stringify(authorizedAdmins));
  }, [authorizedAdmins]);

  const isUserAdmin = user && authorizedAdmins.includes(user.studentId);

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const authorizeNewAdmin = () => {
    // 需求：提示词修改为“请输入密码”
    const pass = prompt("请输入密码");
    if (pass === ADMIN_PASSWORD) {
      const targetId = prompt("请输入要授权的学号/工号：");
      if (targetId && !authorizedAdmins.includes(targetId)) {
        setAuthorizedAdmins(prev => [...prev, targetId]);
        alert("授权成功！");
      }
    } else if (pass !== null) {
      alert("密码错误，授权失败。");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && data.buyerTaxId.trim().toUpperCase() === SCHOOL_TAX_ID;
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    // 需求：上传发票时，勾选已付的出现2个问题，未勾选已付的只出现1个提示词“是否双签”
    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次，无法继续更改。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      // 需求：修改支付状态变成已付后，出现“是否附上支付记录”的提示词
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">报销身份认证</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">进入系统</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && <p className="mt-4 text-[10px] text-center text-slate-400">步骤 1 / 2</p>}
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <div className="hidden md:flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1 rounded-full border">
            <span>用户: <b className="text-slate-800">{user.name}</b></span>
            <span>学号: <b className="text-slate-800">{user.studentId}</b></span>
          </div>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <>
              <button onClick={authorizeNewAdmin} className="text-[10px] font-bold text-blue-500 px-3 py-1.5 hover:bg-blue-50 rounded-lg transition-colors border border-blue-100">授权管理</button>
              <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'}`}>
                {isAdminMode ? '退出管理' : '进入后台'}
              </button>
            </>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持多选 PDF / 图片批量上传</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${item.isDuplicate ? 'bg-amber-50 border-amber-200' : item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 'bg-white border-slate-100 hover:shadow-lg'}`}>
                    <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <p className="text-[10px] font-black text-blue-500 animate-pulse">识别中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">识别失败</div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-colors ${r.isPaid ? 'bg-blue-50 text-blue-600' : 'bg-slate-100'}`}>{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>
                  <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100'}`}>{s}</button>
                      ))}
                      <button onClick={() => {
                        const reason = prompt("请输入退单原因：");
                        if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                      }} className="px-2 py-1 bg-red-50 text-red-500 text-[8px] font-bold rounded-lg">退单</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      // 优化后的识别逻辑，针对 PDF/图片通过 Gemini-3-Flash 极速提取
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    // 问卷逻辑：上传已付需确认双签+支付记录；未付仅确认双签
    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '😞' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">{user ? '修改个人信息' : '报销身份认证'}</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <div className="flex gap-2">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">保存信息</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && <p className="mt-4 text-[10px] text-center text-slate-400">步骤 1 / 2</p>}
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <button 
            onClick={handleEditProfile}
            className="flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1.5 rounded-full border hover:bg-slate-100 transition-colors group"
            title="点击修改信息"
          >
            <span className="group-hover:text-blue-600">用户: <b className="text-slate-800">{user.name}</b></span>
            <span className="group-hover:text-blue-600">学号: <b className="text-slate-800">{user.studentId}</b></span>
            <span className="text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">✎ 修改信息</span>
          </button>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'
              }`}
            >
              {isAdminMode ? '退出管理' : '后台管理'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持 PDF / 图片 (点击或拖拽)</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-lg'
                  }`}>
                    {item.file.type.includes('image') ? (
                      <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    ) : (
                      <div className="w-24 h-24 bg-red-50 rounded-2xl flex items-center justify-center text-3xl shadow-sm border border-red-100">PDF</div>
                    )}
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                            <div className="bg-blue-500 h-full animate-progress-indefinite"></div>
                          </div>
                          <p className="text-[10px] font-black text-blue-500">AI 正在深度解析中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">
                          {item.error || '解析异常'}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单 (管理员视图)" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl ${r.status === 'rejected' ? 'border-red-100' : 'border-slate-50'}`}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-colors ${r.isPaid ? 'bg-blue-50 text-blue-600' : 'bg-slate-100'}`}>{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>
                  <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100'}`}>{s}</button>
                      ))}
                      <button onClick={() => {
                        const reason = prompt("请输入退单原因：");
                        if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                      }} className="px-2 py-1 bg-red-50 text-red-500 text-[8px] font-bold rounded-lg">退单</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
      `}</style>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Chat } from "@google/genai";
import { InvoiceData } from "../types";

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.readAsDataURL(file);
  });
  return {
    inlineData: {
      data: await base64EncodedDataPromise,
      mimeType: file.type,
    },
  };
};

export const extractInvoiceData = async (file: File): Promise<InvoiceData> => {
  // 采用 gemini-3-flash-preview 提供最快响应
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const docPart = await fileToGenerativePart(file);

  // 进一步精简 Prompt 以降低 Token 消耗并提升生成速度
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        docPart,
        { text: "Output JSON ONLY. Required fields: invoiceNumber, sellerName, buyerName, sellerTaxId, buyerTaxId, sellerBankAccount, category, amount. For Buyer Name/TaxID, look for '购买方' or '付款人'. For Seller Bank, look for '开户行及账号'. Amount is the '合计' or '价税合计'." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 0 }, // OCR 任务禁用思维链以提速
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          invoiceNumber: { type: Type.STRING },
          sellerName: { type: Type.STRING },
          buyerName: { type: Type.STRING },
          sellerTaxId: { type: Type.STRING },
          buyerTaxId: { type: Type.STRING },
          sellerBankAccount: { type: Type.STRING },
          category: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        },
        required: ["invoiceNumber", "sellerName", "buyerName", "sellerTaxId", "buyerTaxId", "category", "amount"]
      }
    }
  });

  const text = response.text || '{}';
  try {
    return JSON.parse(text) as InvoiceData;
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("Failed to parse invoice data");
  }
};

export const createChat = (systemInstruction: string): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: { systemInstruction },
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 ${
              isFinished ? 'bg-green-100 border-green-500' : isRejected ? 'bg-red-100 border-red-500 animate-pulse' : 'bg-white border-gray-200'
            }`}>
              {isFinished ? '✅' : isRejected ? '❌' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">{user ? '修改个人信息' : '报销身份认证'}</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <div className="flex gap-2">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">保存信息</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && <p className="mt-4 text-[10px] text-center text-slate-400">步骤 1 / 2</p>}
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <button 
            onClick={handleEditProfile}
            className="flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1.5 rounded-full border hover:bg-slate-100 transition-colors group"
            title="点击修改信息"
          >
            <span className="group-hover:text-blue-600">用户: <b className="text-slate-800">{user.name}</b></span>
            <span className="group-hover:text-blue-600">学号: <b className="text-slate-800">{user.studentId}</b></span>
            <span className="text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">✎ 修改信息</span>
          </button>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'
              }`}
            >
              {isAdminMode ? '退出管理' : '后台管理'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持 PDF / 图片 (点击或拖拽)</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-lg'
                  }`}>
                    {item.file.type.includes('image') ? (
                      <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    ) : (
                      <div className="w-24 h-24 bg-red-50 rounded-2xl flex items-center justify-center text-3xl shadow-sm border border-red-100">PDF</div>
                    )}
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                            <div className="bg-blue-500 h-full animate-progress-indefinite"></div>
                          </div>
                          <p className="text-[10px] font-black text-blue-500">AI 正在深度解析中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">
                          {item.error || '解析异常'}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden relative">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单 (管理员视图)" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl relative overflow-hidden ${r.status === 'rejected' ? 'border-red-200 bg-red-50/10' : 'border-slate-50'}`}>
                  {/* 退单状态水印图标 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-4 right-4 z-0 pointer-events-none opacity-20">
                      <span className="text-7xl font-black text-red-500">×</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-4 relative z-10">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-colors ${r.isPaid ? 'bg-blue-50 text-blue-600' : 'bg-slate-100'}`}>{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>

                  <div className="relative z-10">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white' : 'bg-slate-100 hover:bg-slate-200'}`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-2 py-1 flex items-center gap-1 text-[8px] font-bold rounded-lg transition-colors ${r.status === 'rejected' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-500 hover:bg-red-100'}`}
                      >
                        <span>退单</span>
                        <span className="text-sm">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 font-black transition-all ${
              isFinished ? 'bg-green-100 border-green-500 text-green-600 shadow-lg shadow-green-100' : 
              isRejected ? 'bg-red-100 border-red-500 text-red-600 shadow-lg shadow-red-100 animate-pulse' : 
              'bg-white border-gray-200 text-gray-300'
            }`}>
              {isFinished ? '✅' : isRejected ? '×' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">{user ? '修改个人信息' : '报销身份认证'}</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <div className="flex gap-2">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">保存信息</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && <p className="mt-4 text-[10px] text-center text-slate-400">步骤 1 / 2</p>}
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <button 
            onClick={handleEditProfile}
            className="flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1.5 rounded-full border hover:bg-slate-100 transition-colors group"
            title="点击修改信息"
          >
            <span className="group-hover:text-blue-600">用户: <b className="text-slate-800">{user.name}</b></span>
            <span className="group-hover:text-blue-600">学号: <b className="text-slate-800">{user.studentId}</b></span>
            <span className="text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">✎ 修改信息</span>
          </button>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'
              }`}
            >
              {isAdminMode ? '退出管理' : '后台管理'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持 PDF / 图片 (点击或拖拽)</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-lg'
                  }`}>
                    {item.file.type.includes('image') ? (
                      <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    ) : (
                      <div className="w-24 h-24 bg-red-50 rounded-2xl flex items-center justify-center text-3xl shadow-sm border border-red-100">PDF</div>
                    )}
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                            <div className="bg-blue-500 h-full animate-progress-indefinite"></div>
                          </div>
                          <p className="text-[10px] font-black text-blue-500">AI 正在深度解析中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">
                          {item.error || '解析异常'}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden relative">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单 (管理员视图)" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl relative overflow-hidden ${r.status === 'rejected' ? 'border-red-200 bg-red-50/10 shadow-red-50/20' : 'border-slate-50'}`}>
                  {/* 退单状态水印图标 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-4 right-4 z-0 pointer-events-none opacity-20">
                      <span className="text-8xl font-black text-red-500">×</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-4 relative z-10">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-colors ${r.isPaid ? 'bg-blue-50 text-blue-600' : 'bg-slate-100'}`}>{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>

                  <div className="relative z-10">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white shadow-sm' : 'bg-slate-100 hover:bg-slate-200 text-slate-600'}`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-2 py-1 flex items-center gap-1 text-[8px] font-bold rounded-lg transition-all ${r.status === 'rejected' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-500 hover:bg-red-100'}`}
                      >
                        <span>退单</span>
                        <span className="text-sm font-black">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-2 bg-gray-50 rounded-lg border">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative">
              <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-sm' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[8px] mt-1 font-bold ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
            </div>
          ))}
          <div className="flex flex-col items-center">
            <div className={`w-8 h-8 flex items-center justify-center rounded-full text-lg border-2 font-black transition-all ${
              isFinished ? 'bg-green-100 border-green-500 text-green-600 shadow-lg shadow-green-100' : 
              isRejected ? 'bg-red-100 border-red-500 text-red-600 shadow-lg shadow-red-100 animate-pulse' : 
              'bg-white border-gray-200 text-gray-300'
            }`}>
              {isFinished ? '✅' : isRejected ? '×' : '⌛'}
            </div>
            <span className={`text-[8px] mt-1 font-bold ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '已退单' : '进行中'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-1 p-1 bg-red-50 border border-red-100 rounded text-[9px] text-red-600 font-bold">
            退单原因：{reason}
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-md w-full border">
          <div className="text-center mb-8">
            <span className="text-5xl">📋</span>
            <h1 className="text-2xl font-black mt-4">{user ? '修改个人信息' : '报销身份认证'}</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" defaultValue={user?.name} placeholder="姓名 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="studentId" defaultValue={user?.studentId} placeholder="学号/工号 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="supervisor" defaultValue={user?.supervisor} placeholder="指导老师 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <input name="phone" defaultValue={user?.phone} placeholder="联系电话 *" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500" required />
            <div className="flex gap-2">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg">保存信息</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl scale-in-center">
            <h2 className="text-xl font-black mb-6 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && <p className="mt-4 text-[10px] text-center text-slate-400">步骤 1 / 2</p>}
          </div>
        </div>
      )}

      <header className="bg-white border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2 rounded-xl text-lg font-black shadow-blue-200 shadow-lg">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手</h1>
          <button 
            onClick={handleEditProfile}
            className="flex text-[10px] text-slate-400 gap-3 ml-4 bg-slate-50 px-3 py-1.5 rounded-full border hover:bg-slate-100 transition-colors group"
            title="点击修改信息"
          >
            <span className="group-hover:text-blue-600">用户: <b className="text-slate-800">{user.name}</b></span>
            <span className="group-hover:text-blue-600">学号: <b className="text-slate-800">{user.studentId}</b></span>
            <span className="text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">✎ 修改信息</span>
          </button>
        </div>
        <div className="flex gap-2 items-center">
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-4 py-2 rounded-xl text-xs font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-lg' : 'text-slate-600 border-slate-200 hover:border-blue-400'
              }`}
            >
              {isAdminMode ? '退出管理' : '后台管理'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-green-100 shadow-lg">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-500">
            <section className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 shadow-xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-sm font-black text-slate-300 uppercase tracking-tighter">智能识别区</h2>
                <label className="flex items-center gap-3 px-6 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-transform">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-6 h-6 rounded-lg text-blue-600 focus:ring-0" />
                  <span className={`text-2xl font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-3xl p-10 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <span className="text-6xl block mb-4 group-hover:scale-110 transition-transform">📄</span>
                <p className="text-lg font-black text-slate-800">上传新发票</p>
                <p className="text-xs text-slate-400 mt-2">支持 PDF / 图片 (点击或拖拽)</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-8 space-y-4">
                {files.map(item => (
                  <div key={item.id} className={`p-5 rounded-[1.5rem] border-2 flex gap-4 transition-all ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-lg'
                  }`}>
                    {item.file.type.includes('image') ? (
                      <img src={item.previewUrl} className="w-24 h-24 object-cover rounded-2xl shadow-sm border bg-slate-50" alt="preview" />
                    ) : (
                      <div className="w-24 h-24 bg-red-50 rounded-2xl flex items-center justify-center text-3xl shadow-sm border border-red-100">PDF</div>
                    )}
                    <div className="flex-grow min-w-0">
                      {item.status === 'processing' ? (
                        <div className="h-full flex flex-col justify-center items-center gap-2">
                          <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                            <div className="bg-blue-500 h-full animate-progress-indefinite"></div>
                          </div>
                          <p className="text-[10px] font-black text-blue-500">AI 正在深度解析中...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <span className="text-xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <p className="text-[10px] font-bold text-slate-500 truncate">{item.extractedData.category}</p>
                          </div>
                          <div className="mt-2 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-2.5 bg-blue-600 text-white rounded-xl text-[10px] font-black shadow-lg">提交</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-3 py-2.5 bg-slate-100 text-slate-400 rounded-xl text-[10px]">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-4 text-red-500 font-bold text-xs">
                          {item.error || '解析异常'}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-500`}>
          <div className="bg-white rounded-[2rem] border shadow-xl flex flex-col min-h-[85vh] overflow-hidden relative">
            <div className="px-8 py-6 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-lg font-black text-slate-800">{isAdminMode ? "全部用户报销单 (管理员视图)" : "我的报销流水"}</h2>
            </div>

            <div className={`flex-grow overflow-auto p-4 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6' : 'space-y-4'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-3xl p-6 transition-all group hover:shadow-xl relative overflow-hidden ${r.status === 'rejected' ? 'border-red-200 bg-red-50/10 shadow-red-50/20' : 'border-slate-50'}`}>
                  {/* 退单状态水印图标 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-4 right-4 z-0 pointer-events-none opacity-20">
                      <span className="text-8xl font-black text-red-500">×</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-4 relative z-10">
                    <div className="flex gap-4 items-center">
                      <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="font-black text-slate-800">{r.category}</h3>
                        <p className="text-[9px] font-mono text-slate-400">{r.invoiceNumber}</p>
                        {isAdminMode && <div className="text-[10px] font-black text-blue-600">{r.name} ({r.studentId})</div>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button onClick={() => toggleRecordPaidStatus(r.id)} className={`mt-1 px-3 py-1 rounded-lg text-[10px] font-black transition-colors ${r.isPaid ? 'bg-blue-50 text-blue-600' : 'bg-slate-100'}`}>{r.isPaid ? '已付' : '待付'}</button>
                    </div>
                  </div>

                  <div className="relative z-10">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-4 pt-4 border-t flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-2 py-1 rounded-lg text-[8px] font-bold ${r.status === s ? 'bg-blue-600 text-white shadow-sm' : 'bg-slate-100 hover:bg-slate-200 text-slate-600'}`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-2 py-1 flex items-center gap-1 text-[8px] font-bold rounded-lg transition-all ${r.status === 'rejected' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-500 hover:bg-red-100'}`}
                      >
                        <span>退单</span>
                        <span className="text-sm font-black">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
      <style>{`
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
      `}</style>
    </div>
  );
};

export default App;

{
  "name": "江南报销助手",
  "description": "基于 AI 的极速发票识别与报销进度追踪工具",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-3 bg-gray-50 rounded-2xl border border-slate-100 shadow-inner">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative group">
              <div className={`w-9 h-9 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all duration-300 ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-md scale-110' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
              {i < steps.length - 1 && (
                <div className={`absolute left-[50%] top-4 w-full h-0.5 -z-0 ${i < currentIndex && !isRejected ? 'bg-blue-400' : 'bg-gray-100'}`} style={{ width: 'calc(100% + 20px)' }}></div>
              )}
            </div>
          ))}
          <div className="flex flex-col items-center ml-2">
            <div className={`w-9 h-9 flex items-center justify-center rounded-full text-xl border-2 font-black transition-all duration-500 ${
              isFinished ? 'bg-green-100 border-green-500 text-green-600 shadow-lg shadow-green-200' : 
              isRejected ? 'bg-red-100 border-red-500 text-red-600 shadow-lg shadow-red-200 animate-pulse' : 
              'bg-white border-gray-200 text-gray-300'
            }`}>
              {isFinished ? '✅' : isRejected ? '×' : '⌛'}
            </div>
            <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '报销失败' : '最终状态'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-2 p-2 bg-red-50 border border-red-100 rounded-xl text-[10px] text-red-700 font-bold flex items-start gap-2">
            <span className="text-sm">⚠️</span>
            <span>退单原因：{reason}</span>
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-200 scale-in-center">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-4xl shadow-xl shadow-blue-200">📋</div>
            <h1 className="text-3xl font-black mt-6 tracking-tight">{user ? '修改个人信息' : '报销身份认证'}</h1>
            <p className="text-slate-400 mt-2 text-sm">请确认为江南大学在籍学生或教工</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">姓名</label>
              <input name="name" defaultValue={user?.name} placeholder="请输入姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">学号/工号</label>
              <input name="studentId" defaultValue={user?.studentId} placeholder="请输入学号/工号" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">指导老师</label>
              <input name="supervisor" defaultValue={user?.supervisor} placeholder="请输入导师姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label>
              <input name="phone" defaultValue={user?.phone} placeholder="请输入联系方式" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="flex gap-3 pt-4">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg hover:bg-slate-200 transition-colors">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">保存并进入</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100 selection:text-blue-600">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full shadow-2xl scale-in-center border border-slate-100">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6">🛡️</div>
            <h2 className="text-2xl font-black mb-4 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed text-slate-600">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 active:scale-95 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && (
              <div className="mt-8 flex justify-center gap-2">
                <div className="w-8 h-1.5 bg-blue-600 rounded-full"></div>
                <div className="w-8 h-1.5 bg-slate-100 rounded-full"></div>
              </div>
            )}
          </div>
        </div>
      )}

      <header className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2.5 rounded-2xl text-xl font-black shadow-blue-200 shadow-xl">AI</div>
          <div className="flex flex-col">
            <h1 className="text-xl font-black tracking-tighter leading-none">江南报销助手</h1>
            <span className="text-[10px] font-bold text-blue-500 tracking-widest uppercase">Smart Reimbursement</span>
          </div>
          <button 
            onClick={handleEditProfile}
            className="hidden md:flex items-center text-[11px] text-slate-500 gap-3 ml-6 bg-slate-50 hover:bg-white hover:shadow-md px-4 py-2 rounded-2xl border border-slate-100 transition-all group"
          >
            <div className="flex flex-col items-start">
              <span>用户: <b className="text-slate-800 font-black">{user.name}</b></span>
              <span>学号: <b className="text-slate-800 font-black">{user.studentId}</b></span>
            </div>
            <span className="text-blue-500 font-black bg-blue-50 px-2 py-1 rounded-lg opacity-80 group-hover:opacity-100 transition-opacity">✎ 修改</span>
          </button>
        </div>
        <div className="flex gap-3 items-center">
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-5 py-2.5 rounded-2xl text-[11px] font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-xl' : 'text-slate-600 border-slate-200 hover:border-blue-400 hover:text-blue-600'
              }`}
            >
              {isAdminMode ? '退出管理' : '进入后台'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-xl hover:bg-slate-900 transition-colors">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-green-100 shadow-xl hover:bg-green-700 transition-colors">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-700">
            <section className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-8">
                <div className="flex flex-col">
                  <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest">Smart Scanning</h2>
                  <p className="text-xl font-black text-slate-800">发票识别区</p>
                </div>
                <label className="flex items-center gap-3 px-5 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-all group">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-5 h-5 rounded-lg text-blue-600 focus:ring-0 cursor-pointer" />
                  <span className={`text-lg font-black transition-colors ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>

              <div 
                onClick={() => fileInputRef.current?.click()} 
                className="border-4 border-dashed border-slate-100 rounded-[2rem] p-12 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/50 transition-all group relative overflow-hidden"
              >
                <div className="absolute inset-0 bg-blue-50 opacity-0 group-hover:opacity-10 transition-opacity"></div>
                <span className="text-7xl block mb-6 group-hover:scale-110 group-hover:-rotate-6 transition-transform duration-500">📸</span>
                <p className="text-xl font-black text-slate-800">点击上传发票</p>
                <p className="text-sm text-slate-400 mt-2">支持 PDF 或 图片，系统将自动极速提取</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-10 space-y-5">
                {files.length === 0 && (
                  <div className="py-12 border-2 border-dashed border-slate-50 rounded-3xl text-center text-slate-300 font-bold text-sm">
                    暂未上传任何文件
                  </div>
                )}
                {files.map(item => (
                  <div key={item.id} className={`p-6 rounded-[2rem] border-2 flex gap-5 transition-all animate-in slide-in-from-bottom-4 duration-300 ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-2xl hover:border-blue-100'
                  }`}>
                    <div className="relative">
                      {item.file.type.includes('image') ? (
                        <img src={item.previewUrl} className="w-28 h-28 object-cover rounded-3xl shadow-md border-2 border-white bg-slate-50" alt="preview" />
                      ) : (
                        <div className="w-28 h-28 bg-red-50 rounded-3xl flex flex-col items-center justify-center shadow-md border-2 border-white">
                          <span className="text-4xl">📄</span>
                          <span className="text-[10px] font-black text-red-500 mt-1 uppercase">PDF Document</span>
                        </div>
                      )}
                      {item.isBuyerValid === false && (
                        <div className="absolute -top-2 -right-2 bg-red-500 text-white w-7 h-7 rounded-full flex items-center justify-center text-xs font-black shadow-lg border-2 border-white" title="抬头有误">!</div>
                      )}
                    </div>
                    <div className="flex-grow min-w-0 flex flex-col justify-center">
                      {item.status === 'processing' ? (
                        <div className="space-y-3">
                          <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                            <div className="bg-blue-600 h-full animate-progress-indefinite shadow-sm"></div>
                          </div>
                          <p className="text-[11px] font-black text-blue-500 uppercase tracking-widest">AI Deep Parsing...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <div className="flex justify-between items-start">
                              <span className="text-2xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                              <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full uppercase tracking-tighter">{item.extractedData.category}</span>
                            </div>
                            <p className="text-[10px] font-bold text-slate-400 mt-1 truncate">No. {item.extractedData.invoiceNumber}</p>
                          </div>
                          <div className="mt-4 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">提交报销单</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-4 py-3 bg-slate-100 text-slate-400 rounded-2xl text-[11px] font-black hover:bg-slate-200 transition-colors">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center justify-center h-full">
                          <span className="text-2xl mb-1">⚠️</span>
                          <p className="text-[11px] font-black text-red-500 uppercase">{item.error || '识别异常'}</p>
                          <button onClick={() => handleRemoveFile(item.id)} className="mt-2 text-[10px] font-bold text-slate-400 underline">移除重试</button>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-700 animate-in fade-in slide-in-from-right duration-700`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[85vh] overflow-hidden relative border-slate-100">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/30 backdrop-blur-sm">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
                <p className="text-slate-400 text-xs mt-1">
                  {isAdminMode ? "管理员模式：点击状态快速流转发票进度" : "点击发票卡片查看详细信息与审批原因"}
                </p>
              </div>
              <div className="flex items-center gap-4">
                 <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black text-slate-300 uppercase">Records Found</span>
                    <span className="text-xl font-black text-blue-600">{(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length}</span>
                 </div>
              </div>
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' : 'space-y-6'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-[50vh] opacity-30 grayscale">
                  <span className="text-9xl mb-4">📥</span>
                  <p className="text-2xl font-black text-slate-400">尚无报销记录</p>
                </div>
              )}
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-[2rem] p-8 transition-all group hover:shadow-2xl relative overflow-hidden flex flex-col ${r.status === 'rejected' ? 'border-red-100 bg-red-50/10' : 'border-slate-50'}`}>
                  {/* 退单状态水印图标 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-20 rotate-12">
                      <span className="text-9xl font-black text-red-500 select-none">×</span>
                    </div>
                  )}
                  {r.status === 'success' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-10">
                      <span className="text-9xl font-black text-green-500 select-none">✓</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-6 relative z-10">
                    <div className="flex gap-5 items-center">
                      <div className="bg-slate-50 w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-inner group-hover:bg-blue-50 transition-colors">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800 tracking-tight">{r.category}</h3>
                        <p className="text-[10px] font-mono font-bold text-slate-400 mt-0.5">ID: {r.invoiceNumber}</p>
                        {isAdminMode && (
                          <div className="mt-1 flex items-center gap-2">
                             <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                             <span className="text-[11px] font-black text-blue-600">{r.name} · {r.studentId}</span>
                          </div>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button 
                        onClick={() => toggleRecordPaidStatus(r.id)} 
                        className={`mt-2 px-4 py-1.5 rounded-xl text-[10px] font-black transition-all active:scale-95 shadow-sm ${
                          r.isPaid ? 'bg-blue-500 text-white shadow-blue-100' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                        }`}
                      >
                        {r.isPaid ? '已付发票' : '待付发票'}
                      </button>
                    </div>
                  </div>

                  <div className="relative z-10 flex-grow">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-6 pt-6 border-t border-slate-100 flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${
                          r.status === s ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-slate-50 text-slate-500 hover:bg-slate-200'
                        }`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-4 py-1.5 flex items-center gap-1.5 text-[9px] font-black uppercase rounded-xl transition-all ${
                          r.status === 'rejected' ? 'bg-red-600 text-white shadow-lg shadow-red-100' : 'bg-red-50 text-red-500 hover:bg-red-100'
                        }`}
                      >
                        <span>退单</span>
                        <span className="text-base font-black leading-none">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto p-12 text-center text-slate-300 font-black text-[10px] uppercase tracking-[0.2em]">
        Jiangnan University · Smart Financial AI Assistant · Built with Gemini
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }

        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 20px; border: 2px solid white; }
        ::-webkit-scrollbar-thumb:hover { background: #CBD5E1; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [shareText, setShareText] = useState('分享助手');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
      setShareText('已复制链接！');
      setTimeout(() => setShareText('分享助手'), 2000);
    }).catch(err => {
      alert("复制失败，请手动复制地址栏链接");
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-3 bg-gray-50 rounded-2xl border border-slate-100 shadow-inner">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative group">
              <div className={`w-9 h-9 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all duration-300 ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-md scale-110' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
              {i < steps.length - 1 && (
                <div className={`absolute left-[50%] top-4 w-full h-0.5 -z-0 ${i < currentIndex && !isRejected ? 'bg-blue-400' : 'bg-gray-100'}`} style={{ width: 'calc(100% + 20px)' }}></div>
              )}
            </div>
          ))}
          <div className="flex flex-col items-center ml-2">
            <div className={`w-9 h-9 flex items-center justify-center rounded-full text-xl border-2 font-black transition-all duration-500 ${
              isFinished ? 'bg-green-100 border-green-500 text-green-600 shadow-lg shadow-green-200' : 
              isRejected ? 'bg-red-100 border-red-500 text-red-600 shadow-lg shadow-red-200 animate-pulse' : 
              'bg-white border-gray-200 text-gray-300'
            }`}>
              {isFinished ? '✅' : isRejected ? '×' : '⌛'}
            </div>
            <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '报销失败' : '最终状态'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-2 p-2 bg-red-50 border border-red-100 rounded-xl text-[10px] text-red-700 font-bold flex items-start gap-2">
            <span className="text-sm">⚠️</span>
            <span>退单原因：{reason}</span>
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-200 scale-in-center">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-4xl shadow-xl shadow-blue-200">📋</div>
            <h1 className="text-3xl font-black mt-6 tracking-tight">{user ? '修改个人信息' : '报销身份认证'}</h1>
            <p className="text-slate-400 mt-2 text-sm">请确认为江南大学在籍学生或教工</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">姓名</label>
              <input name="name" defaultValue={user?.name} placeholder="请输入姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">学号/工号</label>
              <input name="studentId" defaultValue={user?.studentId} placeholder="请输入学号/工号" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">指导老师</label>
              <input name="supervisor" defaultValue={user?.supervisor} placeholder="请输入导师姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label>
              <input name="phone" defaultValue={user?.phone} placeholder="请输入联系方式" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="flex gap-3 pt-4">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg hover:bg-slate-200 transition-colors">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">保存并进入</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100 selection:text-blue-600">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full shadow-2xl scale-in-center border border-slate-100">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6">🛡️</div>
            <h2 className="text-2xl font-black mb-4 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed text-slate-600">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 active:scale-95 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && (
              <div className="mt-8 flex justify-center gap-2">
                <div className="w-8 h-1.5 bg-blue-600 rounded-full"></div>
                <div className="w-8 h-1.5 bg-slate-100 rounded-full"></div>
              </div>
            )}
          </div>
        </div>
      )}

      <header className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2.5 rounded-2xl text-xl font-black shadow-blue-200 shadow-xl">AI</div>
          <div className="flex flex-col">
            <h1 className="text-xl font-black tracking-tighter leading-none">江南报销助手</h1>
            <span className="text-[10px] font-bold text-blue-500 tracking-widest uppercase">Smart Reimbursement</span>
          </div>
          <button 
            onClick={handleEditProfile}
            className="hidden md:flex items-center text-[11px] text-slate-500 gap-3 ml-6 bg-slate-50 hover:bg-white hover:shadow-md px-4 py-2 rounded-2xl border border-slate-100 transition-all group"
          >
            <div className="flex flex-col items-start">
              <span>用户: <b className="text-slate-800 font-black">{user.name}</b></span>
              <span>学号: <b className="text-slate-800 font-black">{user.studentId}</b></span>
            </div>
            <span className="text-blue-500 font-black bg-blue-50 px-2 py-1 rounded-lg opacity-80 group-hover:opacity-100 transition-opacity">✎ 修改</span>
          </button>
        </div>
        <div className="flex gap-3 items-center">
          <button 
            onClick={handleShare}
            className="bg-blue-50 text-blue-600 px-5 py-2.5 rounded-2xl text-[11px] font-black border border-blue-100 shadow-sm hover:bg-blue-100 transition-all flex items-center gap-2"
          >
            <span className="text-lg leading-none">🔗</span>
            {shareText}
          </button>
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-5 py-2.5 rounded-2xl text-[11px] font-black border-2 transition-all ${
