                            <div className="bg-blue-600 h-full animate-progress-indefinite shadow-sm"></div>
                          </div>
                          <p className="text-[11px] font-black text-blue-500 uppercase tracking-widest">AI Deep Parsing...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <div className="flex justify-between items-start">
                              <span className="text-2xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                              <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full uppercase tracking-tighter">{item.extractedData.category}</span>
                            </div>
                            <p className="text-[10px] font-bold text-slate-400 mt-1 truncate">No. {item.extractedData.invoiceNumber}</p>
                          </div>
                          <div className="mt-4 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">提交报销单</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-4 py-3 bg-slate-100 text-slate-400 rounded-2xl text-[11px] font-black hover:bg-slate-200 transition-colors">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center justify-center h-full">
                          <span className="text-2xl mb-1">⚠️</span>
                          <p className="text-[11px] font-black text-red-500 uppercase">{item.error || '识别异常'}</p>
                          <button onClick={() => handleRemoveFile(item.id)} className="mt-2 text-[10px] font-bold text-slate-400 underline">移除重试</button>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-700 animate-in fade-in slide-in-from-right duration-700`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[85vh] overflow-hidden relative border-slate-100">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/30 backdrop-blur-sm">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
                <p className="text-slate-400 text-xs mt-1">
                  {isAdminMode ? "管理员模式：点击状态快速流转发票进度" : "点击发票卡片查看详细信息与审批原因"}
                </p>
              </div>
              <div className="flex items-center gap-4">
                 <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black text-slate-300 uppercase">Records Found</span>
                    <span className="text-xl font-black text-blue-600">{(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length}</span>
                 </div>
              </div>
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' : 'space-y-6'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-[50vh] opacity-30 grayscale">
                  <span className="text-9xl mb-4">📥</span>
                  <p className="text-2xl font-black text-slate-400">尚无报销记录</p>
                </div>
              )}
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-[2rem] p-8 transition-all group hover:shadow-2xl relative overflow-hidden flex flex-col ${r.status === 'rejected' ? 'border-red-100 bg-red-50/10 shadow-red-50/20' : 'border-slate-50'}`}>
                  {/* 退单状态水印图标 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-20 rotate-12">
                      <span className="text-9xl font-black text-red-500 select-none">×</span>
                    </div>
                  )}
                  {r.status === 'success' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-10">
                      <span className="text-9xl font-black text-green-500 select-none">✓</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-6 relative z-10">
                    <div className="flex gap-5 items-center">
                      <div className="bg-slate-50 w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-inner group-hover:bg-blue-50 transition-colors">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800 tracking-tight">{r.category}</h3>
                        <p className="text-[10px] font-mono font-bold text-slate-400 mt-0.5">ID: {r.invoiceNumber}</p>
                        {isAdminMode && (
                          <div className="mt-1 flex items-center gap-2">
                             <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                             <span className="text-[11px] font-black text-blue-600">{r.name} · {r.studentId}</span>
                          </div>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button 
                        onClick={() => toggleRecordPaidStatus(r.id)} 
                        className={`mt-2 px-4 py-1.5 rounded-xl text-[10px] font-black transition-all active:scale-95 shadow-sm ${
                          r.isPaid ? 'bg-blue-500 text-white shadow-blue-100' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                        }`}
                      >
                        {r.isPaid ? '已付发票' : '待付发票'}
                      </button>
                    </div>
                  </div>

                  <div className="relative z-10 flex-grow">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-6 pt-6 border-t border-slate-100 flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${
                          r.status === s ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-slate-50 text-slate-500 hover:bg-slate-200'
                        }`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-4 py-1.5 flex items-center gap-1.5 text-[9px] font-black uppercase rounded-xl transition-all ${
                          r.status === 'rejected' ? 'bg-red-600 text-white shadow-lg shadow-red-100' : 'bg-red-50 text-red-500 hover:bg-red-100'
                        }`}
                      >
                        <span>退单</span>
                        <span className="text-base font-black leading-none">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto p-12 text-center text-slate-300 font-black text-[10px] uppercase tracking-[0.2em]">
        Jiangnan University · Smart Financial AI Assistant · Built with Gemini
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }

        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 20px; border: 2px solid white; }
        ::-webkit-scrollbar-thumb:hover { background: #CBD5E1; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [shareText, setShareText] = useState('分享助手');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
      setShareText('已复制链接！');
      setTimeout(() => setShareText('分享助手'), 2000);
    }).catch(err => {
      alert("复制失败，请手动复制地址栏链接");
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-3 bg-gray-50 rounded-2xl border border-slate-100 shadow-inner">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative group">
              <div className={`w-9 h-9 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all duration-300 ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-md scale-110' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
              {i < steps.length - 1 && (
                <div className={`absolute left-[50%] top-4 w-full h-0.5 -z-0 ${i < currentIndex && !isRejected ? 'bg-blue-400' : 'bg-gray-100'}`} style={{ width: 'calc(100% + 20px)' }}></div>
              )}
            </div>
          ))}
          <div className="flex flex-col items-center ml-2">
            <div className={`w-9 h-9 flex items-center justify-center rounded-full text-xl border-2 font-black transition-all duration-500 ${
              isFinished ? 'bg-green-100 border-green-500 text-green-600 shadow-lg shadow-green-200' : 
              isRejected ? 'bg-red-100 border-red-500 text-red-600 shadow-lg shadow-red-200 animate-pulse' : 
              'bg-white border-gray-200 text-gray-300'
            }`}>
              {isFinished ? '✅' : isRejected ? '×' : '⌛'}
            </div>
            <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '报销失败' : '最终状态'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-2 p-2 bg-red-50 border border-red-100 rounded-xl text-[10px] text-red-700 font-bold flex items-start gap-2">
            <span className="text-sm">⚠️</span>
            <span>退单原因：{reason}</span>
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-200 scale-in-center">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-4xl shadow-xl shadow-blue-200">📋</div>
            <h1 className="text-3xl font-black mt-6 tracking-tight">{user ? '修改个人信息' : '报销身份认证'}</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">姓名</label>
              <input name="name" defaultValue={user?.name} placeholder="请输入姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">学号/工号</label>
              <input name="studentId" defaultValue={user?.studentId} placeholder="请输入学号/工号" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">指导老师</label>
              <input name="supervisor" defaultValue={user?.supervisor} placeholder="请输入导师姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label>
              <input name="phone" defaultValue={user?.phone} placeholder="请输入联系方式" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="flex gap-3 pt-4">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg hover:bg-slate-200 transition-colors">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">保存并进入</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100 selection:text-blue-600">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full shadow-2xl scale-in-center border border-slate-100">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6">🛡️</div>
            <h2 className="text-2xl font-black mb-4 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed text-slate-600">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 active:scale-95 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && (
              <div className="mt-8 flex justify-center gap-2">
                <div className="w-8 h-1.5 bg-blue-600 rounded-full"></div>
                <div className="w-8 h-1.5 bg-slate-100 rounded-full"></div>
              </div>
            )}
          </div>
        </div>
      )}

      <header className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2.5 rounded-2xl text-xl font-black shadow-blue-200 shadow-xl">AI</div>
          <div className="flex flex-col">
            <h1 className="text-xl font-black tracking-tighter leading-none">江南报销助手</h1>
            <span className="text-[10px] font-bold text-blue-500 tracking-widest uppercase">Smart Reimbursement</span>
          </div>
          <button 
            onClick={handleEditProfile}
            className="hidden md:flex items-center text-[11px] text-slate-500 gap-3 ml-6 bg-slate-50 hover:bg-white hover:shadow-md px-4 py-2 rounded-2xl border border-slate-100 transition-all group"
          >
            <div className="flex flex-col items-start">
              <span>用户: <b className="text-slate-800 font-black">{user.name}</b></span>
              <span>学号: <b className="text-slate-800 font-black">{user.studentId}</b></span>
            </div>
            <span className="text-blue-500 font-black bg-blue-50 px-2 py-1 rounded-lg opacity-80 group-hover:opacity-100 transition-opacity">✎ 修改</span>
          </button>
        </div>
        <div className="flex gap-3 items-center">
          <button 
            onClick={handleShare}
            className="bg-blue-50 text-blue-600 px-5 py-2.5 rounded-2xl text-[11px] font-black border border-blue-100 shadow-sm hover:bg-blue-100 transition-all flex items-center gap-2"
          >
            <span className="text-lg leading-none">🔗</span>
            {shareText}
          </button>
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-5 py-2.5 rounded-2xl text-[11px] font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-xl' : 'text-slate-600 border-slate-200 hover:border-blue-400 hover:text-blue-600'
              }`}
            >
              {isAdminMode ? '退出管理' : '进入后台'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-xl hover:bg-slate-900 transition-colors">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-green-100 shadow-xl hover:bg-green-700 transition-colors">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-700">
            <section className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-8">
                <div className="flex flex-col">
                  <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest">Smart Scanning</h2>
                  <p className="text-xl font-black text-slate-800">发票识别区</p>
                </div>
                <label className="flex items-center gap-3 px-5 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-all group">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-5 h-5 rounded-lg text-blue-600 focus:ring-0 cursor-pointer" />
                  <span className={`text-lg font-black transition-colors ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>

              <div 
                onClick={() => fileInputRef.current?.click()} 
                className="border-4 border-dashed border-slate-100 rounded-[2rem] p-12 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/50 transition-all group relative overflow-hidden"
              >
                <div className="absolute inset-0 bg-blue-50 opacity-0 group-hover:opacity-10 transition-opacity"></div>
                <span className="text-7xl block mb-6 group-hover:scale-110 group-hover:-rotate-6 transition-transform duration-500">📸</span>
                <p className="text-xl font-black text-slate-800">点击上传发票</p>
                <p className="text-sm text-slate-400 mt-2">支持 PDF 或 图片，系统将自动极速提取</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-10 space-y-5">
                {files.length === 0 && (
                  <div className="py-12 border-2 border-dashed border-slate-50 rounded-3xl text-center text-slate-300 font-bold text-sm">
                    暂未上传任何文件
                  </div>
                )}
                {files.map(item => (
                  <div key={item.id} className={`p-6 rounded-[2rem] border-2 flex gap-5 transition-all animate-in slide-in-from-bottom-4 duration-300 ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-2xl hover:border-blue-100'
                  }`}>
                    <div className="relative">
                      {item.file.type.includes('image') ? (
                        <img src={item.previewUrl} className="w-28 h-28 object-cover rounded-3xl shadow-md border-2 border-white bg-slate-50" alt="preview" />
                      ) : (
                        <div className="w-28 h-28 bg-red-50 rounded-3xl flex flex-col items-center justify-center shadow-md border-2 border-white">
                          <span className="text-4xl">📄</span>
                          <span className="text-[10px] font-black text-red-500 mt-1 uppercase">PDF Document</span>
                        </div>
                      )}
                      {item.isBuyerValid === false && (
                        <div className="absolute -top-2 -right-2 bg-red-500 text-white w-7 h-7 rounded-full flex items-center justify-center text-xs font-black shadow-lg border-2 border-white" title="抬头有误">!</div>
                      )}
                    </div>
                    <div className="flex-grow min-w-0 flex flex-col justify-center">
                      {item.status === 'processing' ? (
                        <div className="space-y-3">
                          <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                            <div className="bg-blue-600 h-full animate-progress-indefinite shadow-sm"></div>
                          </div>
                          <p className="text-[11px] font-black text-blue-500 uppercase tracking-widest">AI Deep Parsing...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <div className="flex justify-between items-start">
                              <span className="text-2xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                              <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full uppercase tracking-tighter">{item.extractedData.category}</span>
                            </div>
                            <p className="text-[10px] font-bold text-slate-400 mt-1 truncate">No. {item.extractedData.invoiceNumber}</p>
                          </div>
                          <div className="mt-4 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">提交报销单</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-4 py-3 bg-slate-100 text-slate-400 rounded-2xl text-[11px] font-black hover:bg-slate-200 transition-colors">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center justify-center h-full">
                          <span className="text-2xl mb-1">⚠️</span>
                          <p className="text-[11px] font-black text-red-500 uppercase">{item.error || '识别异常'}</p>
                          <button onClick={() => handleRemoveFile(item.id)} className="mt-2 text-[10px] font-bold text-slate-400 underline">移除重试</button>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-700 animate-in fade-in slide-in-from-right duration-700`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[85vh] overflow-hidden relative border-slate-100">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/30 backdrop-blur-sm">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
                <p className="text-slate-400 text-xs mt-1">
                  {isAdminMode ? "管理员模式：点击状态快速流转发票进度" : "点击发票卡片查看详细信息与审批原因"}
                </p>
              </div>
              <div className="flex items-center gap-4">
                 <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black text-slate-300 uppercase">Records Found</span>
                    <span className="text-xl font-black text-blue-600">{(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length}</span>
                 </div>
              </div>
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' : 'space-y-6'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-[50vh] opacity-30 grayscale">
                  <span className="text-9xl mb-4">📥</span>
                  <p className="text-2xl font-black text-slate-400">尚无报销记录</p>
                </div>
              )}
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-[2rem] p-8 transition-all group hover:shadow-2xl relative overflow-hidden flex flex-col ${r.status === 'rejected' ? 'border-red-100 bg-red-50/10 shadow-red-50/20' : 'border-slate-50'}`}>
                  {/* 退单状态水印图标 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-20 rotate-12">
                      <span className="text-9xl font-black text-red-500 select-none">×</span>
                    </div>
                  )}
                  {r.status === 'success' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-10">
                      <span className="text-9xl font-black text-green-500 select-none">✓</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-6 relative z-10">
                    <div className="flex gap-5 items-center">
                      <div className="bg-slate-50 w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-inner group-hover:bg-blue-50 transition-colors">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800 tracking-tight">{r.category}</h3>
                        <p className="text-[10px] font-mono font-bold text-slate-400 mt-0.5">ID: {r.invoiceNumber}</p>
                        {isAdminMode && (
                          <div className="mt-1 flex items-center gap-2">
                             <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                             <span className="text-[11px] font-black text-blue-600">{r.name} · {r.studentId}</span>
                          </div>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button 
                        onClick={() => toggleRecordPaidStatus(r.id)} 
                        className={`mt-2 px-4 py-1.5 rounded-xl text-[10px] font-black transition-all active:scale-95 shadow-sm ${
                          r.isPaid ? 'bg-blue-500 text-white shadow-blue-100' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                        }`}
                      >
                        {r.isPaid ? '已付发票' : '待付发票'}
                      </button>
                    </div>
                  </div>

                  <div className="relative z-10 flex-grow">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-6 pt-6 border-t border-slate-100 flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${
                          r.status === s ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-slate-50 text-slate-500 hover:bg-slate-200'
                        }`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-4 py-1.5 flex items-center gap-1.5 text-[9px] font-black uppercase rounded-xl transition-all ${
                          r.status === 'rejected' ? 'bg-red-600 text-white shadow-lg shadow-red-100' : 'bg-red-50 text-red-500 hover:bg-red-100'
                        }`}
                      >
                        <span>退单</span>
                        <span className="text-base font-black leading-none">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto p-12 text-center text-slate-300 font-black text-[10px] uppercase tracking-[0.2em]">
        Jiangnan University · Smart Financial AI Assistant · Built with Gemini
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }

        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 20px; border: 2px solid white; }
        ::-webkit-scrollbar-thumb:hover { background: #CBD5E1; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [shareText, setShareText] = useState('分享助手');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isPaid, setIsPaid] = useState(false);

  // 问卷工作流状态
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const savedRecords = localStorage.getItem('invoice_records');

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      setIsLoginView(true);
    }

    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  useEffect(() => {
    localStorage.setItem('invoice_records', JSON.stringify(records));
  }, [records]);

  const isUserAdmin = user?.studentId === SUPER_ADMIN_ID;

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
  };

  const handleEditProfile = () => {
    setIsLoginView(true);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
      setShareText('已复制链接！');
      setTimeout(() => setShareText('分享助手'), 2000);
    }).catch(err => {
      alert("复制失败，请手动复制地址栏链接");
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const selectedFiles = Array.from(fileList) as File[];
    const newFiles: ProcessingFile[] = selectedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending' as const
    }));
    setFiles(prev => [...prev, ...newFiles]);
    newFiles.forEach(processFile);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      console.error(err);
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === id);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== id);
    });
  };

  const handleAddRecord = (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`发票抬头错误！购买方必须是：${SCHOOL_NAME}\n识别到的购买方：${extracted.buyerName}`);
    if (isDuplicate) return alert(`发票号码 ${extracted.invoiceNumber} 已存在，不可重复报销！`);
    if (!user) return;

    const newId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = {
      ...extracted,
      ...user,
      isPaid,
      id: newId,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box'
    };

    setRecords(prev => [newRecord, ...prev]);
    setFiles(prev => {
      const fileToRemove = prev.find(f => f.id === fileId);
      if (fileToRemove) URL.revokeObjectURL(fileToRemove.previewUrl);
      return prev.filter(f => f.id !== fileId);
    });

    setActiveWorkflowId(newId);
    if (isPaid) {
      setSurveyQueue(['double_signature', 'payment_record']);
    } else {
      setSurveyQueue(['double_signature']);
    }
  };

  const toggleRecordPaidStatus = (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    if (record.paidEditCount >= 1 && !isAdminMode) {
      alert("支付状态提交后仅可修改一次。");
      return;
    }

    const becomingPaid = !record.isPaid;
    if (becomingPaid) {
      setActiveWorkflowId(recordId);
      setSurveyQueue(['payment_record']);
    }

    setRecords(prev => prev.map(r => 
      r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r
    ));
  };

  const handleSurveyAnswer = (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { 
      ...r, 
      surveyAnswers: { 
        ...(r.surveyAnswers || {}),
        ...(currentSurvey === 'payment_record' ? { hasPaymentRecord: answer } : { hasDoubleSignature: answer })
      } 
    } : r));

    const nextQueue = surveyQueue.slice(1);
    setSurveyQueue(nextQueue);
    if (nextQueue.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const adminUpdateStatus = (id: string, status: ReimbursementStatus, reason?: string) => {
    setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
  };

  const exportData = (all: boolean = false) => {
    const targetRecords = all ? records : records.filter(r => r.studentId === user?.studentId);
    if (targetRecords.length === 0) return;
    const headers = ['发票号', '金额', '分类', '提交人', '学号', '电话', '导师', '状态', '老师签字', '支付记录', '当前进度', '退单原因'];
    const rows = targetRecords.map(r => [
      r.invoiceNumber, r.amount, r.category, r.name, r.studentId, r.phone, r.supervisor,
      r.isPaid ? '已付' : '待付',
      r.surveyAnswers?.hasDoubleSignature === undefined ? '-' : (r.surveyAnswers.hasDoubleSignature ? '是' : '否'),
      r.surveyAnswers?.hasPaymentRecord === undefined ? '-' : (r.surveyAnswers.hasPaymentRecord ? '是' : '否'),
      r.status, r.rejectionReason || ''
    ]);
    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${all ? '全部' : '个人'}报销清单_${Date.now()}.csv`;
    link.click();
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isFinished = status === 'success';
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-3 bg-gray-50 rounded-2xl border border-slate-100 shadow-inner">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative group">
              <div className={`w-9 h-9 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all duration-300 ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-md scale-110' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
              {i < steps.length - 1 && (
                <div className={`absolute left-[50%] top-4 w-full h-0.5 -z-0 ${i < currentIndex && !isRejected ? 'bg-blue-400' : 'bg-gray-100'}`} style={{ width: 'calc(100% + 20px)' }}></div>
              )}
            </div>
          ))}
          <div className="flex flex-col items-center ml-2">
            <div className={`w-9 h-9 flex items-center justify-center rounded-full text-xl border-2 font-black transition-all duration-500 ${
              isFinished ? 'bg-green-100 border-green-500 text-green-600 shadow-lg shadow-green-200' : 
              isRejected ? 'bg-red-100 border-red-500 text-red-600 shadow-lg shadow-red-200 animate-pulse' : 
              'bg-white border-gray-200 text-gray-300'
            }`}>
              {isFinished ? '✅' : isRejected ? '×' : '⌛'}
            </div>
            <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${isFinished ? 'text-green-600' : isRejected ? 'text-red-600' : 'text-gray-400'}`}>
              {isFinished ? '报销成功' : isRejected ? '报销失败' : '最终状态'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-2 p-2 bg-red-50 border border-red-100 rounded-xl text-[10px] text-red-700 font-bold flex items-start gap-2">
            <span className="text-sm">⚠️</span>
            <span>退单原因：{reason}</span>
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-200 scale-in-center">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-4xl shadow-xl shadow-blue-200">📋</div>
            <h1 className="text-3xl font-black mt-6 tracking-tight">{user ? '修改个人信息' : '报销身份认证'}</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">姓名</label>
              <input name="name" defaultValue={user?.name} placeholder="请输入姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">学号/工号</label>
              <input name="studentId" defaultValue={user?.studentId} placeholder="请输入学号/工号" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">指导老师</label>
              <input name="supervisor" defaultValue={user?.supervisor} placeholder="请输入导师姓名" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label>
              <input name="phone" defaultValue={user?.phone} placeholder="请输入联系方式" className="w-full border-2 p-4 rounded-2xl outline-none focus:border-blue-500 transition-all bg-slate-50 focus:bg-white" required />
            </div>
            <div className="flex gap-3 pt-4">
               {user && <button type="button" onClick={() => setIsLoginView(false)} className="flex-1 bg-slate-100 text-slate-500 p-4 rounded-2xl font-black text-lg hover:bg-slate-200 transition-colors">取消</button>}
               <button type="submit" className="flex-[2] bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">保存并进入</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100 selection:text-blue-600">
      {/* 动态合规性问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full shadow-2xl scale-in-center border border-slate-100">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6">🛡️</div>
            <h2 className="text-2xl font-black mb-4 text-center">合规性确认</h2>
            <div className="space-y-6">
              <p className="text-lg font-bold text-center leading-relaxed text-slate-600">
                {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
              </p>
              <div className="flex gap-4">
                <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all">是</button>
                <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black shadow-inner hover:bg-slate-200 active:scale-95 transition-all">否</button>
              </div>
            </div>
            {surveyQueue.length > 1 && (
              <div className="mt-8 flex justify-center gap-2">
                <div className="w-8 h-1.5 bg-blue-600 rounded-full"></div>
                <div className="w-8 h-1.5 bg-slate-100 rounded-full"></div>
              </div>
            )}
          </div>
        </div>
      )}

      <header className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2.5 rounded-2xl text-xl font-black shadow-blue-200 shadow-xl">AI</div>
          <div className="flex flex-col">
            <h1 className="text-xl font-black tracking-tighter leading-none">江南报销助手</h1>
            <span className="text-[10px] font-bold text-blue-500 tracking-widest uppercase">Smart Reimbursement</span>
          </div>
          <button 
            onClick={handleEditProfile}
            className="hidden md:flex items-center text-[11px] text-slate-500 gap-3 ml-6 bg-slate-50 hover:bg-white hover:shadow-md px-4 py-2 rounded-2xl border border-slate-100 transition-all group"
          >
            <div className="flex flex-col items-start">
              <span>用户: <b className="text-slate-800 font-black">{user.name}</b></span>
              <span>学号: <b className="text-slate-800 font-black">{user.studentId}</b></span>
            </div>
            <span className="text-blue-500 font-black bg-blue-50 px-2 py-1 rounded-lg opacity-80 group-hover:opacity-100 transition-opacity">✎ 修改</span>
          </button>
        </div>
        <div className="flex gap-3 items-center">
          <button 
            onClick={handleShare}
            className="bg-blue-50 text-blue-600 px-5 py-2.5 rounded-2xl text-[11px] font-black border border-blue-100 shadow-sm hover:bg-blue-100 transition-all flex items-center gap-2"
          >
            <span className="text-lg leading-none">🔗</span>
            {shareText}
          </button>
          {isUserAdmin && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-5 py-2.5 rounded-2xl text-[11px] font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-red-100 shadow-xl' : 'text-slate-600 border-slate-200 hover:border-blue-400 hover:text-blue-600'
              }`}
            >
              {isAdminMode ? '退出管理' : '进入后台'}
            </button>
          )}
          {isAdminMode && <button onClick={() => exportData(true)} className="bg-slate-800 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-xl hover:bg-slate-900 transition-colors">全量导出</button>}
          <button onClick={() => exportData(false)} className="bg-green-600 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-green-100 shadow-xl hover:bg-green-700 transition-colors">我的导出</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in fade-in slide-in-from-left duration-700">
            <section className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-8">
                <div className="flex flex-col">
                  <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest">Smart Scanning</h2>
                  <p className="text-xl font-black text-slate-800">发票识别区</p>
                </div>
                <label className="flex items-center gap-3 px-5 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer select-none shadow-lg active:scale-95 transition-all group">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-5 h-5 rounded-lg text-blue-600 focus:ring-0 cursor-pointer" />
                  <span className={`text-lg font-black transition-colors ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>

              <div 
                onClick={() => fileInputRef.current?.click()} 
                className="border-4 border-dashed border-slate-100 rounded-[2rem] p-12 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/50 transition-all group relative overflow-hidden"
              >
                <div className="absolute inset-0 bg-blue-50 opacity-0 group-hover:opacity-10 transition-opacity"></div>
                <span className="text-7xl block mb-6 group-hover:scale-110 group-hover:-rotate-6 transition-transform duration-500">📸</span>
                <p className="text-xl font-black text-slate-800">点击上传发票</p>
                <p className="text-sm text-slate-400 mt-2">支持 PDF 或 图片，系统将自动极速提取</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={handleFileUpload} />
              </div>

              <div className="mt-10 space-y-5">
                {files.length === 0 && (
                  <div className="py-12 border-2 border-dashed border-slate-50 rounded-3xl text-center text-slate-300 font-bold text-sm">
                    暂未上传任何文件
                  </div>
                )}
                {files.map(item => (
                  <div key={item.id} className={`p-6 rounded-[2rem] border-2 flex gap-5 transition-all animate-in slide-in-from-bottom-4 duration-300 ${
                    item.isDuplicate ? 'bg-amber-50 border-amber-200' : 
                    item.isBuyerValid === false ? 'bg-red-50 border-red-200' : 
                    'bg-white border-slate-100 hover:shadow-2xl hover:border-blue-100'
                  }`}>
                    <div className="relative">
                      {item.file.type.includes('image') ? (
                        <img src={item.previewUrl} className="w-28 h-28 object-cover rounded-3xl shadow-md border-2 border-white bg-slate-50" alt="preview" />
                      ) : (
                        <div className="w-28 h-28 bg-red-50 rounded-3xl flex flex-col items-center justify-center shadow-md border-2 border-white">
                          <span className="text-4xl">📄</span>
                          <span className="text-[10px] font-black text-red-500 mt-1 uppercase">PDF Document</span>
                        </div>
                      )}
                      {item.isBuyerValid === false && (
                        <div className="absolute -top-2 -right-2 bg-red-500 text-white w-7 h-7 rounded-full flex items-center justify-center text-xs font-black shadow-lg border-2 border-white" title="抬头有误">!</div>
                      )}
                    </div>
                    <div className="flex-grow min-w-0 flex flex-col justify-center">
                      {item.status === 'processing' ? (
                        <div className="space-y-3">
                          <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                            <div className="bg-blue-600 h-full animate-progress-indefinite shadow-sm"></div>
                          </div>
                          <p className="text-[11px] font-black text-blue-500 uppercase tracking-widest">AI Deep Parsing...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div>
                            <div className="flex justify-between items-start">
                              <span className="text-2xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                              <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full uppercase tracking-tighter">{item.extractedData.category}</span>
                            </div>
                            <p className="text-[10px] font-bold text-slate-400 mt-1 truncate">No. {item.extractedData.invoiceNumber}</p>
                          </div>
                          <div className="mt-4 flex gap-2">
                            <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="flex-grow py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all">提交报销单</button>
                            <button onClick={() => handleRemoveFile(item.id)} className="px-4 py-3 bg-slate-100 text-slate-400 rounded-2xl text-[11px] font-black hover:bg-slate-200 transition-colors">删除</button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center justify-center h-full">
                          <span className="text-2xl mb-1">⚠️</span>
                          <p className="text-[11px] font-black text-red-500 uppercase">{item.error || '识别异常'}</p>
                          <button onClick={() => handleRemoveFile(item.id)} className="mt-2 text-[10px] font-bold text-slate-400 underline">移除重试</button>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 transition-all duration-700 animate-in fade-in slide-in-from-right duration-700`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[85vh] overflow-hidden relative border-slate-100">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/30 backdrop-blur-sm">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-800">{isAdminMode ? "全部用户报销单" : "我的报销流水"}</h2>
                <p className="text-slate-400 text-xs mt-1">
                  {isAdminMode ? "管理员模式：点击状态快速流转发票进度" : "点击发票卡片查看详细信息与审批原因"}
                </p>
              </div>
              <div className="flex items-center gap-4">
                 <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black text-slate-300 uppercase">Records Found</span>
                    <span className="text-xl font-black text-blue-600">{(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length}</span>
                 </div>
              </div>
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' : 'space-y-6'}`}>
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-[50vh] opacity-30 grayscale">
                  <span className="text-9xl mb-4">📥</span>
                  <p className="text-2xl font-black text-slate-400">尚无报销记录</p>
                </div>
              )}
              {(isAdminMode ? records : records.filter(r => r.studentId === user.studentId)).map(r => (
                <div key={r.id} className={`bg-white border-2 rounded-[2rem] p-8 transition-all group hover:shadow-2xl relative overflow-hidden flex flex-col ${r.status === 'rejected' ? 'border-red-100 bg-red-50/10 shadow-red-50/20' : 'border-slate-50'}`}>
                  {/* 水印标识 */}
                  {r.status === 'rejected' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-20 rotate-12">
                      <span className="text-9xl font-black text-red-500 select-none">×</span>
                    </div>
                  )}
                  {r.status === 'success' && (
                    <div className="absolute top-6 right-6 z-0 pointer-events-none opacity-10">
                      <span className="text-9xl font-black text-green-500 select-none">✓</span>
                    </div>
                  )}

                  <div className="flex justify-between items-start mb-6 relative z-10">
                    <div className="flex gap-5 items-center">
                      <div className="bg-slate-50 w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-inner group-hover:bg-blue-50 transition-colors">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800 tracking-tight">{r.category}</h3>
                        <p className="text-[10px] font-mono font-bold text-slate-400 mt-0.5">ID: {r.invoiceNumber}</p>
                        {isAdminMode && (
                          <div className="mt-1 flex items-center gap-2">
                             <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                             <span className="text-[11px] font-black text-blue-600">{r.name} · {r.studentId}</span>
                          </div>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button 
                        onClick={() => toggleRecordPaidStatus(r.id)} 
                        className={`mt-2 px-4 py-1.5 rounded-xl text-[10px] font-black transition-all active:scale-95 shadow-sm ${
                          r.isPaid ? 'bg-blue-500 text-white shadow-blue-100' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                        }`}
                      >
                        {r.isPaid ? '已付发票' : '待付发票'}
                      </button>
                    </div>
                  </div>

                  <div className="relative z-10 flex-grow">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-6 pt-6 border-t border-slate-100 flex flex-wrap gap-2 relative z-10">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${
                          r.status === s ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-slate-50 text-slate-500 hover:bg-slate-200'
                        }`}>{s}</button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className={`px-4 py-1.5 flex items-center gap-1.5 text-[9px] font-black uppercase rounded-xl transition-all ${
                          r.status === 'rejected' ? 'bg-red-600 text-white shadow-lg shadow-red-100' : 'bg-red-50 text-red-500 hover:bg-red-100'
                        }`}
                      >
                        <span>退单</span>
                        <span className="text-base font-black leading-none">×</span>
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto p-12 text-center text-slate-300 font-black text-[10px] uppercase tracking-[0.2em]">
        Jiangnan University · Smart Financial AI Assistant · Built with Gemini
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }

        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 20px; border: 2px solid white; }
        ::-webkit-scrollbar-thumb:hover { background: #CBD5E1; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

// ==========================================
// 请在这里替换为您在 Supabase 后台获取的凭证
// ==========================================
const SUPABASE_URL = 'YOUR_SUPABASE_PROJECT_URL'; 
const SUPABASE_ANON_KEY = 'YOUR_SUPABASE_ANON_KEY';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [shareText, setShareText] = useState('分享助手');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // 初始化：检查登录并从云端同步数据
  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchCloudRecords(parsedUser.studentId);
    } else {
      setIsLoginView(true);
    }
  }, []);

  // 当切换管理员模式时，重新获取数据
  useEffect(() => {
    if (user) {
      fetchCloudRecords(user.studentId);
    }
  }, [isAdminMode]);

  const fetchCloudRecords = async (studentId: string) => {
    setIsLoading(true);
    try {
      let query = supabase.from('reimbursements').select('*').order('timestamp', { ascending: false });

      // 如果不是管理员模式，只查自己的
      if (!(isAdminMode && studentId === SUPER_ADMIN_ID)) {
        query = query.eq('studentId', studentId);
      }

      const { data, error } = await query;
      if (error) throw error;
      setRecords(data || []);
    } catch (err) {
      console.error('云端数据获取失败:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
    fetchCloudRecords(profile.studentId);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
      setShareText('已复制链接！');
      setTimeout(() => setShareText('分享助手'), 2000);
    });
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleAddRecord = async (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert("发票抬头错误！");
    if (isDuplicate) return alert("发票号码已存在，不可重复报销！");
    if (!user) return;

    setIsLoading(true);
    const newRecord: any = {
      ...extracted,
      ...user,
      isPaid,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box',
      surveyAnswers: {}
    };

    try {
      // 插入到 Supabase 云端
      const { data, error } = await supabase.from('reimbursements').insert([newRecord]).select();
      if (error) throw error;

      const savedRecord = data[0];
      setRecords(prev => [savedRecord, ...prev]);
      setFiles(prev => prev.filter(f => f.id !== fileId));

      setActiveWorkflowId(savedRecord.id);
      setSurveyQueue(isPaid ? ['double_signature', 'payment_record'] : ['double_signature']);
    } catch (err) {
      alert('上传云端失败，请检查网络');
    } finally {
      setIsLoading(false);
    }
  };

  const adminUpdateStatus = async (id: string, status: ReimbursementStatus, reason?: string) => {
    try {
      const { error } = await supabase.from('reimbursements')
        .update({ status, rejectionReason: reason || null })
        .eq('id', id);

      if (error) throw error;
      setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
    } catch (err) {
      alert('更新失败');
    }
  };

  const toggleRecordPaidStatus = async (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;

    const becomingPaid = !record.isPaid;
    try {
      const { error } = await supabase.from('reimbursements')
        .update({ isPaid: becomingPaid, paidEditCount: record.paidEditCount + 1 })
        .eq('id', recordId);

      if (error) throw error;

      if (becomingPaid) {
        setActiveWorkflowId(recordId);
        setSurveyQueue(['payment_record']);
      }
      setRecords(prev => prev.map(r => r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r));
    } catch (err) {
      alert('同步失败');
    }
  };

  const handleSurveyAnswer = async (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    const key = currentSurvey === 'payment_record' ? 'hasPaymentRecord' : 'hasDoubleSignature';

    const record = records.find(r => r.id === activeWorkflowId);
    const newAnswers = { ...(record?.surveyAnswers || {}), [key]: answer };

    try {
      await supabase.from('reimbursements').update({ surveyAnswers: newAnswers }).eq('id', activeWorkflowId);
      setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { ...r, surveyAnswers: newAnswers } : r));

      const nextQueue = surveyQueue.slice(1);
      setSurveyQueue(nextQueue);
      if (nextQueue.length === 0) setActiveWorkflowId(null);
    } catch (err) {
      alert('同步失败');
    }
  };

  // 渲染逻辑保持一致，仅增加 Loading 状态显示
  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-3 bg-gray-50 rounded-2xl border border-slate-100 shadow-inner">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative group">
              <div className={`w-9 h-9 flex items-center justify-center rounded-full text-lg z-10 border-2 transition-all duration-300 ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-md scale-110' : 'bg-white border-gray-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-gray-400'}`}>{s.label}</span>
              {i < steps.length - 1 && (
                <div className={`absolute left-[50%] top-4 w-full h-0.5 -z-0 ${i < currentIndex && !isRejected ? 'bg-blue-400' : 'bg-gray-100'}`} style={{ width: 'calc(100% + 20px)' }}></div>
              )}
            </div>
          ))}
          <div className="flex flex-col items-center ml-2">
            <div className={`w-9 h-9 flex items-center justify-center rounded-full text-xl border-2 font-black ${
              status === 'success' ? 'bg-green-100 border-green-500 text-green-600 shadow-lg' : 
              status === 'rejected' ? 'bg-red-100 border-red-500 text-red-600 shadow-lg' : 'bg-white border-gray-200 text-gray-300'
            }`}>
              {status === 'success' ? '✅' : status === 'rejected' ? '×' : '⌛'}
            </div>
            <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest ${status === 'success' ? 'text-green-600' : status === 'rejected' ? 'text-red-600' : 'text-gray-400'}`}>
              {status === 'success' ? '已成功' : status === 'rejected' ? '已退单' : '最终状态'}
            </span>
          </div>
        </div>
        {isRejected && reason && <div className="mt-2 p-2 bg-red-50 border border-red-100 rounded-xl text-[10px] text-red-700 font-bold">⚠️ 原因：{reason}</div>}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-200 scale-in-center">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-4xl shadow-xl shadow-blue-200">📋</div>
            <h1 className="text-3xl font-black mt-6 tracking-tight">报销身份认证</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">姓名</label><input name="name" placeholder="请输入姓名" className="w-full border-2 p-4 rounded-2xl bg-slate-50" required /></div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">学号</label><input name="studentId" placeholder="请输入学号" className="w-full border-2 p-4 rounded-2xl bg-slate-50" required /></div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">指导老师</label><input name="supervisor" placeholder="导师姓名" className="w-full border-2 p-4 rounded-2xl bg-slate-50" required /></div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label><input name="phone" placeholder="手机号" className="w-full border-2 p-4 rounded-2xl bg-slate-50" required /></div>
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg hover:bg-blue-700 transition-all">确认进入</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans">
      {/* 问卷弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full shadow-2xl scale-in-center">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6">🛡️</div>
            <h2 className="text-2xl font-black mb-4 text-center">合规确认</h2>
            <p className="text-lg font-bold text-center text-slate-600 mb-8">
              {surveyQueue[0] === 'double_signature' ? "发票是否由2名以上的老师签字？" : "已付发票是否附上支付记录？"}
            </p>
            <div className="flex gap-4">
              <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black">是</button>
              <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black">否</button>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2.5 rounded-2xl text-xl font-black">AI</div>
          <h1 className="text-xl font-black tracking-tighter">江南报销助手 <span className="text-blue-500 text-xs ml-2">CLOUD</span></h1>
        </div>
        <div className="flex gap-3">
          <button onClick={handleShare} className="bg-blue-50 text-blue-600 px-5 py-2.5 rounded-2xl text-[11px] font-black border border-blue-100 hover:bg-blue-100 transition-all">🔗 {shareText}</button>
          {user.studentId === SUPER_ADMIN_ID && (
            <button onClick={() => setIsAdminMode(!isAdminMode)} className={`px-5 py-2.5 rounded-2xl text-[11px] font-black transition-all ${isAdminMode ? 'bg-red-600 text-white shadow-xl' : 'text-slate-600 border-slate-200 hover:border-blue-400'}`}>
              {isAdminMode ? '管理模式中...' : '后台入口'}
            </button>
          )}
          <button onClick={() => fetchCloudRecords(user.studentId)} className="bg-slate-100 text-slate-600 px-5 py-2.5 rounded-2xl text-[11px] font-black hover:bg-slate-200">刷新数据</button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-2xl">
              <div className="flex justify-between items-center mb-8">
                <p className="text-xl font-black text-slate-800">发票识别区</p>
                <label className="flex items-center gap-3 px-5 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer shadow-lg active:scale-95 transition-all">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-5 h-5 rounded-lg text-blue-600" />
                  <span className={`text-lg font-black ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>
              <div onClick={() => fileInputRef.current?.click()} className="border-4 border-dashed border-slate-100 rounded-[2rem] p-12 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/50 transition-all group">
                <span className="text-7xl block mb-6 group-hover:scale-110 transition-transform">📸</span>
                <p className="text-xl font-black">点击上传发票</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={(e) => {
                  const files = Array.from(e.target.files || []) as File[];
                  const newFiles = files.map(file => ({ id: Math.random().toString(36).substr(2, 9), file, previewUrl: URL.createObjectURL(file), status: 'pending' as const }));
                  setFiles(prev => [...prev, ...newFiles]);
                  newFiles.forEach(processFile);
                }} />
              </div>
              <div className="mt-10 space-y-5">
                {files.map(item => (
                  <div key={item.id} className="p-6 rounded-[2rem] border-2 bg-white flex gap-5 animate-in slide-in-from-bottom">
                    <img src={item.previewUrl} className="w-28 h-28 object-cover rounded-3xl" alt="preview" />
                    <div className="flex-grow">
                      {item.status === 'processing' ? <div className="h-full flex items-center"><div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-progress-indefinite"></div></div></div> : 
                       item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <span className="text-2xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                          <button onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} className="w-full py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg">提交到云端汇总</button>
                        </div>
                      ) : <div className="text-red-500 font-black">识别异常</div>}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[80vh] overflow-hidden relative">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/50">
              <h2 className="text-2xl font-black text-slate-800">{isAdminMode ? "全班汇总数据(仅管理员可见)" : "我的报销流水"}</h2>
              {isLoading && <span className="text-blue-500 font-black text-xs animate-pulse">正在同步云端...</span>}
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 gap-8' : 'space-y-6'}`}>
              {records.map(r => (
                <div key={r.id} className="bg-white border-2 rounded-[2rem] p-8 hover:shadow-2xl transition-all relative">
                  <div className="flex justify-between items-start mb-6">
                    <div className="flex gap-4">
                      <div className="bg-slate-50 w-14 h-14 rounded-2xl flex items-center justify-center text-2xl">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800">{r.category}</h3>
                        <p className="text-[10px] font-bold text-slate-400">单号: {r.invoiceNumber}</p>
                        {isAdminMode && <p className="text-[10px] font-black text-blue-600 mt-1">{r.name} · {r.studentId}</p>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <span className={`text-[9px] font-black px-3 py-1 rounded-full ${r.isPaid ? 'bg-blue-500 text-white' : 'bg-slate-100 text-slate-400'}`}>{r.isPaid ? '已付' : '待付'}</span>
                    </div>
                  </div>
                  <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  {isAdminMode && (
                    <div className="mt-6 pt-6 border-t border-slate-50 flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button key={s} onClick={() => adminUpdateStatus(r.id, s)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black ${r.status === s ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-50 text-slate-500'}`}>{s}</button>
                      ))}
                      <button onClick={() => {
                        const reason = prompt("退单原因：");
                        if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                      }} className="px-3 py-1.5 bg-red-50 text-red-500 text-[9px] font-black rounded-xl">退单</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="text-center p-12 text-slate-300 font-black text-[10px] uppercase tracking-widest">
        Jiangnan University · Cloud Database Powered · Built with Gemini
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

// ============================================================
// 🛠️ 配置区域：请将你在 Supabase 获取的凭证填入下方引号中
// ============================================================
const SUPABASE_URL = 'YOUR_SUPABASE_PROJECT_URL'; // 替换为 Project URL
const SUPABASE_ANON_KEY = 'YOUR_SUPABASE_ANON_KEY'; // 替换为 Anon Key (public)
// ============================================================

const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [shareText, setShareText] = useState('分享助手');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // 初始化：检查登录并从云端同步数据
  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchCloudRecords(parsedUser.studentId);
    } else {
      setIsLoginView(true);
    }
  }, []);

  // 监听管理员模式切换，自动拉取数据
  useEffect(() => {
    if (user) {
      fetchCloudRecords(user.studentId);
    }
  }, [isAdminMode]);

  const fetchCloudRecords = async (studentId: string) => {
    setIsLoading(true);
    try {
      let query = supabase.from('reimbursements').select('*').order('timestamp', { ascending: false });

      // 管理员视角拉取全量，普通学生仅拉取个人
      if (!(isAdminMode && studentId === SUPER_ADMIN_ID)) {
        query = query.eq('studentId', studentId);
      }

      const { data, error } = await query;
      if (error) throw error;
      setRecords(data || []);
    } catch (err) {
      console.error('Cloud Fetch Error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
    fetchCloudRecords(profile.studentId);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
      setShareText('已复制链接！');
      setTimeout(() => setShareText('分享助手'), 2000);
    });
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleAddRecord = async (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`抬头错误！请检查发票购买方是否为：${SCHOOL_NAME}`);
    if (isDuplicate) return alert("该发票已在系统中，请勿重复提交");
    if (!user) return;

    setIsLoading(true);
    const newRecord = {
      ...extracted,
      ...user,
      isPaid,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box',
      surveyAnswers: {}
    };

    try {
      const { data, error } = await supabase.from('reimbursements').insert([newRecord]).select();
      if (error) throw error;

      const savedRecord = data[0];
      setRecords(prev => [savedRecord, ...prev]);
      setFiles(prev => prev.filter(f => f.id !== fileId));

      setActiveWorkflowId(savedRecord.id);
      setSurveyQueue(isPaid ? ['double_signature', 'payment_record'] : ['double_signature']);
    } catch (err) {
      alert('上传云端失败，请检查数据库配置或网络');
    } finally {
      setIsLoading(false);
    }
  };

  const adminUpdateStatus = async (id: string, status: ReimbursementStatus, reason?: string) => {
    try {
      const { error } = await supabase.from('reimbursements')
        .update({ status, rejectionReason: reason || null })
        .eq('id', id);

      if (error) throw error;
      setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
    } catch (err) {
      alert('更新失败');
    }
  };

  const toggleRecordPaidStatus = async (recordId: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;

    const becomingPaid = !record.isPaid;
    try {
      const { error } = await supabase.from('reimbursements')
        .update({ isPaid: becomingPaid, paidEditCount: record.paidEditCount + 1 })
        .eq('id', recordId);

      if (error) throw error;

      if (becomingPaid) {
        setActiveWorkflowId(recordId);
        setSurveyQueue(['payment_record']);
      }
      setRecords(prev => prev.map(r => r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r));
    } catch (err) {
      alert('状态同步失败');
    }
  };

  const handleSurveyAnswer = async (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const currentSurvey = surveyQueue[0];
    const key = currentSurvey === 'payment_record' ? 'hasPaymentRecord' : 'hasDoubleSignature';

    const record = records.find(r => r.id === activeWorkflowId);
    const newAnswers = { ...(record?.surveyAnswers || {}), [key]: answer };

    try {
      await supabase.from('reimbursements').update({ surveyAnswers: newAnswers }).eq('id', activeWorkflowId);
      setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { ...r, surveyAnswers: newAnswers } : r));

      const nextQueue = surveyQueue.slice(1);
      setSurveyQueue(nextQueue);
      if (nextQueue.length === 0) setActiveWorkflowId(null);
    } catch (err) {
      alert('问卷状态同步失败');
    }
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
    ];
    const currentIndex = steps.findIndex(s => s.key === status);
    const isRejected = status === 'rejected';

    return (
      <div className="flex flex-col gap-2 p-4 bg-slate-50 rounded-2xl border border-slate-100 shadow-inner">
        <div className="flex items-center justify-between px-2">
          {steps.map((s, i) => (
            <div key={s.key} className="flex flex-col items-center relative z-10">
              <div className={`w-10 h-10 flex items-center justify-center rounded-full text-lg border-2 transition-all ${
                i <= currentIndex && !isRejected ? 'bg-blue-100 border-blue-500 shadow-md' : 'bg-white border-slate-200 grayscale'
              }`}>
                {s.icon}
              </div>
              <span className={`text-[9px] mt-2 font-black uppercase tracking-widest ${i <= currentIndex && !isRejected ? 'text-blue-600' : 'text-slate-400'}`}>{s.label}</span>
              {i < steps.length - 1 && (
                <div className={`absolute left-[50%] top-5 w-[140%] h-0.5 -z-10 ${i < currentIndex && !isRejected ? 'bg-blue-400' : 'bg-slate-100'}`}></div>
              )}
            </div>
          ))}
          <div className="flex flex-col items-center ml-2">
            <div className={`w-10 h-10 flex items-center justify-center rounded-full text-xl border-2 font-black ${
              status === 'success' ? 'bg-green-100 border-green-500 text-green-600 shadow-lg' : 
              status === 'rejected' ? 'bg-red-100 border-red-500 text-red-600 shadow-lg' : 'bg-white border-slate-200 text-slate-300'
            }`}>
              {status === 'success' ? '✅' : status === 'rejected' ? '×' : '⌛'}
            </div>
            <span className={`text-[9px] mt-2 font-black uppercase tracking-widest ${status === 'success' ? 'text-green-600' : status === 'rejected' ? 'text-red-600' : 'text-slate-400'}`}>
              {status === 'success' ? '已成功' : status === 'rejected' ? '已退单' : '最终状态'}
            </span>
          </div>
        </div>
        {isRejected && reason && (
          <div className="mt-3 p-3 bg-red-50 border border-red-100 rounded-xl text-xs text-red-700 font-bold flex items-center gap-2">
            <span>⚠️ 退单理由：{reason}</span>
          </div>
        )}
      </div>
    );
  };

  if (isLoginView || !user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-200 scale-in-center">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-4xl shadow-xl shadow-blue-200">📋</div>
            <h1 className="text-3xl font-black mt-6 tracking-tight">报销身份认证</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">姓名</label><input name="name" placeholder="请输入真实姓名" className="w-full border-2 p-4 rounded-2xl bg-slate-50 focus:bg-white outline-none focus:border-blue-500 transition-all" required /></div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">学号</label><input name="studentId" placeholder="用于同步报销记录" className="w-full border-2 p-4 rounded-2xl bg-slate-50 focus:bg-white outline-none focus:border-blue-500 transition-all" required /></div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">指导老师</label><input name="supervisor" placeholder="请输入导师姓名" className="w-full border-2 p-4 rounded-2xl bg-slate-50 focus:bg-white outline-none focus:border-blue-500 transition-all" required /></div>
            <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label><input name="phone" placeholder="用于异常提醒" className="w-full border-2 p-4 rounded-2xl bg-slate-50 focus:bg-white outline-none focus:border-blue-500 transition-all" required /></div>
            <button type="submit" className="w-full bg-blue-600 text-white p-4 rounded-2xl font-black text-lg shadow-lg hover:bg-blue-700 active:scale-95 transition-all">确认进入</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] text-slate-900 font-sans selection:bg-blue-100 selection:text-blue-600">
      {/* 问卷确认弹窗 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-sm w-full shadow-2xl scale-in-center">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6">🛡️</div>
            <h2 className="text-2xl font-black mb-4 text-center">合规性自查</h2>
            <p className="text-lg font-bold text-center text-slate-600 mb-8 leading-relaxed">
              {surveyQueue[0] === 'double_signature' ? "发票背面是否已有 2 名及以上的老师签字？" : "已付发票是否已附上银行/支付宝支付流水？"}
            </p>
            <div className="flex gap-4">
              <button onClick={() => handleSurveyAnswer(true)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all">是</button>
              <button onClick={() => handleSurveyAnswer(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black hover:bg-slate-200 active:scale-95 transition-all">否</button>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-20 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 text-white p-2.5 rounded-2xl text-xl font-black shadow-xl shadow-blue-100">AI</div>
          <div className="flex flex-col">
            <h1 className="text-xl font-black tracking-tighter leading-none">江南报销助手</h1>
            <span className="text-blue-500 text-[9px] font-black uppercase tracking-widest mt-1">Cloud Sync Version</span>
          </div>
        </div>
        <div className="flex gap-3 items-center">
          <button onClick={handleShare} className="bg-blue-50 text-blue-600 px-5 py-2.5 rounded-2xl text-[11px] font-black border border-blue-100 hover:bg-blue-100 transition-all flex items-center gap-2">
            <span>🔗</span> {shareText}
          </button>
          {user.studentId === SUPER_ADMIN_ID && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)} 
              className={`px-5 py-2.5 rounded-2xl text-[11px] font-black border-2 transition-all ${
                isAdminMode ? 'bg-red-600 text-white border-red-600 shadow-xl' : 'text-slate-600 border-slate-200 hover:border-blue-400'
              }`}
            >
              {isAdminMode ? '🛑 退出管理' : '👨‍💻 管理入口'}
            </button>
          )}
          <button 
            onClick={() => fetchCloudRecords(user.studentId)} 
            className="bg-slate-800 text-white px-5 py-2.5 rounded-2xl text-[11px] font-black shadow-xl hover:bg-slate-900 active:scale-95 transition-all"
          >
            🔄 刷新云端
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {!isAdminMode && (
          <div className="lg:col-span-5 space-y-6 animate-in slide-in-from-left duration-500">
            <section className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
              <div className="flex justify-between items-center mb-8">
                <div className="flex flex-col">
                  <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Scanner</h2>
                  <p className="text-xl font-black text-slate-800">发票识别</p>
                </div>
                <label className="flex items-center gap-3 px-5 py-3 bg-blue-50 border-2 border-blue-100 rounded-2xl cursor-pointer shadow-lg active:scale-95 transition-all">
                  <input type="checkbox" checked={isPaid} onChange={e => setIsPaid(e.target.checked)} className="w-5 h-5 rounded-lg text-blue-600 cursor-pointer" />
                  <span className={`text-lg font-black transition-colors ${isPaid ? 'text-blue-700' : 'text-slate-300'}`}>已付发票</span>
                </label>
              </div>

              <div 
                onClick={() => fileInputRef.current?.click()} 
                className="border-4 border-dashed border-slate-50 rounded-[2rem] p-12 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/50 transition-all group"
              >
                <span className="text-7xl block mb-6 group-hover:scale-110 group-hover:-rotate-6 transition-transform">📸</span>
                <p className="text-xl font-black text-slate-800">点击/拖拽发票文件</p>
                <p className="text-xs text-slate-400 mt-2">支持单张或批量 PDF/图片上传</p>
                <input ref={fileInputRef} type="file" multiple accept="image/*,application/pdf" className="hidden" onChange={(e) => {
                  const files = Array.from(e.target.files || []) as File[];
                  const newFiles = files.map(file => ({ 
                    id: Math.random().toString(36).substr(2, 9), 
                    file, 
                    previewUrl: URL.createObjectURL(file), 
                    status: 'pending' as const 
                  }));
                  setFiles(prev => [...prev, ...newFiles]);
                  newFiles.forEach(processFile);
                }} />
              </div>

              <div className="mt-10 space-y-5">
                {files.map(item => (
                  <div key={item.id} className="p-6 rounded-[2rem] border-2 bg-white flex gap-5 animate-in slide-in-from-bottom border-slate-50 hover:border-blue-100 transition-all">
                    {item.file.type.includes('image') ? (
                       <img src={item.previewUrl} className="w-28 h-28 object-cover rounded-3xl shadow-md" alt="preview" />
                    ) : (
                       <div className="w-28 h-28 bg-red-50 rounded-3xl flex items-center justify-center text-4xl">📄</div>
                    )}
                    <div className="flex-grow flex flex-col justify-center">
                      {item.status === 'processing' ? (
                        <div className="space-y-3">
                          <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-progress-indefinite"></div></div>
                          <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest">AI Parsing...</p>
                        </div>
                      ) : item.status === 'completed' && item.extractedData ? (
                        <div className="flex flex-col h-full justify-between">
                          <div className="flex justify-between items-start">
                            <span className="text-2xl font-black text-slate-800">¥{item.extractedData.amount.toFixed(2)}</span>
                            <span className="text-[10px] font-black bg-slate-100 px-2 py-0.5 rounded-full uppercase">{item.extractedData.category}</span>
                          </div>
                          <button 
                            onClick={() => handleAddRecord(item.extractedData!, item.id, item.isBuyerValid || false, item.isDuplicate || false)} 
                            className="mt-4 py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all"
                          >
                            🚀 提交到云端汇总
                          </button>
                        </div>
                      ) : (
                        <div className="text-red-500 text-[10px] font-black uppercase">识别失败，请点击重试</div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 animate-in slide-in-from-right duration-500`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[85vh] overflow-hidden relative border-slate-100">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/50 backdrop-blur-md">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-800">
                  {isAdminMode ? "🗂️ 全班报销大盘" : "📉 我的报销流水"}
                </h2>
                <p className="text-xs text-slate-400 mt-1">数据已实时同步至 Supabase 云端数据库</p>
              </div>
              {isLoading && <span className="text-blue-600 font-black text-xs animate-pulse">☁️ 正在同步...</span>}
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' : 'space-y-6'}`}>
              {records.length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-[50vh] opacity-20">
                  <span className="text-9xl">📭</span>
                  <p className="text-xl font-black mt-4 uppercase">暂无记录</p>
                </div>
              )}
              {records.map(r => (
                <div key={r.id} className="bg-white border-2 border-slate-50 rounded-[2.5rem] p-8 hover:shadow-2xl transition-all relative group flex flex-col">
                  <div className="flex justify-between items-start mb-6">
                    <div className="flex gap-4">
                      <div className="bg-slate-50 w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-inner group-hover:bg-blue-50 transition-colors">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800 tracking-tight">{r.category}</h3>
                        <p className="text-[10px] font-mono text-slate-400">单号: {r.invoiceNumber}</p>
                        {isAdminMode && <p className="text-[10px] font-black text-blue-600 mt-2 bg-blue-50 px-2 py-0.5 rounded-lg inline-block">{r.name} · {r.studentId}</p>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button 
                        onClick={() => toggleRecordPaidStatus(r.id)}
                        className={`mt-2 px-3 py-1.5 rounded-xl text-[9px] font-black shadow-sm active:scale-95 transition-all ${
                          r.isPaid ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
                        }`}
                      >
                        {r.isPaid ? '已付' : '待付'}
                      </button>
                    </div>
                  </div>

                  <div className="flex-grow">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-8 pt-6 border-t border-slate-50 flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button 
                          key={s} 
                          onClick={() => adminUpdateStatus(r.id, s)} 
                          className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${
                            r.status === s ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                          }`}
                        >
                          {s}
                        </button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className="px-4 py-1.5 bg-red-600 text-white text-[9px] font-black rounded-xl shadow-lg hover:bg-red-700 active:scale-95 transition-all"
                      >
                        ❌ 退单
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="text-center p-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] animate-pulse">
        Jiangnan University · Cloud Database Powered · Built with Gemini 3
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 20px; border: 2px solid white; }
        ::-webkit-scrollbar-thumb:hover { background: #CBD5E1; }
      `}</style>
    </div>
  );
};

