                            className="mt-4 py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all"
                          >
                            🚀 提交到云端汇总
                          </button>
                        </div>
                      ) : (
                        <div className="text-red-500 text-[10px] font-black uppercase">识别失败，请点击重试</div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        <div className={`${isAdminMode ? 'lg:col-span-12' : 'lg:col-span-7'} space-y-6 animate-in slide-in-from-right duration-500`}>
          <div className="bg-white rounded-[2.5rem] border shadow-2xl flex flex-col min-h-[85vh] overflow-hidden relative border-slate-100">
            <div className="px-10 py-8 border-b flex justify-between items-center bg-slate-50/50 backdrop-blur-md">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black text-slate-800">
                  {isAdminMode ? "🗂️ 全班报销大盘" : "📉 我的报销流水"}
                </h2>
                <p className="text-xs text-slate-400 mt-1">数据已实时同步至 Supabase 云端数据库</p>
              </div>
              {isLoading && <span className="text-blue-600 font-black text-xs animate-pulse">☁️ 正在同步...</span>}
            </div>

            <div className={`flex-grow overflow-auto p-8 ${isAdminMode ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' : 'space-y-6'}`}>
              {records.length === 0 && (
                <div className="col-span-full flex flex-col items-center justify-center h-[50vh] opacity-20">
                  <span className="text-9xl">📭</span>
                  <p className="text-xl font-black mt-4 uppercase">暂无记录</p>
                </div>
              )}
              {records.map(r => (
                <div key={r.id} className="bg-white border-2 border-slate-50 rounded-[2.5rem] p-8 hover:shadow-2xl transition-all relative group flex flex-col">
                  <div className="flex justify-between items-start mb-6">
                    <div className="flex gap-4">
                      <div className="bg-slate-50 w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-inner group-hover:bg-blue-50 transition-colors">🧾</div>
                      <div>
                        <h3 className="text-lg font-black text-slate-800 tracking-tight">{r.category}</h3>
                        <p className="text-[10px] font-mono text-slate-400">单号: {r.invoiceNumber}</p>
                        {isAdminMode && <p className="text-[10px] font-black text-blue-600 mt-2 bg-blue-50 px-2 py-0.5 rounded-lg inline-block">{r.name} · {r.studentId}</p>}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-2xl font-black text-blue-600">¥{r.amount.toFixed(2)}</div>
                      <button 
                        onClick={() => toggleRecordPaidStatus(r.id)}
                        className={`mt-2 px-3 py-1.5 rounded-xl text-[9px] font-black shadow-sm active:scale-95 transition-all ${
                          r.isPaid ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
                        }`}
                      >
                        {r.isPaid ? '已付' : '待付'}
                      </button>
                    </div>
                  </div>

                  <div className="flex-grow">
                    <ProgressSteps status={r.status} reason={r.rejectionReason} />
                  </div>

                  {isAdminMode && (
                    <div className="mt-8 pt-6 border-t border-slate-50 flex flex-wrap gap-2">
                      {(['box', 'han', 'assistant', 'office', 'success'] as ReimbursementStatus[]).map(s => (
                        <button 
                          key={s} 
                          onClick={() => adminUpdateStatus(r.id, s)} 
                          className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${
                            r.status === s ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                          }`}
                        >
                          {s}
                        </button>
                      ))}
                      <button 
                        onClick={() => {
                          const reason = prompt("请输入退单原因：");
                          if(reason) adminUpdateStatus(r.id, 'rejected', reason);
                        }} 
                        className="px-4 py-1.5 bg-red-600 text-white text-[9px] font-black rounded-xl shadow-lg hover:bg-red-700 active:scale-95 transition-all"
                      >
                        ❌ 退单
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      <footer className="text-center p-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] animate-pulse">
        Jiangnan University · Cloud Database Powered · Built with Gemini 3
      </footer>

      <style>{`
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
        @keyframes scale-in-center { 0% { transform: scale(0.5); opacity: 0; } 100% { transform: scale(1); opacity: 1; } }
        @keyframes progress-indefinite { 0% { width: 0; margin-left: 0; } 50% { width: 40%; margin-left: 60%; } 100% { width: 0; margin-left: 100%; } }
        .animate-progress-indefinite { animation: progress-indefinite 1.5s infinite linear; }
        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 20px; border: 2px solid white; }
        ::-webkit-scrollbar-thumb:hover { background: #CBD5E1; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

// ============================================================
// 🛠️ 配置区域：填入你的 Supabase 凭证
// ============================================================
const SUPABASE_URL = 'https://csvymqgaoabenakyzzsk.supabase.co'; 
const SUPABASE_ANON_KEY = 'YOUR_SUPABASE_ANON_KEY'; // 请在此处填入你的 Anon Key (可以在 Supabase Project Settings > API 找到)
// ============================================================

/**
 * 严格校验 URL 格式。
 * 只有当 URL 是有效的 http/https 协议且不包含占位符时才返回有效 URL 字符串。
 */
const getValidUrl = (url: string) => {
  if (!url || url.includes('YOUR_SUPABASE_PROJECT_URL')) return null;
  try {
    const parsed = new URL(url.trim());
    return (parsed.protocol === 'http:' || parsed.protocol === 'https:') ? parsed.toString() : null;
  } catch {
    return null;
  }
};

const validUrl = getValidUrl(SUPABASE_URL);
const isKeySet = SUPABASE_ANON_KEY && !SUPABASE_ANON_KEY.includes('YOUR_SUPABASE_ANON_KEY');

const supabase = validUrl && isKeySet
  ? createClient(validUrl, SUPABASE_ANON_KEY)
  : null;

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

// Fix: Ensured the functional component returns a valid React element and is properly exported.
const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [shareText, setShareText] = useState('分享助手');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchCloudRecords(parsedUser.studentId);
    } else {
      setIsLoginView(true);
    }
  }, []);

  useEffect(() => {
    if (user) {
      fetchCloudRecords(user.studentId);
    }
  }, [isAdminMode]);

  const fetchCloudRecords = async (studentId: string) => {
    if (!supabase) {
      console.warn("Supabase 未配置或配置无效，跳过云端获取。");
      return;
    }
    setIsLoading(true);
    try {
      let query = supabase.from('reimbursements').select('*').order('timestamp', { ascending: false });
      if (!(isAdminMode && studentId === SUPER_ADMIN_ID)) {
        query = query.eq('studentId', studentId);
      }
      const { data, error } = await query;
      if (error) throw error;
      setRecords(data || []);
    } catch (err) {
      console.error('Cloud Fetch Error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("请补全必要信息");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
    fetchCloudRecords(profile.studentId);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(() => {
      setShareText('已复制链接！');
      setTimeout(() => setShareText('分享助手'), 2000);
    });
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) && 
                          data.buyerTaxId.trim().toUpperCase().includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber.trim().toUpperCase() === data.invoiceNumber.trim().toUpperCase());

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, 
        status: 'completed', 
        extractedData: data, 
        isBuyerValid, 
        isDuplicate 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error', error: '识别失败' } : f));
    }
  };

  const handleAddRecord = async (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`抬头错误！请检查发票购买方是否为：${SCHOOL_NAME}`);
    if (isDuplicate) return alert("该发票已在系统中，请勿重复提交");
    if (!user) return;
    if (!supabase) return alert("云端数据库尚未正确配置（Anon Key 缺失或无效）。请检查 App.tsx 顶部的设置。");

    setIsLoading(true);
    const newRecord = {
      ...extracted,
      ...user,
      isPaid,
      timestamp: Date.now(),
      paidEditCount: 0,
      status: 'box',
      surveyAnswers: {}
    };

    try {
      const { data, error } = await supabase.from('reimbursements').insert([newRecord]).select();
      if (error) throw error;
      const savedRecord = data[0];
      setRecords(prev => [savedRecord, ...prev]);
      setFiles(prev => prev.filter(f => f.id !== fileId));
      setActiveWorkflowId(savedRecord.id);
      setSurveyQueue(isPaid ? ['double_signature', 'payment_record'] : ['double_signature']);
    } catch (err) {
      alert('上传云端失败，请确认数据库中已创建名为 reimbursements 的表，且 RLS 权限已正确配置。');
    } finally {
      setIsLoading(false);
    }
  };

  const adminUpdateStatus = async (id: string, status: ReimbursementStatus, reason?: string) => {
    if (!supabase) return;
    try {
      const { error } = await supabase.from('reimbursements')
        .update({ status, rejectionReason: reason || null })
        .eq('id', id);
      if (error) throw error;
      setRecords(prev => prev.map(r => r.id === id ? { ...r, status, rejectionReason: reason } : r));
    } catch (err) {
      alert('状态更新失败');
    }
  };

  const toggleRecordPaidStatus = async (recordId: string) => {
    if (!supabase) return;
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    const becomingPaid = !record.isPaid;
    try {
      const { error } = await supabase.from('reimbursements')
        .update({ isPaid: becomingPaid, paidEditCount: record.paidEditCount + 1 })
        .eq('id', recordId);
      if (error) throw error;
      if (becomingPaid) {
        setActiveWorkflowId(recordId);
        setSurveyQueue(['payment_record']);
      }
      setRecords(prev => prev.map(r => r.id === recordId ? { ...r, isPaid: becomingPaid, paidEditCount: r.paidEditCount + 1 } : r));
    } catch (err) {
      alert('支付状态同步失败');
    }
  };

  const handleSurveyAnswer = async (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0 || !supabase) return;
    const currentSurvey = surveyQueue[0];
    const key = currentSurvey === 'payment_record' ? 'hasPaymentRecord' : 'hasDoubleSignature';
    const record = records.find(r => r.id === activeWorkflowId);
    const newAnswers = { ...(record?.surveyAnswers || {}), [key]: answer };
    try {
      await supabase.from('reimbursements').update({ surveyAnswers: newAnswers }).eq('id', activeWorkflowId);
      setRecords(prev => prev.map(r => r.id === activeWorkflowId ? { ...r, surveyAnswers: newAnswers } : r));
      const nextQueue = surveyQueue.slice(1);
      setSurveyQueue(nextQueue);
      if (nextQueue.length === 0) setActiveWorkflowId(null);
    } catch (err) {
      alert('问卷状态更新失败');
    }
  };

  // Fix: Completed the truncated ProgressSteps component and added logic to render rejection reasons.
  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍🦰' },
      { key: 'assistant', label: '财务助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏢' },
      { key: 'success', label: '报销成功', icon: '✅' }
    ];

    const currentIdx = steps.findIndex(s => s.key === status);
    const isRejected = status === 'rejected';

    return (
      <div className="py-4">
        <div className="flex justify-between items-start">
          {steps.map((step, idx) => {
            const isCompleted = !isRejected && idx <= currentIdx;
            const isCurrent = !isRejected && idx === currentIdx;
            return (
              <div key={step.key} className="flex flex-col items-center flex-1 relative">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm z-10 transition-colors ${
                  isCompleted ? 'bg-blue-500 text-white' : 'bg-gray-100 text-gray-400'
                } ${isCurrent ? 'ring-4 ring-blue-100' : ''}`}>
                  {isCompleted ? '✓' : step.icon}
                </div>
                <div className={`text-[10px] mt-1 text-center ${isCompleted ? 'text-blue-600 font-bold' : 'text-gray-400'}`}>
                  {step.label}
                </div>
                {idx < steps.length - 1 && (
                  <div className={`absolute left-1/2 top-4 w-full h-[2px] -z-0 ${
                    idx < currentIdx && !isRejected ? 'bg-blue-500' : 'bg-gray-100'
                  }`} />
                )}
              </div>
            );
          })}
        </div>
        {isRejected && (
          <div className="mt-4 p-3 bg-red-50 border border-red-100 rounded-xl text-red-600 text-[11px] leading-relaxed">
            <span className="font-bold">❌ 报销被驳回：</span>{reason || '请联系助管核实详情'}
          </div>
        )}
      </div>
    );
  };

  // Fix: Added the missing JSX return and default export for the App component.
  if (isLoginView) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <form onSubmit={handleLogin} className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-sm space-y-4">
          <div className="text-center mb-6">
            <h1 className="text-2xl font-bold">江南大学报销助手</h1>
            <p className="text-gray-400 text-sm mt-1">请填写你的基本信息以开始</p>
          </div>
          <input name="name" placeholder="真实姓名" className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" required />
          <input name="studentId" placeholder="学号/工号" className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" required />
          <input name="supervisor" placeholder="导师姓名" className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" />
          <input name="phone" placeholder="手机号" className="w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" />
          <button type="submit" className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 active:scale-95 transition-all">
            开启报销之旅
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <header className="bg-white border-b sticky top-0 z-40 px-4 h-16 flex items-center justify-between">
        <div className="font-bold text-lg text-gray-800">报销助手</div>
        <div className="flex gap-2">
          {user?.studentId === SUPER_ADMIN_ID && (
            <button 
              onClick={() => setIsAdminMode(!isAdminMode)}
              className={`text-xs px-3 py-1 rounded-full border transition-colors ${isAdminMode ? 'bg-indigo-600 text-white border-indigo-600' : 'text-indigo-600 border-indigo-200 bg-indigo-50'}`}
            >
              {isAdminMode ? '退出管理' : '管理员模式'}
            </button>
          )}
          <button onClick={handleShare} className="text-xs px-3 py-1 rounded-full border bg-gray-50 hover:bg-gray-100">{shareText}</button>
        </div>
      </header>

      <main className="max-w-xl mx-auto p-4 space-y-6">
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="bg-white border-2 border-dashed border-gray-300 rounded-3xl p-10 text-center hover:bg-gray-50 transition-colors cursor-pointer"
        >
          <div className="text-4xl mb-2">📄</div>
          <h2 className="font-bold text-gray-700">上传发票或拖拽至此</h2>
          <p className="text-xs text-gray-400 mt-1">支持图片/PDF，利用 Gemini 智能 OCR 提取</p>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            multiple 
            onChange={(e) => {
              const selected = Array.from(e.target.files || []);
              const newFiles = selected.map(f => ({
                id: Math.random().toString(36).substr(2, 9),
                file: f,
                previewUrl: URL.createObjectURL(f),
                status: 'pending' as const
              }));
              setFiles(prev => [...prev, ...newFiles]);
              newFiles.forEach(processFile);
            }} 
          />
        </div>

        {files.length > 0 && (
          <div className="space-y-3">
            {files.map(f => (
              <div key={f.id} className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-4">
                <div className="w-12 h-12 bg-gray-100 rounded-lg overflow-hidden flex-shrink-0">
                  <img src={f.previewUrl} className="w-full h-full object-cover" alt="invoice preview" />
                </div>
                <div className="flex-grow">
                  {f.status === 'processing' ? (
                    <div className="text-xs text-blue-500 animate-pulse font-medium">Gemini 正在提取数据...</div>
                  ) : f.status === 'completed' && f.extractedData ? (
                    <div className="flex justify-between items-center">
                      <div>
                        <div className="text-sm font-bold">¥{f.extractedData.amount}</div>
                        <div className="text-[10px] text-gray-400 truncate max-w-[120px]">{f.extractedData.sellerName}</div>
                      </div>
                      <button 
                        onClick={() => handleAddRecord(f.extractedData!, f.id, !!f.isBuyerValid, !!f.isDuplicate)}
                        className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-lg font-bold hover:bg-blue-700 transition-colors"
                      >
                        确认报销
                      </button>
                    </div>
                  ) : (
                    <div className="text-xs text-red-500">识别失败，请检查文件清晰度</div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        <div className="space-y-4">
          <h3 className="font-bold text-gray-400 text-sm px-1">最近报销记录</h3>
          {records.length === 0 ? (
            <div className="text-center py-20 text-gray-300 border-2 border-dashed border-gray-100 rounded-3xl">暂无记录</div>
          ) : records.map(record => (
            <div key={record.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 group transition-all hover:shadow-md">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <div className="text-2xl font-bold text-gray-800">¥{record.amount}</div>
                  <div className="text-[11px] text-gray-500 font-medium">{record.sellerName}</div>
                </div>
                <div className="text-right">
                  <div className={`text-[10px] font-bold px-3 py-1 rounded-full ${record.isPaid ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                    {record.isPaid ? '已打款' : '待打款'}
                  </div>
                  <div className="text-[10px] text-gray-300 mt-2">{new Date(record.timestamp).toLocaleDateString()}</div>
                </div>
              </div>

              <ProgressSteps status={record.status} reason={record.rejectionReason} />

              {isAdminMode && (
                <div className="mt-4 flex flex-wrap gap-2 pt-4 border-t border-gray-50">
                  <button onClick={() => adminUpdateStatus(record.id, 'han')} className="text-[10px] px-2 py-1 bg-gray-50 rounded text-gray-600 hover:bg-gray-100">发至韩老师</button>
                  <button onClick={() => adminUpdateStatus(record.id, 'assistant')} className="text-[10px] px-2 py-1 bg-gray-50 rounded text-gray-600 hover:bg-gray-100">发至助管</button>
                  <button onClick={() => adminUpdateStatus(record.id, 'office')} className="text-[10px] px-2 py-1 bg-gray-50 rounded text-gray-600 hover:bg-gray-100">发至财务</button>
                  <button onClick={() => adminUpdateStatus(record.id, 'success')} className="text-[10px] px-2 py-1 bg-green-500 text-white rounded font-bold">审核通过</button>
                  <button 
                    onClick={() => {
                      const reason = prompt("请输入驳回原因");
                      if (reason) adminUpdateStatus(record.id, 'rejected', reason);
                    }} 
                    className="text-[10px] px-2 py-1 bg-red-500 text-white rounded font-bold"
                  >
                    驳回
                  </button>
                </div>
              )}
            </div>
          ))}
        </div>
      </main>

      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white p-8 rounded-[40px] shadow-2xl w-full max-w-xs text-center">
            <div className="text-4xl mb-4">📝</div>
            <h3 className="text-xl font-bold mb-2">确认报销详情</h3>
            <p className="text-sm text-gray-400 mb-8 leading-relaxed">
              {surveyQueue[0] === 'double_signature' ? '此发票是否已经由两位负责老师签字确认？' : '是否已保存该笔交易的江苏银行打款截图？'}
            </p>
            <div className="flex gap-4">
              <button 
                onClick={() => handleSurveyAnswer(false)}
                className="flex-1 py-3 border border-gray-100 rounded-2xl font-bold text-gray-400 hover:bg-gray-50 transition-colors"
              >
                未完成
              </button>
              <button 
                onClick={() => handleSurveyAnswer(true)}
                className="flex-1 py-3 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-500/30 active:scale-95 transition-all"
              >
                已确认
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

