                    <div className="space-y-2">
                      <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden"><div className="h-full bg-blue-500 w-1/2 animate-[progress_1s_infinite_linear]"></div></div>
                      <p className="text-[10px] font-black text-blue-600">解析数据中...</p>
                    </div>
                  ) : f.status === 'completed' && f.extractedData ? (
                    <div className="flex justify-between items-center">
                      <div>
                        <div className="text-xl font-black text-slate-800">¥{f.extractedData.amount}</div>
                        <div className={`text-[10px] font-bold ${f.isBuyerValid ? 'text-green-500' : 'text-red-500'}`}>
                          {f.isBuyerValid ? '✅ 抬头匹配' : '⚠️ 抬头有误'}
                        </div>
                      </div>
                      <button 
                        onClick={() => handleAddRecord(f.extractedData!, f.id, !!f.isBuyerValid, !!f.isDuplicate)}
                        className="bg-blue-600 text-white px-5 py-2.5 rounded-2xl font-black text-xs shadow-lg shadow-blue-100"
                      >
                        下一步
                      </button>
                    </div>
                  ) : (
                    <p className="text-xs text-red-500 font-bold">哎呀，识别断网了，点我重试</p>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* 历史记录 */}
        <div className="space-y-4">
          <div className="flex justify-between items-center px-2">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">我的报销进度</h3>
            {isLoading && <span className="text-[10px] font-black text-blue-500 animate-pulse">同步云端中...</span>}
          </div>

          {records.length === 0 ? (
            <div className="py-20 text-center bg-slate-50/50 rounded-[2.5rem] border-2 border-dashed border-slate-100">
              <span className="text-4xl">🌤️</span>
              <p className="text-xs font-bold text-slate-300 mt-4">这里空空如也，快去上传发票吧</p>
            </div>
          ) : records.map(record => (
            <div key={record.id} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300">
              <div className="flex justify-between items-start mb-6">
                <div>
                  <div className="text-2xl font-black text-slate-800 tracking-tighter">¥{record.amount.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-slate-400 mt-1 uppercase truncate max-w-[150px]">{record.sellerName}</div>
                </div>
                <div className={`px-4 py-1.5 rounded-full text-[10px] font-black ${record.isPaid ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                  {record.isPaid ? '已打款' : '等待中'}
                </div>
              </div>

              <ProgressSteps status={record.status} reason={record.rejectionReason} />

              <div className="mt-4 pt-4 border-t border-slate-50 flex justify-between items-center">
                <span className="text-[10px] font-bold text-slate-300">{new Date(record.timestamp).toLocaleDateString()} 提交</span>
                <span className="text-[10px] font-black text-slate-800">#{record.invoiceNumber.slice(-6)}</span>
              </div>
            </div>
          ))}
        </div>
      </main>

      {/* 问卷交互 */}
      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl w-full max-w-sm animate-in slide-in-from-bottom duration-300">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-6 shadow-inner">📋</div>
            <h3 className="text-xl font-black text-center mb-2">最后一步确认</h3>
            <p className="text-sm text-slate-500 text-center mb-8 leading-relaxed font-medium">
              {surveyQueue[0] === 'double_signature' ? '这张发票背面有没有【2位老师】的签字？' : '你是不是已经准备好【支付流水/银行回执】了？'}
            </p>
            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => handleSurveyAnswer(false)}
                className="py-4 rounded-2xl font-black text-slate-400 bg-slate-50 hover:bg-slate-100"
              >
                还没好
              </button>
              <button 
                onClick={() => handleSurveyAnswer(true)}
                className="py-4 bg-blue-600 text-white rounded-2xl font-black shadow-xl shadow-blue-100 active:scale-95 transition-all"
              >
                准备好了
              </button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes progress { 0% { transform: translateX(-100%); } 100% { transform: translateX(200%); } }
        body { background-color: #FDFDFD; }
        ::-webkit-scrollbar { width: 0; }
      `}</style>
    </div>
  );
};

