import React, { useState, useEffect, useRef } from 'react';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

// ============================================================
// 🛠️ 配置区域：填入你的 Supabase 凭证
// ============================================================
const SUPABASE_URL = 'https://csvymqgaoabenakyzzsk.supabase.co'; 
const SUPABASE_ANON_KEY = 'YOUR_SUPABASE_ANON_KEY'; // 请在此处填入你的 Anon Key
// ============================================================

const getValidUrl = (url: string) => {
  if (!url || url.includes('YOUR_SUPABASE_PROJECT_URL')) return null;
  try {
    const parsed = new URL(url.trim());
    return (parsed.protocol === 'http:' || parsed.protocol === 'https:') ? parsed.toString() : null;
  } catch {
    return null;
  }
};

const validUrl = getValidUrl(SUPABASE_URL);
const isKeySet = SUPABASE_ANON_KEY && !SUPABASE_ANON_KEY.includes('YOUR_SUPABASE_ANON_KEY');
const supabase = validUrl && isKeySet ? createClient(validUrl, SUPABASE_ANON_KEY) : null;

const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";

type SurveyType = 'double_signature' | 'payment_record';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [shareText, setShareText] = useState('分享给同学');

  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isPaid, setIsPaid] = useState(false);

  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const hasSeenGuide = localStorage.getItem('has_seen_guide');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchCloudRecords(parsedUser.studentId);
      if (!hasSeenGuide) setShowGuide(true);
    } else {
      setIsLoginView(true);
    }
  }, []);

  const fetchCloudRecords = async (studentId: string) => {
    if (!supabase) return;
    setIsLoading(true);
    try {
      let query = supabase.from('reimbursements').select('*').order('timestamp', { ascending: false });
      if (!(isAdminMode && studentId === SUPER_ADMIN_ID)) {
        query = query.eq('studentId', studentId);
      }
      const { data, error } = await query;
      if (error) throw error;
      setRecords(data || []);
    } catch (err) {
      console.error('Fetch Error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("姓名和学号是必填的哦！");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
    setShowGuide(true);
    fetchCloudRecords(profile.studentId);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) || data.buyerTaxId.includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber === data.invoiceNumber);

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error' } : f));
    }
  };

  const handleAddRecord = async (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`⚠️ 抬头不对！购买方必须是“${SCHOOL_NAME}”，请联系卖家修改。`);
    if (isDuplicate) return alert("❌ 这张发票你已经提交过啦，别重复哦。");
    if (!supabase) return alert("数据库还没连上，请联系管理员。");

    setIsLoading(true);
    const newRecord = { ...extracted, ...user, isPaid, timestamp: Date.now(), paidEditCount: 0, status: 'box', surveyAnswers: {} };
    try {
      const { data, error } = await supabase.from('reimbursements').insert([newRecord]).select();
      if (error) throw error;
      setRecords(prev => [data[0], ...prev]);
      setFiles(prev => prev.filter(f => f.id !== fileId));
      setActiveWorkflowId(data[0].id);
      setSurveyQueue(isPaid ? ['double_signature', 'payment_record'] : ['double_signature']);
    } catch (err) {
      alert('上传失败，请检查网络');
    } finally {
      setIsLoading(false);
    }
  };

  // Fix: Added handleSurveyAnswer to manage the post-upload confirmation workflow.
  // It updates the record's survey answers and moves through the survey queue.
  const handleSurveyAnswer = async (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;

    const type = surveyQueue[0];
    const field = type === 'double_signature' ? 'hasDoubleSignature' : 'hasPaymentRecord';

    // Update state locally
    setRecords(prev => prev.map(r => 
      r.id === activeWorkflowId 
        ? { ...r, surveyAnswers: { ...r.surveyAnswers, [field]: answer } }
        : r
    ));

    // Update database
    if (supabase) {
      const record = records.find(r => r.id === activeWorkflowId);
      const newAnswers = { ...(record?.surveyAnswers || {}), [field]: answer };
      await supabase.from('reimbursements').update({
        surveyAnswers: newAnswers
      }).eq('id', activeWorkflowId);
    }

    // Move to next question or close modal
    const remaining = surveyQueue.slice(1);
    setSurveyQueue(remaining);
    if (remaining.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '韩老师', icon: '👩‍' },
      { key: 'assistant', label: '助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
      { key: 'success', label: '成功', icon: '✅' }
    ];
    const currentIdx = steps.findIndex(s => s.key === status);
    const isRejected = status === 'rejected';

    return (
      <div className="py-4">
        <div className="flex justify-between items-start relative">
          <div className="absolute top-4 left-0 w-full h-[2px] bg-gray-100 -z-0"></div>
          {steps.map((step, idx) => {
            const isDone = !isRejected && idx <= currentIdx;
            return (
              <div key={step.key} className="flex flex-col items-center flex-1 z-10">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm transition-all duration-500 ${
                  isDone ? 'bg-blue-600 text-white shadow-lg shadow-blue-200 scale-110' : 'bg-white border-2 border-gray-100 text-gray-300'
                }`}>
                  {isDone ? '✓' : step.icon}
                </div>
                <span className={`text-[10px] mt-2 font-bold ${isDone ? 'text-blue-600' : 'text-gray-300'}`}>{step.label}</span>
              </div>
            );
          })}
        </div>
        {isRejected && <div className="mt-4 p-3 bg-red-50 text-red-600 rounded-xl text-xs font-medium border border-red-100">❌ 被退回：{reason || '查看原因'}</div>}
      </div>
    );
  };

  if (isLoginView) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="bg-white p-8 rounded-[2rem] shadow-2xl w-full max-w-sm border border-slate-100">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl mx-auto flex items-center justify-center text-3xl shadow-xl shadow-blue-100 mb-4">🏫</div>
            <h1 className="text-2xl font-black text-slate-800">江南报销助手</h1>
            <p className="text-slate-400 text-sm mt-2">小白也能三秒上手的财务工具</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" placeholder="您的姓名" className="w-full px-4 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" required />
            <input name="studentId" placeholder="您的学号" className="w-full px-4 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" required />
            <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95">开始使用</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#FDFDFD] pb-24 text-slate-800">
      {/* 新手引导 */}
      {showGuide && (
        <div className="fixed inset-0 z-[100] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white p-8 rounded-[2.5rem] max-w-sm w-full shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black mb-6 text-center">🌟 欢迎，{user?.name}！</h3>
            <div className="space-y-6">
              <div className="flex gap-4">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black flex-shrink-0">1</div>
                <p className="text-sm font-medium text-slate-600">点击主页的“上传”，把发票照片丢进去。</p>
              </div>
              <div className="flex gap-4">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black flex-shrink-0">2</div>
                <p className="text-sm font-medium text-slate-600">AI 会帮你把金额、抬头全都填好，你核对一下。</p>
              </div>
              <div className="flex gap-4">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black flex-shrink-0">3</div>
                <p className="text-sm font-medium text-slate-600">点击“确认报销”，剩下的进度条会自动帮你追踪。</p>
              </div>
            </div>
            <button onClick={() => { setShowGuide(false); localStorage.setItem('has_seen_guide', 'true'); }} className="w-full mt-10 bg-slate-800 text-white py-4 rounded-2xl font-black shadow-lg">我学会了！</button>
          </div>
        </div>
      )}

      <header className="px-6 h-20 border-b flex items-center justify-between sticky top-0 bg-white/80 backdrop-blur-md z-40">
        <div className="flex items-center gap-2">
          <div className="text-2xl">🌱</div>
          <span className="font-black text-lg tracking-tight">江南报销助手</span>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowGuide(true)} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-xl border border-slate-100">❓</button>
          <button onClick={() => { localStorage.clear(); window.location.reload(); }} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-xl border border-slate-100">🚪</button>
        </div>
      </header>

      <main className="max-w-md mx-auto p-6 space-y-8">
        {/* 操作区 */}
        <div className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2.5rem] blur opacity-20 group-hover:opacity-40 transition duration-1000"></div>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="relative bg-white border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 text-center hover:border-blue-400 transition-all cursor-pointer overflow-hidden"
          >
            <div className="text-6xl mb-4 group-hover:scale-110 transition-transform">📸</div>
            <h2 className="text-xl font-black text-slate-800">上传发票</h2>
            <p className="text-xs text-slate-400 mt-2 font-medium">支持 PDF 或 直接拍照上传</p>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              multiple 
              onChange={(e) => {
                const selected = Array.from(e.target.files || []);
                const newFiles = selected.map(f => ({
                  id: Math.random().toString(36).substr(2, 9),
                  file: f, previewUrl: URL.createObjectURL(f), status: 'pending' as const
                }));
                setFiles(prev => [...prev, ...newFiles]);
                newFiles.forEach(processFile);
              }} 
            />
          </div>
        </div>

        {/* 正在处理的发票 */}
        {files.length > 0 && (
          <div className="space-y-4">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">AI 正在努力识别中...</h3>
            {files.map(f => (
              <div key={f.id} className="bg-white p-5 rounded-3xl shadow-xl border border-blue-50 flex items-center gap-5 animate-in slide-in-from-bottom duration-300">
                <div className="w-16 h-16 bg-slate-100 rounded-2xl overflow-hidden shadow-inner">
