                        </div>
                      </div>
                      <button 
                        onClick={() => handleAddRecord(f.extractedData!, f.id, !!f.isBuyerValid, !!f.isDuplicate)}
                        className="bg-blue-600 text-white px-5 py-2.5 rounded-2xl font-black text-xs shadow-lg shadow-blue-100"
                      >
                        下一步
                      </button>
                    </div>
                  ) : (
                    <p className="text-xs text-red-500 font-bold">哎呀，识别断网了，点我重试</p>
                  )}
                </div>
              </div>
            ))}
