                <div>
                  <div className="text-2xl font-black text-slate-800 tracking-tighter">¥{record.amount.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-slate-400 mt-1 uppercase truncate max-w-[150px]">{record.sellerName}</div>
                </div>
                <div className={`px-4 py-1.5 rounded-full text-[10px] font-black ${record.isPaid ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
