            <h3 className="text-xl font-black text-center mb-2">最后一步确认</h3>
            <p className="text-sm text-slate-500 text-center mb-8 leading-relaxed font-medium">
              {surveyQueue[0] === 'double_signature' ? '这张发票背面有没有【2位老师】的签字？' : '你是不是已经准备好【支付流水/银行回执】了？'}
            </p>
            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => handleSurveyAnswer(false)}
                className="py-4 rounded-2xl font-black text-slate-400 bg-slate-50 hover:bg-slate-100"
              >
                还没好
              </button>
              <button 
                onClick={() => handleSurveyAnswer(true)}
                className="py-4 bg-blue-600 text-white rounded-2xl font-black shadow-xl shadow-blue-100 active:scale-95 transition-all"
              >
                准备好了
              </button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes progress { 0% { transform: translateX(-100%); } 100% { transform: translateX(200%); } }
        body { background-color: #FDFDFD; }
        ::-webkit-scrollbar { width: 0; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import Hero from './components/Hero';
import BlueprintView from './components/BlueprintView';
import ChatPanel from './components/ChatPanel';
import { IdeaBlueprint } from './types';

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [blueprint, setBlueprint] = useState<IdeaBlueprint | null>(null);
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  const generateBlueprint = async (idea: string) => {
    setLoading(true);
    setBlueprint(null);
    setImageUrl(null);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      // 1. 生成商业蓝图 JSON
      const blueprintResponse = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `基于以下想法生成一份专业的商业蓝图。想法内容：${idea}。
        必须返回符合 Schema 的 JSON 格式，语言使用中文。`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              summary: { type: Type.STRING },
              targetAudience: { type: Type.STRING },
              uniqueValueProp: { type: Type.STRING },
              marketOpportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
              challenges: { type: Type.ARRAY, items: { type: Type.STRING } },
              roadmap: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["title", "summary", "targetAudience", "uniqueValueProp", "marketOpportunities", "challenges", "roadmap"]
          }
        }
      });

      const blueprintData = JSON.parse(blueprintResponse.text || '{}') as IdeaBlueprint;
      setBlueprint(blueprintData);
      setLoading(false);

      // 2. 异步生成概念视觉图
      setIsGeneratingImage(true);
      try {
        const imageResponse = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [{ text: `A professional, high-tech conceptual 3D render representing the startup idea: ${blueprintData.title}. Aesthetic: Sleek, modern, dark UI style, vibrant accent colors, 4k resolution.` }]
          },
          config: {
            imageConfig: { aspectRatio: "16:9" }
          }
        });

        for (const part of imageResponse.candidates[0].content.parts) {
          if (part.inlineData) {
            setImageUrl(`data:image/png;base64,${part.inlineData.data}`);
            break;
          }
        }
      } catch (err) {
        console.error("Image generation failed:", err);
      } finally {
        setIsGeneratingImage(false);
      }

    } catch (err) {
      console.error("Blueprint generation failed:", err);
      alert("锻造失败，请稍后再试。");
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#050508] text-white selection:bg-purple-500/30">
      {/* 背景装饰 */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-900/20 rounded-full blur-[120px]"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-900/20 rounded-full blur-[120px]"></div>
      </div>

      <nav className="relative z-10 px-6 py-6 border-b border-white/5 bg-black/20 backdrop-blur-md">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 group cursor-pointer" onClick={() => setBlueprint(null)}>
            <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-lg shadow-indigo-500/20">I</div>
            <span className="text-xl font-bold tracking-tighter">IdeaForge</span>
          </div>
          <div className="flex gap-6 text-sm font-medium text-gray-400">
            <button className="hover:text-white transition-colors">画廊</button>
            <button className="hover:text-white transition-colors">文档</button>
            <button className="bg-white/5 hover:bg-white/10 px-4 py-2 rounded-lg transition-colors border border-white/5 text-gray-200">我的创意</button>
          </div>
        </div>
      </nav>

      <main className="relative z-10">
        {!blueprint ? (
          <Hero onStart={generateBlueprint} loading={loading} />
        ) : (
          <>
            <BlueprintView 
              blueprint={blueprint} 
              imageUrl={imageUrl} 
              isGeneratingImage={isGeneratingImage} 
            />
            <ChatPanel ideaTitle={blueprint.title} />

            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 flex gap-4">
              <button 
                onClick={() => setBlueprint(null)}
                className="px-6 py-3 bg-white/5 hover:bg-white/10 backdrop-blur-md border border-white/10 rounded-2xl font-semibold transition-all"
              >
                ← 返回重新锻造
              </button>
              <button className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 shadow-xl shadow-indigo-500/20 rounded-2xl font-semibold transition-all">
                导出项目方案
              </button>
            </div>
          </>
        )}
      </main>

      <footer className="relative z-10 py-12 border-t border-white/5 text-center text-gray-600 text-sm">
        <p>&copy; 2025 IdeaForge AI. Built with Gemini 3.</p>
      </footer>

      <style>{`
        .gradient-text {
          background: linear-gradient(135deg, #818cf8 0%, #c084fc 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }
        .glass {
          background: rgba(255, 255, 255, 0.03);
          backdrop-filter: blur(12px);
          border: 1px solid rgba(255, 255, 255, 0.08);
        }
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-in {
          animation: fade-in 0.8s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

{
