}

import React, { useState, useEffect, useRef } from 'react';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus, SurveyType } from './types';

// ============================================================
// 🛠️ 配置区域
// ============================================================
const SUPABASE_URL = 'https://csvymqgaoabenakyzzsk.supabase.co'; 
const SUPABASE_ANON_KEY = 'YOUR_SUPABASE_ANON_KEY'; // 填入你的 Supabase Anon Key
const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
const SUPER_ADMIN_ID = "6240210040";
// ============================================================

const getValidUrl = (url: string) => {
  if (!url || url.includes('YOUR_SUPABASE_PROJECT_URL')) return null;
  try {
    const parsed = new URL(url.trim());
    return (parsed.protocol === 'http:' || parsed.protocol === 'https:') ? parsed.toString() : null;
  } catch {
    return null;
  }
};

const validUrl = getValidUrl(SUPABASE_URL);
const isKeySet = SUPABASE_ANON_KEY && !SUPABASE_ANON_KEY.includes('YOUR_SUPABASE_ANON_KEY');
const supabase = validUrl && isKeySet ? createClient(validUrl, SUPABASE_ANON_KEY) : null;

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [activeWorkflowId, setActiveWorkflowId] = useState<string | null>(null);
  const [surveyQueue, setSurveyQueue] = useState<SurveyType[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    const hasSeenGuide = localStorage.getItem('has_seen_guide');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchCloudRecords(parsedUser.studentId);
      if (!hasSeenGuide) setShowGuide(true);
    } else {
      setIsLoginView(true);
    }
  }, []);

  const fetchCloudRecords = async (studentId: string) => {
    if (!supabase) return;
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('reimbursements')
        .select('*')
        .eq('studentId', studentId)
        .order('timestamp', { ascending: false });
      if (error) throw error;
      setRecords(data || []);
    } catch (err) {
      console.error('Fetch Error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("姓名和学号是必填的哦！");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
    setShowGuide(true);
    fetchCloudRecords(profile.studentId);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) || data.buyerTaxId.includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber === data.invoiceNumber);

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error' } : f));
    }
  };

  const handleAddRecord = async (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`⚠️ 抬头不对！购买方必须是“${SCHOOL_NAME}”，请联系卖家修改。`);
    if (isDuplicate) return alert("❌ 这张发票你已经提交过啦，别重复哦。");

    setIsLoading(true);
    const newRecordId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = { 
      ...extracted, 
      ...user!, 
      isPaid: false, 
      id: newRecordId,
      timestamp: Date.now(), 
      paidEditCount: 0, 
      status: 'box', 
      surveyAnswers: {} 
    };

    try {
      if (supabase) {
        const { error } = await supabase.from('reimbursements').insert([newRecord]);
        if (error) throw error;
      }
      setRecords(prev => [newRecord, ...prev]);
      setFiles(prev => prev.filter(f => f.id !== fileId));
      setActiveWorkflowId(newRecordId);
      setSurveyQueue(['double_signature', 'payment_record']);
    } catch (err) {
      alert('提交失败，请重试');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSurveyAnswer = async (answer: boolean) => {
    if (!activeWorkflowId || surveyQueue.length === 0) return;
    const type = surveyQueue[0];
    const field = type === 'double_signature' ? 'hasDoubleSignature' : 'hasPaymentRecord';

    setRecords(prev => prev.map(r => 
      r.id === activeWorkflowId 
        ? { ...r, surveyAnswers: { ...r.surveyAnswers, [field]: answer } }
        : r
    ));

    const remaining = surveyQueue.slice(1);
    setSurveyQueue(remaining);
    if (remaining.length === 0) {
      setActiveWorkflowId(null);
    }
  };

  const ProgressSteps = ({ status, reason }: { status: ReimbursementStatus, reason?: string }) => {
    const steps: { key: ReimbursementStatus, label: string, icon: string }[] = [
      { key: 'box', label: '发票盒', icon: '📦' },
      { key: 'han', label: '审批中', icon: '👩‍' },
      { key: 'assistant', label: '助管', icon: '👧' },
      { key: 'office', label: '财务处', icon: '🏛️' },
      { key: 'success', label: '完成', icon: '✅' }
    ];
    const currentIdx = steps.findIndex(s => s.key === status);
    const isRejected = status === 'rejected';

    return (
      <div className="py-4">
        <div className="flex justify-between items-start relative">
          <div className="absolute top-4 left-0 w-full h-[1px] bg-slate-100 -z-0"></div>
          {steps.map((step, idx) => {
            const isDone = !isRejected && idx <= currentIdx;
            return (
              <div key={step.key} className="flex flex-col items-center flex-1 z-10">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs transition-all duration-300 ${
                  isDone ? 'bg-blue-600 text-white shadow-lg' : 'bg-white border border-slate-200 text-slate-300'
                }`}>
                  {isDone ? '✓' : step.icon}
                </div>
                <span className={`text-[10px] mt-2 font-bold ${isDone ? 'text-blue-600' : 'text-slate-400'}`}>{step.label}</span>
              </div>
            );
          })}
        </div>
        {isRejected && <div className="mt-4 p-3 bg-red-50 text-red-600 rounded-xl text-xs border border-red-100">❌ 被退回：{reason || '查看原因'}</div>}
      </div>
    );
  };

  if (isLoginView) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="bg-white p-8 rounded-[2rem] shadow-xl w-full max-w-sm border border-slate-100">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl mx-auto flex items-center justify-center text-3xl shadow-xl shadow-blue-100 mb-4">🏫</div>
            <h1 className="text-2xl font-black text-slate-800">江南报销助手</h1>
            <p className="text-slate-400 text-sm mt-2 font-medium">江大财务，一键即达</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input name="name" placeholder="您的姓名" className="w-full px-4 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" required />
            <input name="studentId" placeholder="您的学号" className="w-full px-4 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" required />
            <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95">开启极速报销</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#FDFDFD] pb-24 text-slate-800">
      {showGuide && (
        <div className="fixed inset-0 z-[100] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white p-8 rounded-[2.5rem] max-w-sm w-full shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black mb-6 text-center">🌟 欢迎，{user?.name}！</h3>
            <div className="space-y-6">
              <div className="flex gap-4">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black flex-shrink-0">1</div>
                <p className="text-sm font-medium text-slate-600">点击主页的“上传”，AI 会自动识别金额和抬头。</p>
              </div>
              <div className="flex gap-4">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black flex-shrink-0">2</div>
                <p className="text-sm font-medium text-slate-600">确认数据无误后点击提交，进入云端管理。</p>
              </div>
              <div className="flex gap-4">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black flex-shrink-0">3</div>
                <p className="text-sm font-medium text-slate-600">实时查看进度条，审批到哪一步一目了然。</p>
              </div>
            </div>
            <button onClick={() => { setShowGuide(false); localStorage.setItem('has_seen_guide', 'true'); }} className="w-full mt-10 bg-slate-800 text-white py-4 rounded-2xl font-black shadow-lg">开启使用</button>
          </div>
        </div>
      )}

      <header className="px-6 h-20 border-b flex items-center justify-between sticky top-0 bg-white/80 backdrop-blur-md z-40">
        <div className="flex items-center gap-2">
          <div className="text-2xl">🌱</div>
          <span className="font-black text-lg tracking-tight">江南报销助手</span>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowGuide(true)} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-xl border border-slate-100">❓</button>
          <button onClick={() => { localStorage.clear(); window.location.reload(); }} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-xl border border-slate-100">🚪</button>
        </div>
      </header>

      <main className="max-w-md mx-auto p-6 space-y-8">
        <div className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2.5rem] blur opacity-10"></div>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="relative bg-white border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 text-center hover:border-blue-400 transition-all cursor-pointer"
          >
            <div className="text-6xl mb-4">📸</div>
            <h2 className="text-xl font-black text-slate-800">上传发票</h2>
            <p className="text-xs text-slate-400 mt-2 font-medium">支持 PDF 或 图片，AI 自动填写</p>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              multiple 
              onChange={(e) => {
                const selected = Array.from(e.target.files || []);
                const newFiles = selected.map(f => ({
                  id: Math.random().toString(36).substr(2, 9),
                  file: f, previewUrl: URL.createObjectURL(f), status: 'pending' as const
                }));
                setFiles(prev => [...prev, ...newFiles]);
                newFiles.forEach(processFile);
              }} 
            />
          </div>
        </div>

        {files.length > 0 && (
          <div className="space-y-4">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">处理中...</h3>
            {files.map(f => (
              <div key={f.id} className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-5">
                <div className="w-16 h-16 bg-slate-50 rounded-2xl overflow-hidden">
                  <img src={f.previewUrl} className="w-full h-full object-cover" alt="preview" />
                </div>
                <div className="flex-grow">
                  {f.status === 'processing' ? (
                    <div className="space-y-2">
                      <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden"><div className="h-full bg-blue-500 w-1/2 animate-[progress_1.5s_infinite]"></div></div>
                      <p className="text-[10px] font-bold text-blue-600">正在提取金额与抬头</p>
                    </div>
                  ) : f.status === 'completed' && f.extractedData ? (
                    <div className="flex justify-between items-center">
                      <div>
                        <div className="text-xl font-black text-slate-800">¥{f.extractedData.amount}</div>
                        <div className={`text-[10px] font-bold ${f.isBuyerValid ? 'text-green-500' : 'text-red-500'}`}>
                          {f.isBuyerValid ? '✅ 抬头匹配' : '⚠️ 抬头有误'}
                        </div>
                      </div>
                      <button 
                        onClick={() => handleAddRecord(f.extractedData!, f.id, !!f.isBuyerValid, !!f.isDuplicate)}
                        className="bg-blue-600 text-white px-5 py-2.5 rounded-2xl font-black text-xs shadow-lg shadow-blue-100"
                      >
                        确认提交
                      </button>
                    </div>
                  ) : (
                    <p className="text-xs text-red-500 font-bold">识别失败，点击重试</p>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        <div className="space-y-4">
          <div className="flex justify-between items-center px-2">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">历史报销</h3>
            {isLoading && <span className="text-[10px] font-bold text-blue-500 animate-pulse">更新中</span>}
          </div>

          {records.length === 0 ? (
            <div className="py-20 text-center bg-slate-50/50 rounded-[2.5rem] border border-dashed border-slate-100">
              <span className="text-4xl opacity-50">🌤️</span>
              <p className="text-xs font-bold text-slate-300 mt-4">没有任何记录</p>
            </div>
          ) : records.map(record => (
            <div key={record.id} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100">
              <div className="flex justify-between items-start mb-6">
                <div>
                  <div className="text-2xl font-black text-slate-800 tracking-tighter">¥{record.amount.toFixed(2)}</div>
                  <div className="text-[10px] font-bold text-slate-400 mt-1 uppercase truncate max-w-[150px]">{record.sellerName}</div>
                </div>
                <div className={`px-4 py-1.5 rounded-full text-[10px] font-black ${record.isPaid ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                  {record.isPaid ? '已打款' : '待处理'}
                </div>
              </div>
              <ProgressSteps status={record.status} reason={record.rejectionReason} />
            </div>
          ))}
        </div>
      </main>

      {activeWorkflowId && surveyQueue.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[100] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl w-full max-w-sm">
            <h3 className="text-xl font-black text-center mb-2">最后确认</h3>
            <p className="text-sm text-slate-500 text-center mb-8 font-medium">
              {surveyQueue[0] === 'double_signature' ? '发票背面是否有【两位老师】签字？' : '是否已保存该交易的【支付流水】回执？'}
            </p>
            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => handleSurveyAnswer(false)} className="py-4 rounded-2xl font-black text-slate-400 bg-slate-50">还没</button>
              <button onClick={() => handleSurveyAnswer(true)} className="py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg">确认好了</button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes progress { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
      `}</style>
    </div>
  );
};

