import React, { useState, useEffect, useRef } from 'react';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';
import { extractInvoiceData } from './services/geminiService';
import { SubmissionRecord, ProcessingFile, InvoiceData, UserProfile, ReimbursementStatus } from './types';

// ============================================================
// 🛠️ 配置区域
// ============================================================
const SUPABASE_URL = 'https://csvymqgaoabenakyzzsk.supabase.co'; 
const SUPABASE_ANON_KEY = 'YOUR_SUPABASE_ANON_KEY'; // 填入你的 Supabase Anon Key
const SCHOOL_NAME = "江南大学";
const SCHOOL_TAX_ID = "1210000071780177X1";
// ============================================================

const getValidUrl = (url: string) => {
  if (!url || url.includes('YOUR_SUPABASE_PROJECT_URL')) return null;
  try {
    const parsed = new URL(url.trim());
    return (parsed.protocol === 'http:' || parsed.protocol === 'https:') ? parsed.toString() : null;
  } catch {
    return null;
  }
};

const validUrl = getValidUrl(SUPABASE_URL);
const isKeySet = SUPABASE_ANON_KEY && !SUPABASE_ANON_KEY.includes('YOUR_SUPABASE_ANON_KEY');
const supabase = validUrl && isKeySet ? createClient(validUrl, SUPABASE_ANON_KEY) : null;

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [isLoginView, setIsLoginView] = useState(false);
  const [files, setFiles] = useState<ProcessingFile[]>([]);
  const [records, setRecords] = useState<SubmissionRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('invoice_user_profile');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      fetchCloudRecords(parsedUser.studentId);
    } else {
      setIsLoginView(true);
    }
  }, []);

  const fetchCloudRecords = async (studentId: string) => {
    if (!supabase) return;
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('reimbursements')
        .select('*')
        .eq('studentId', studentId)
        .order('timestamp', { ascending: false });
      if (error) throw error;
      setRecords(data || []);
    } catch (err) {
      console.error('Fetch Error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      studentId: formData.get('studentId') as string,
      supervisor: formData.get('supervisor') as string,
      phone: formData.get('phone') as string,
    };
    if (!profile.name || !profile.studentId) return alert("姓名和学号不能为空");
    localStorage.setItem('invoice_user_profile', JSON.stringify(profile));
    setUser(profile);
    setIsLoginView(false);
    fetchCloudRecords(profile.studentId);
  };

  const processFile = async (item: ProcessingFile) => {
    setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing' } : f));
    try {
      const data = await extractInvoiceData(item.file);
      const isBuyerValid = data.buyerName.includes(SCHOOL_NAME) || data.buyerTaxId.includes(SCHOOL_TAX_ID);
      const isDuplicate = records.some(r => r.invoiceNumber === data.invoiceNumber);

      setFiles(prev => prev.map(f => f.id === item.id ? { 
        ...f, status: 'completed', extractedData: data, isBuyerValid, isDuplicate 
      } : f));
    } catch (err) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'error' } : f));
    }
  };

  const handleAddRecord = async (extracted: InvoiceData, fileId: string, isValid: boolean, isDuplicate: boolean) => {
    if (!isValid) return alert(`购买方必须是“${SCHOOL_NAME}”`);
    if (isDuplicate) return alert("该发票已存在");

    setIsLoading(true);
    const newRecordId = Math.random().toString(36).substr(2, 9);
    const newRecord: SubmissionRecord = { 
      ...extracted, 
      ...user!, 
      isPaid: false, 
      id: newRecordId,
      timestamp: Date.now(), 
      paidEditCount: 0, 
      status: 'box'
    };

    try {
      if (supabase) {
        const { error } = await supabase.from('reimbursements').insert([newRecord]);
        if (error) throw error;
      }
      setRecords(prev => [newRecord, ...prev]);
      setFiles(prev => prev.filter(f => f.id !== fileId));
    } catch (err) {
      alert('保存失败');
    } finally {
      setIsLoading(false);
    }
  };

  const ProgressIndicator = ({ status }: { status: ReimbursementStatus }) => {
    const states: ReimbursementStatus[] = ['box', 'han', 'assistant', 'office', 'success'];
    const currentIdx = states.indexOf(status);

    return (
      <div className="flex gap-1.5 mt-2">
        {states.map((s, idx) => (
          <div 
            key={s} 
            className={`h-1.5 flex-1 rounded-full transition-colors duration-500 ${
              idx <= currentIdx ? 'bg-blue-600' : 'bg-slate-100'
            }`}
          />
        ))}
      </div>
    );
  };

  if (isLoginView) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-sm">
          <h1 className="text-2xl font-bold text-slate-900 mb-6">身份验证</h1>
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-400 ml-1">姓名</label>
              <input name="name" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" required />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-400 ml-1">学号</label>
              <input name="studentId" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" required />
            </div>
            <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold mt-4">登录系统</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-12">
      <header className="bg-white px-6 py-4 border-b sticky top-0 z-30 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">J</div>
          <span className="font-bold text-slate-800">发票报销系统</span>
        </div>
        <button 
          onClick={() => { localStorage.clear(); window.location.reload(); }}
          className="text-xs font-bold text-slate-400 hover:text-red-500"
        >
          退出
        </button>
      </header>

      <main className="max-w-xl mx-auto p-4 space-y-6">
        {/* 上传区 */}
        <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-slate-100 rounded-2xl py-10 text-center cursor-pointer hover:bg-slate-50 transition-colors"
          >
            <span className="text-4xl mb-2 block">📄</span>
            <p className="font-bold text-slate-800">上传新发票</p>
            <p className="text-xs text-slate-400 mt-1">支持图片或 PDF 文件</p>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              multiple 
              onChange={(e) => {
                const selected = Array.from(e.target.files || []);
                const newFiles = selected.map(f => ({
                  id: Math.random().toString(36).substr(2, 9),
                  file: f, previewUrl: URL.createObjectURL(f), status: 'pending' as const
                }));
                setFiles(prev => [...prev, ...newFiles]);
                newFiles.forEach(processFile);
              }} 
            />
          </div>
        </section>

        {/* 正在处理 */}
        {files.length > 0 && (
          <section className="space-y-3">
            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-2">正在处理 ({files.length})</h3>
            {files.map(f => (
              <div key={f.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center gap-4 animate-pulse">
                <div className="w-12 h-12 bg-slate-50 rounded-xl overflow-hidden flex-shrink-0">
                  <img src={f.previewUrl} className="w-full h-full object-cover" />
                </div>
                <div className="flex-grow">
                  {f.status === 'processing' ? (
                    <div className="h-2 w-24 bg-slate-100 rounded-full" />
                  ) : f.status === 'completed' && f.extractedData ? (
                    <div className="flex justify-between items-center animate-none">
                      <div>
                        <p className="text-sm font-bold text-slate-800">¥{f.extractedData.amount}</p>
                        <p className={`text-[10px] font-bold ${f.isBuyerValid ? 'text-green-500' : 'text-red-500'}`}>
                          {f.isBuyerValid ? '抬头匹配' : '抬头不符'}
                        </p>
                      </div>
                      <button 
                        onClick={() => handleAddRecord(f.extractedData!, f.id, !!f.isBuyerValid, !!f.isDuplicate)}
                        className="bg-blue-600 text-white text-[10px] px-4 py-2 rounded-lg font-bold"
                      >
                        确认提交
                      </button>
                    </div>
                  ) : (
                    <p className="text-[10px] text-red-400 font-bold">处理出错</p>
                  )}
                </div>
              </div>
            ))}
          </section>
        )}

        {/* 报销列表 */}
        <section className="space-y-4">
          <div className="flex justify-between items-center px-2">
            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">报销记录</h3>
            {isLoading && <span className="text-[10px] text-blue-600 font-bold">刷新中...</span>}
          </div>

          {records.length === 0 ? (
            <div className="bg-white p-12 rounded-3xl border border-dashed border-slate-200 text-center">
              <p className="text-sm font-medium text-slate-300">暂无报销记录</p>
            </div>
          ) : records.map(record => (
            <div key={record.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm transition-transform active:scale-[0.98]">
              <div className="flex justify-between items-start mb-1">
                <h4 className="text-lg font-black text-slate-900">¥{record.amount.toFixed(2)}</h4>
                <span className={`text-[10px] px-2 py-0.5 rounded-md font-bold ${
                  record.isPaid ? 'bg-green-50 text-green-600' : 'bg-slate-50 text-slate-500'
                }`}>
                  {record.isPaid ? '已结算' : '待处理'}
                </span>
              </div>
              <p className="text-[10px] font-bold text-slate-400 truncate uppercase mb-4">{record.sellerName}</p>

              <ProgressIndicator status={record.status} />

              <div className="mt-4 flex justify-between items-center border-t border-slate-50 pt-3">
                <span className="text-[10px] text-slate-300 font-medium">
                  {new Date(record.timestamp).toLocaleDateString()}
                </span>
                <span className="text-[10px] text-slate-800 font-bold">#{record.invoiceNumber.slice(-8)}</span>
              </div>
            </div>
          ))}
        </section>
      </main>
    </div>
  );
};

